-- Poems batch 242
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('0e691b77-24a8-4a0b-b371-fd1a58d78954','自餘吟','邵雍','宋','宋诗','song-poetry','','[]','身生天地後，心在天地前。',24,'全唐诗/poet.song.22000.json','["身生天地後，心在天地前。", "天地自我出，自餘何足言。"]'),
('2058318a-cb48-4498-824c-8885c18e38bd','四可吟','邵雍','宋','宋诗','song-poetry','','[]','可勉者行，可信者言。',20,'全唐诗/poet.song.22000.json','["可勉者行，可信者言。", "可委者命，可託者天。"]'),
('c0488a53-a501-451f-9621-d9f70bd00d58','四不可吟','邵雍','宋','宋诗','song-poetry','','[]','言不可妄，行不可隳。',20,'全唐诗/poet.song.22000.json','["言不可妄，行不可隳。", "命不可忽，天不可違。"]'),
('6f07906d-b73b-47ca-a2b1-95aaa75e2501','賃屋吟','邵雍','宋','宋诗','song-poetry','','[]','屋新人喜居，屋弊人思去。',24,'全唐诗/poet.song.22000.json','["屋新人喜居，屋弊人思去。", "主若善修完，何時不能住。"]'),
('7034b1d7-06c6-440b-b08f-07381e9916dc','小人吟','邵雍','宋','宋诗','song-poetry','','[]','小人無恥，重利輕死。',20,'全唐诗/poet.song.22000.json','["小人無恥，重利輕死。", "不畏人誅，豈顧物議。"]'),
('96d25087-65e9-4cbc-90bd-bd30d662371b','覽照吟','邵雍','宋','宋诗','song-poetry','','[]','其骨爽，其神清。',16,'全唐诗/poet.song.22000.json','["其骨爽，其神清。", "其祿薄，其福輕。"]'),
('647b6617-a0dc-4eb6-8150-4bbe375b92c9','有病吟','邵雍','宋','宋诗','song-poetry','','[]','一身如一國，有病當求醫。',24,'全唐诗/poet.song.22000.json','["一身如一國，有病當求醫。", "病愈藥便止，節宣良得宜。"]'),
('c40a9cd3-bc85-4b0e-a3d7-c0e1335cbb65','二月吟','邵雍','宋','宋诗','song-poetry','','[]','林下故無知，唯知二月期。',48,'全唐诗/poet.song.22000.json','["林下故無知，唯知二月期。", "酒嘗新熟後，花賞半開時。", "只有醺酣趣，殊無爛熳悲。", "誰能將此景，長貯在心脾。"]'),
('04c4d218-29c7-41dc-aeb0-b7b005f2d642','三月吟','邵雍','宋','宋诗','song-poetry','','[]','滿城盡日行春去，言會行春還有數。',63,'全唐诗/poet.song.22000.json','["滿城盡日行春去，言會行春還有數。", "真宰何嘗不發生，遊人其那無憑據。", "梨花著雨漫成啼，柳絮因風肯住。", "一片清明好意多，柰何意好難分付。"]'),
('15bf85b5-5e13-4438-abdd-56f28105de8d','一等吟','邵雍','宋','宋诗','song-poetry','','[]','欲出第一等言，須有第一等意。',28,'全唐诗/poet.song.22000.json','["欲出第一等言，須有第一等意。", "欲爲第一等人，須作等一等事。"]'),
('34197266-7c8d-48d7-9218-6e1f8a13cb29','萬物吟','邵雍','宋','宋诗','song-poetry','','[]','成敗須歸命，興衰各有時。',48,'全唐诗/poet.song.22000.json','["成敗須歸命，興衰各有時。", "小人縱多欲，真宰豈容私。", "只此浪喜歡，便成空慘悽。", "請觀春去後，遊者更爲誰。"]'),
('a28f5fb3-1323-4b71-a3fa-a42fb6e23228','洛陽春吟  其一','邵雍','宋','宋诗','song-poetry','','[]','四方景好無如洛，一歲花奇莫若春。',32,'全唐诗/poet.song.22000.json','["四方景好無如洛，一歲花奇莫若春。", "景好花奇精妙處，又能分付與閑人。"]'),
('a4e2935f-759f-41b4-bf8c-98f58c9a562d','洛陽春吟  其二','邵雍','宋','宋诗','song-poetry','','[]','洛陽人慣見奇葩，桃李花開未當花。',32,'全唐诗/poet.song.22000.json','["洛陽人慣見奇葩，桃李花開未當花。", "須是牡丹花盛發，滿城方始樂無涯。"]'),
('090b9112-4fb6-45af-8254-e5b48dde7ad0','洛陽春吟  其三','邵雍','宋','宋诗','song-poetry','','[]','桃李花開人不窺，花時須是牡丹時。',32,'全唐诗/poet.song.22000.json','["桃李花開人不窺，花時須是牡丹時。", "牡丹花發酒增價，夜半遊人猶未歸。"]'),
('490e9788-d51e-413f-9986-be3d7e18e636','洛陽春吟  其四','邵雍','宋','宋诗','song-poetry','','[]','光陰不肯略從容，九十日春還又空。',32,'全唐诗/poet.song.22000.json','["光陰不肯略從容，九十日春還又空。", "多少落花無著莫，半隨流水半隨風。"]'),
('d92d6bc5-8ec0-44df-809e-0024443e438e','洛陽春吟  其五','邵雍','宋','宋诗','song-poetry','','[]','春歸花謝日初長，燕語鶑啼各自忙。',32,'全唐诗/poet.song.22000.json','["春歸花謝日初長，燕語鶑啼各自忙。", "何故遊人斷來往，綠陰殊不減紅芳。"]'),
('5bac25e6-a02e-4b1a-b6ff-1af5c2e07c9f','洛陽春吟  其六','邵雍','宋','宋诗','song-poetry','','[]','十日好花都去盡，可憐青帝用功深。',32,'全唐诗/poet.song.22000.json','["十日好花都去盡，可憐青帝用功深。", "遊人莫便無憑據，未必紅芳勝綠陰。"]'),
('d0dfa4b1-fad5-4a01-94b7-4db6d2cd7511','洛陽春吟  其七','邵雍','宋','宋诗','song-poetry','','[]','春歸必竟歸何處，無限春寃都未訴。',32,'全唐诗/poet.song.22000.json','["春歸必竟歸何處，無限春寃都未訴。", "欲託流鶑問所因，子規又叫不如去。"]'),
('0713b59f-83cf-47a4-bcb3-0c8224477264','洛陽春吟  其八','邵雍','宋','宋诗','song-poetry','','[]','用盡四時周一歲，唯春能見好花開。',32,'全唐诗/poet.song.22000.json','["用盡四時周一歲，唯春能見好花開。", "十千買酒未爲貴，既去紅芳豈再來。"]'),
('a9044341-f466-451d-b4bc-7f78bbe4791d','自貽吟','邵雍','宋','宋诗','song-poetry','','[]','六十有七歲，生爲世上人。',36,'全唐诗/poet.song.22000.json','["六十有七歲，生爲世上人。", "四方中正地，萬物備全身。", "天外更無樂，胸中別有春。"]'),
('47b1745d-07cb-48c7-a6d2-23930c63fe77','落花吟','邵雍','宋','宋诗','song-poetry','','[]','萬紫千紅處處飛，滿川桃李漫成蹊。',64,'全唐诗/poet.song.22000.json','["萬紫千紅處處飛，滿川桃李漫成蹊。", "狂風猛雨日將暮，舞榭歌臺人乍稀。", "水上漂浮安有定，徑邊狼籍更無依。", "流鶑不用多言語，到了一番春已歸。"]'),
('c2fd02bd-e633-419f-aa0d-abce07e8ca07','春暮吟  其一','邵雍','宋','宋诗','song-poetry','','[]','花開春正好，花謝春還暮。',24,'全唐诗/poet.song.22000.json','["花開春正好，花謝春還暮。", "不意子規禽，猶能道歸去。"]'),
('44e23d8e-d109-4091-b9be-0dfc8e08daf2','春暮吟  其二','邵雍','宋','宋诗','song-poetry','','[]','春來蝴蝶亂，春去子規啼。',24,'全唐诗/poet.song.22000.json','["春來蝴蝶亂，春去子規啼。", "安得如前日，和風初扇時。"]'),
('62389993-55b4-40f3-aeed-bd8ad7f5ddca','春暮吟  其三','邵雍','宋','宋诗','song-poetry','','[]','禽不通人情，唯知春已暮。',24,'全唐诗/poet.song.22000.json','["禽不通人情，唯知春已暮。", "亦或叫提壺，亦或叫歸去。"]'),
('5f76d2a4-5975-4f67-9883-70cae498e52a','泉布吟','邵雍','宋','宋诗','song-poetry','','[]','名爲泉布者，無足走人間。',48,'全唐诗/poet.song.22000.json','["名爲泉布者，無足走人間。", "善發難言口，能開不笑顔。", "償逋小續命，賙急大還丹。", "唯有商山老，非干買得閑。"]'),
('aaf56151-8c91-4054-ac58-51c49a224164','牡丹吟','邵雍','宋','宋诗','song-poetry','','[]','一盤顔色一般香，香是天香色異常。',32,'全唐诗/poet.song.22000.json','["一盤顔色一般香，香是天香色異常。", "真宰功夫精妙處，非容人意可思量。"]'),
('a81fd02b-0dbf-4e75-81d8-33a4879fd55b','和鳳翔橫渠張子厚學士','邵雍','宋','宋诗','song-poetry','','[]','秦甸山河半域中，精英孕育古今同。',32,'全唐诗/poet.song.22000.json','["秦甸山河半域中，精英孕育古今同。", "古來賢傑知多少，何代無人振素風。"]'),
('38e256ee-32d3-4618-a698-0081bd14e78b','自處吟','邵雍','宋','宋诗','song-poetry','','[]','堯夫自處道如何，滿洛陽城都似家。',64,'全唐诗/poet.song.22000.json','["堯夫自處道如何，滿洛陽城都似家。", "不德於人焉敢異，至誠從物更無他。", "眼前只見羅天爵，頭上誰知換歲華。", "何止春歸與春在，胸中長有四時花。"]'),
('3f9ead8b-43cb-43f5-b922-d2beb44a37c5','爲人吟','邵雍','宋','宋诗','song-poetry','','[]','爲人須是與人羣，不與人羣不盡人。',64,'全唐诗/poet.song.22000.json','["爲人須是與人羣，不與人羣不盡人。", "大舜與人焉有異，帝堯親族亦推倫。", "人心齟齬一身病，事體和諧四海春。", "心在四支心是主，四支又復遠于身。"]'),
('51c89bda-3940-42f0-b928-4f6337955df0','先天吟','邵雍','宋','宋诗','song-poetry','','[]','先天事業有誰爲，爲者如何告者誰。',64,'全唐诗/poet.song.22000.json','["先天事業有誰爲，爲者如何告者誰。", "若謂先天言可告，君臣父子外何歸。", "眼前伎倆人皆曉，心上功夫世莫知。", "天地與身皆易地，己身殊不異庖犧。"]'),
('1ed7898a-6b6b-41d3-a9f5-ef1b0821ecf8','中和吟','邵雍','宋','宋诗','song-poetry','','[]','性亦故無他，須是識中和。',48,'全唐诗/poet.song.22000.json','["性亦故無他，須是識中和。", "心上語言少，人間事體多。", "如霖迴久旱，似藥起沉痾。", "一物尚不了，其如萬物何。"]'),
('640876af-8beb-46d3-afd9-689ec5481efa','四賢吟','邵雍','宋','宋诗','song-poetry','','[]','彥國之言鋪陳，晦叔之言簡當。',57,'全唐诗/poet.song.22000.json','["彥國之言鋪陳，晦叔之言簡當。", "君實之言優游，伯淳之言調暢。", "四賢洛陽之名望，是以在人之上。", "有宋熙寧之間，大爲一時之壯。"]'),
('bb605b4d-fc9c-4907-812a-618a5c5f7cae','年老吟','邵雍','宋','宋诗','song-poetry','','[]','歲華頭上不能驚，唯有交親眼更明。',64,'全唐诗/poet.song.22000.json','["歲華頭上不能驚，唯有交親眼更明。", "皓皓月常因坐看，深深酒不爲愁傾。", "苟於心上無先覺，却似人間小後生。", "欲約何人爲伴侶，江湖泛去一舟輕。"]'),
('ef00c936-ce3c-4806-a24b-f0524d8c3132','天地吟','邵雍','宋','宋诗','song-poetry','','[]','天人之際豈容鍼，至理何煩遠去尋。',64,'全唐诗/poet.song.22000.json','["天人之際豈容鍼，至理何煩遠去尋。", "凶焰熾時焚更烈，恩波流處浸還深。", "長征戍卒思歸意，久旱蒼生望雨心。", "禍福轉來如反掌，可能中夜不沉吟。"]'),
('f03097f4-be15-4c73-9eda-a04079766c44','至論吟','邵雍','宋','宋诗','song-poetry','','[]','民于萬物已稱珍，聖向民中更出羣。',64,'全唐诗/poet.song.22000.json','["民于萬物已稱珍，聖向民中更出羣。", "介石不疑何盡日，知幾何患未如神。", "若無剛果難成善，既有精明又貴純。", "禍福兆時皆有漸，不由天地只由人。"]'),
('1bde0bc3-0b30-440f-ab06-094925b0a6e6','人玉吟','邵雍','宋','宋诗','song-poetry','','[]','玉不自珍人與珍，人珍何謝玉之純。',64,'全唐诗/poet.song.22000.json','["玉不自珍人與珍，人珍何謝玉之純。", "然知粹美如終一，更看清光表裏真。", "韜韞有名初在石，琢磨成器却須人。", "古人已死不復見，被褐之言不謬云。"]'),
('4179a9bb-4c33-4d6a-a840-bd135569bee2','詐者吟','邵雍','宋','宋诗','song-poetry','','[]','詐者固疑人，天下盡行詐。',24,'全唐诗/poet.song.22000.json','["詐者固疑人，天下盡行詐。", "不信天下人，其間無真話。"]'),
('5a97483f-1b3a-422a-b3a2-56d705b7778d','飲酒吟','邵雍','宋','宋诗','song-poetry','','[]','時時醇酒飲些些，頤養天和以代茶。',64,'全唐诗/poet.song.22000.json','["時時醇酒飲些些，頤養天和以代茶。", "無雨將成大凶歲，負城非有好生涯。", "身居畎畝須憂國，事委男兒尚恤家。", "人問老來何長進，鑑中添得鬢邊華。"]'),
('325c0b42-b671-4831-ac7d-b4bb634936a7','樂物吟','邵雍','宋','宋诗','song-poetry','','[]','物有聲色氣味，人有耳目口鼻。',28,'全唐诗/poet.song.22000.json','["物有聲色氣味，人有耳目口鼻。", "萬物于人一身，反觀莫不全備。"]'),
('da5b44ae-faae-41bc-a205-60820b4182a8','和王安之小園五題','邵雍','宋','宋诗','song-poetry','','[]','小園新葺不離家，高就崗頭低就窳。',64,'全唐诗/poet.song.22000.json','["小園新葺不離家，高就崗頭低就窳。", "洛邑地疑偏得勝，天津人至又非賒。", "宜將閬苑同時語，莫共桃源一道誇。", "聞說一軒多種藥，只應猶欠紫河車。"]'),
('0c329cf4-bc15-4898-90e7-69c8719ce55f','野軒','邵雍','宋','宋诗','song-poetry','','[]','一軒名野非塵境，嵩少煙岑送好風。',32,'全唐诗/poet.song.22000.json','["一軒名野非塵境，嵩少煙岑送好風。", "日月歲時都屬己，更於何處覓壺中。"]'),
('a197a51c-9136-4567-8b44-e9c2e8b992f9','污亭','邵雍','宋','宋诗','song-poetry','','[]','許由爲計未爲深，洗耳如何不動心。',32,'全唐诗/poet.song.22000.json','["許由爲計未爲深，洗耳如何不動心。", "到此灑然如世外，何嘗更有事來侵。"]'),
('04c8215b-85c4-4b24-8929-2776642afba8','藥軒','邵雍','宋','宋诗','song-poetry','','[]','山裏藥多人不識，夫君移植更標名。',32,'全唐诗/poet.song.22000.json','["山裏藥多人不識，夫君移植更標名。", "果能醫得人間病，紅紫何妨好近楹。"]'),
('25939aaf-8fdf-47de-a4a8-1ff591a99dc9','晚暉亭','邵雍','宋','宋诗','song-poetry','','[]','高亭新建礙煙霞，暮景能留是可嘉。',32,'全唐诗/poet.song.22000.json','["高亭新建礙煙霞，暮景能留是可嘉。", "最近賞春來往路，遊人應問是誰家。"]'),
('ea353238-5aa6-4dc1-a4b6-3efdb10a3fcf','歡物吟  其一','邵雍','宋','宋诗','song-poetry','','[]','水雨霖，火雨露。',16,'全唐诗/poet.song.22000.json','["水雨霖，火雨露。", "土雨濛，石雨雹。"]'),
('27f90b88-e2f2-4974-80a3-1c0a52452fc7','歡物吟  其二','邵雍','宋','宋诗','song-poetry','','[]','水風涼，火風熱。',16,'全唐诗/poet.song.22000.json','["水風涼，火風熱。", "土風和，石風冽。"]'),
('5514863a-e0c9-40c5-8c39-8a1dba132a5f','歡物吟  其三','邵雍','宋','宋诗','song-poetry','','[]','水雲黑，火雲赤。',16,'全唐诗/poet.song.22000.json','["水雲黑，火雲赤。", "土雲黄，石雲白。"]'),
('a830f57d-13f3-42d8-8c23-7f217b035906','歡物吟  其四','邵雍','宋','宋诗','song-poetry','','[]','水雷{雨/玄}，火雷虩。',20,'全唐诗/poet.song.22000.json','["水雷{雨/玄}，火雷虩。", "土雷連，石雷霹。"]'),
('92205cfd-8537-41c2-9cf0-1f925d41ecd9','晝睡','邵雍','宋','宋诗','song-poetry','','[]','晝睡功夫未易偕，羲皇以上合安排。',64,'全唐诗/poet.song.22000.json','["晝睡功夫未易偕，羲皇以上合安排。", "心間無事飽食後，園裏有時閑步迴。", "未午庭柯鶑屢囀，已殘花徑客稀來。", "請觀世上多愁者，枕簟雖涼無此懷。"]'),
('da82c86e-b40f-44a0-9efa-0125b9ef551a','進退吟','邵雍','宋','宋诗','song-poetry','','[]','進退兩途皆日賓，何煩坐上苦云云。',64,'全唐诗/poet.song.22000.json','["進退兩途皆日賓，何煩坐上苦云云。", "低眉坐處當周物，掉臂行時莫顧人。", "齒髮既衰非少日，林泉能老是長春。", "行於無事人知否，寵辱何由得到身。"]'),
('20a21877-8d08-436b-9a29-bdea8749fa0b','爲客吟  其一','邵雍','宋','宋诗','song-poetry','','[]','忽憶南秦爲客日，洛陽東望隔秦川。',64,'全唐诗/poet.song.22000.json','["忽憶南秦爲客日，洛陽東望隔秦川。", "雲山去此二千里，歲月于今十九年。", "柳色得非新婀娜，江聲應是舊潺湲。", "衰軀設使能重往，疇昔情懷柰杳然。"]'),
('2ed46632-b827-428c-bca9-9b23d6aba7fe','爲客吟  其二','邵雍','宋','宋诗','song-poetry','','[]','忽憶東朐爲客日，壯心初見水雲鄉。',64,'全唐诗/poet.song.22000.json','["忽憶東朐爲客日，壯心初見水雲鄉。", "島夷居處隣荒服，潮水來時雜海商。", "卧看蒼溟圍大塊，坐觀紅日出扶桑。", "虛生虛死人何限，男子之稱不易當。"]'),
('c9d5ca63-c4b1-4c79-a993-ed540f668477','爲客吟  其三','邵雍','宋','宋诗','song-poetry','','[]','忽憶東吳爲客日，當年意氣樂從遊。',64,'全唐诗/poet.song.22000.json','["忽憶東吳爲客日，當年意氣樂從遊。", "登山未始等閑輟，飲酒何嘗容易休。", "萬柄荷香經楚甸，一帆風軟過揚州。", "追思何異邯鄲夢，瞬息光陰三十秋。"]'),
('75ff71a6-9df0-450e-8b11-4106e36291de','爲客吟  其四','邵雍','宋','宋诗','song-poetry','','[]','忽憶太原爲客日，經秋縱酒未成歸。',64,'全唐诗/poet.song.22000.json','["忽憶太原爲客日，經秋縱酒未成歸。", "遠山近水都成恨，高閣斜陽盡是悲。", "年少不禁花到眼，情多唯只淚沾衣。", "如今老向洛城裏，更沒這般愁到眉。"]'),
('2c70763b-ffcf-468a-a018-af8f6f326d2c','攝生吟','邵雍','宋','宋诗','song-poetry','','[]','握固如嬰兒，作氣如壯士。',48,'全唐诗/poet.song.22000.json','["握固如嬰兒，作氣如壯士。", "二者非自然，皆出不容易。", "心爲身之主，志者氣之師。", "沉珠于深淵，養自己天地。"]'),
('64d549a3-f702-41dd-ab49-9bd9644ca104','病中吟','邵雍','宋','宋诗','song-poetry','','[]','堯夫三月病，憂損洛陽人。',48,'全唐诗/poet.song.22000.json','["堯夫三月病，憂損洛陽人。", "非止交朋意，都如骨肉親。", "薦醫心懇切，求藥意慇懃。", "安得如前日，登門謝此恩。"]'),
('f7ef2071-93ee-492b-b010-a2911a102004','重病吟','邵雍','宋','宋诗','song-poetry','','[]','安樂五十年，一旦感重疾。',48,'全唐诗/poet.song.22000.json','["安樂五十年，一旦感重疾。", "仍在盛夏中，伏枕幾百日。", "砭灸與藥餌，百療效無一。", "以命聽於天，於心何所失。"]'),
('17e3eba2-0353-4b24-a1a3-37d92d996a46','天人吟','邵雍','宋','宋诗','song-poetry','','[]','天生此身人力寄，人力盡兮天數至。',32,'全唐诗/poet.song.22000.json','["天生此身人力寄，人力盡兮天數至。", "天人相去不毫芒，若有毫芒却成二。"]'),
('b016ab9a-9869-4de5-9a2e-7756f4b92f1a','疾革吟','邵雍','宋','宋诗','song-poetry','','[]','有命更危亦不死，無命極醫亦無效。',32,'全唐诗/poet.song.22000.json','["有命更危亦不死，無命極醫亦無效。", "唯將以命聽於天，此外誰能閑計較。"]'),
('6d4b4d11-4376-4231-968b-aef4062f5ba3','聽天吟','邵雍','宋','宋诗','song-poetry','','[]','上天生我，上天死我。',20,'全唐诗/poet.song.22000.json','["上天生我，上天死我。", "一聽於天，有何不可。"]'),
('9d482b51-e3f9-4970-a798-9d930e8cc0d7','得一吟','邵雍','宋','宋诗','song-poetry','','[]','天自得一天無既，我一自天而後至。',32,'全唐诗/poet.song.22000.json','["天自得一天無既，我一自天而後至。", "唯天與一無兩般，我亦何嘗與天異。"]'),
('63245d9e-e22a-4d48-ad42-7a60c32d94ad','答客問病','邵雍','宋','宋诗','song-poetry','','[]','世上重黄金，伊予獨喜吟。',48,'全唐诗/poet.song.22000.json','["世上重黄金，伊予獨喜吟。", "死生都一致，利害漫相尋。", "湯濟功非淺，膏肓疾已深。", "然而猶灼艾，用慰友朋心。"]'),
('82d334e8-8bdb-4cc7-bf35-49fd7219d5aa','病亟吟','邵雍','宋','宋诗','song-poetry','','[]','生于太平世，長于太平世。',48,'全唐诗/poet.song.22000.json','["生于太平世，長于太平世。", "老于太平世，死于太平世。", "客問年幾何，六十有七歲。", "俯仰天地間，浩然無所愧。"]'),
('2028971a-c566-4016-92ba-b0f01e9bead1','首尾吟  其一','邵雍','宋','宋诗','song-poetry','','[]','堯夫非是愛吟詩，爲見聖賢興有時。',64,'全唐诗/poet.song.22000.json','["堯夫非是愛吟詩，爲見聖賢興有時。", "日月星辰堯則了，江河淮濟禹平之。", "皇王帝伯經褒貶，雪月風花未品題。", "豈謂古人無闕典，堯夫非是愛吟詩。"]'),
('d107dc31-9f90-4516-8b63-aa08467e5ffe','首尾吟  其二','邵雍','宋','宋诗','song-poetry','','[]','堯夫非是愛吟詩，安樂窩中坐看時。',64,'全唐诗/poet.song.22000.json','["堯夫非是愛吟詩，安樂窩中坐看時。", "一氣旋回無少息，兩儀覆燾未嘗私。", "四時更革互爲主，百物新陳爭效奇。", "享了許多家樂事，堯夫非是愛吟詩。"]'),
('47465701-2eae-491e-b0b5-436a4654d02e','首尾吟  其三','邵雍','宋','宋诗','song-poetry','','[]','堯夫非是愛吟詩，安樂窩中得意時。',64,'全唐诗/poet.song.22000.json','["堯夫非是愛吟詩，安樂窩中得意時。", "志快不須求事顯，書成當自有人知。", "林泉且作酬心物，風月聊充藉手資。", "多少寬平好田地，堯夫非是愛吟詩。"]'),
('190f65f9-2727-4dc9-9c76-c4058f420882','首尾吟  其四','邵雍','宋','宋诗','song-poetry','','[]','堯夫非是愛吟詩，安樂窩中半醉時。',64,'全唐诗/poet.song.22000.json','["堯夫非是愛吟詩，安樂窩中半醉時。", "因月因花因興詠，代書代簡代行移。", "池中既有雙魚躍，天際寧無一鴈飛。", "無限交親在南北，堯夫非是愛吟詩。"]'),
('4a488477-18c3-4b73-920d-0c790f1b5311','首尾吟  其五','邵雍','宋','宋诗','song-poetry','','[]','堯夫非是愛吟詩，詩是堯夫可愛時。',64,'全唐诗/poet.song.22000.json','["堯夫非是愛吟詩，詩是堯夫可愛時。", "寶鑑造形難著髮，鸞刀迎刃豈容絲。", "風埃若不來侵路，塵大何由得上衣。", "欲論誠明是難事，堯夫非是愛吟詩。"]'),
('56fb85e1-5b2e-439d-9b83-d43ca4c414a7','首尾吟  其六','邵雍','宋','宋诗','song-poetry','','[]','堯夫非是愛吟詩，爲見興衰各有時。',64,'全唐诗/poet.song.22000.json','["堯夫非是愛吟詩，爲見興衰各有時。", "天地全功須發露，朝廷盛美在施爲。", "便都默默柰何見，若不云云那得知。", "事在目前人不慮，堯夫非是愛吟詩。"]'),
('87a433a5-7a14-452e-93cf-a4931f7ef450','首尾吟  其七','邵雍','宋','宋诗','song-poetry','','[]','堯夫非是愛吟詩，詩是堯夫不寐時。',64,'全唐诗/poet.song.22000.json','["堯夫非是愛吟詩，詩是堯夫不寐時。", "咀茹蘭薰宜有主，恢張風雅更爲誰。", "三千來首收清月，二十餘年撚白髭。", "了却許多閑職分，堯夫非是愛吟詩。"]'),
('e20812db-3be2-4265-a238-be454339bc1d','首尾吟  其八','邵雍','宋','宋诗','song-poetry','','[]','堯夫非是愛吟詩，詩到忘言是盡時。',64,'全唐诗/poet.song.22000.json','["堯夫非是愛吟詩，詩到忘言是盡時。", "雖則借言通要妙，又須從物見幾微。", "羹因不和方知淡，樂爲無聲始識希。", "多少風花待除改，堯夫非是愛吟詩。"]'),
('0dacfbdc-1cec-4e28-aa24-2ac3d67d9484','首尾吟  其九','邵雍','宋','宋诗','song-poetry','','[]','堯夫非是愛吟詩，雖老精神未耗時。',64,'全唐诗/poet.song.22000.json','["堯夫非是愛吟詩，雖老精神未耗時。", "水竹清閑先據了，鶑花富貴又兼之。", "梧桐月向懷中照，楊柳風來面上吹。", "被有許多閑捧擁，堯夫非是愛吟詩。"]'),
('d28bf31b-f9cd-49a4-b730-e9dbd2bb0b49','首尾吟  其一○','邵雍','宋','宋诗','song-poetry','','[]','堯夫非是愛吟詩，詩是天津竚立時。',64,'全唐诗/poet.song.22000.json','["堯夫非是愛吟詩，詩是天津竚立時。", "有意水聲千古在，無情山色四邊圍。", "孤鴻遠入晴烟去，雙鷺斜穿禁柳飛。", "景物不妨閑自適，堯夫非是愛吟詩。"]'),
('6f7bacbd-18ea-4c4e-8e51-abe8cbba8425','首尾吟  其一一','邵雍','宋','宋诗','song-poetry','','[]','堯夫非是愛吟詩，詩是天津再住時。',64,'全唐诗/poet.song.22000.json','["堯夫非是愛吟詩，詩是天津再住時。", "積翠鶑花供秀潤，上陽風月助新奇。", "鳳凰樓觀雲中看，道德園林枕上窺。", "不負太平吟笑事，堯夫非是愛吟詩。"]'),
('38bff146-5467-48d1-ab0d-3214511a30c4','首尾吟  其一二','邵雍','宋','宋诗','song-poetry','','[]','堯夫非是愛吟詩，詩是堯夫漸老時。',64,'全唐诗/poet.song.22000.json','["堯夫非是愛吟詩，詩是堯夫漸老時。", "每用風騷觀物體，却因言語漏天機。", "林間車馬自稀到，塵外盃觴不浪飛。", "六十一年無事客，堯夫非是愛吟詩。"]'),
('ebbb14d5-6d48-4481-95d0-e53ecdef25f0','首尾吟  其一三','邵雍','宋','宋诗','song-poetry','','[]','堯夫非是愛吟詩，詩是堯夫忠恕時。',64,'全唐诗/poet.song.22000.json','["堯夫非是愛吟詩，詩是堯夫忠恕時。", "無限物情閑處見，諸般藥性病來知。", "暗於成事事必敗，失在知人人必欺。", "家國與身同一體，堯夫非是愛吟詩。"]'),
('f9a1ac58-c00b-44cb-86bd-703bc9e51c3f','首尾吟  其一四','邵雍','宋','宋诗','song-poetry','','[]','堯夫非是愛吟詩，詩是堯夫默識時。',64,'全唐诗/poet.song.22000.json','["堯夫非是愛吟詩，詩是堯夫默識時。", "初有意時如父子，到無情處類蠻夷。", "睛前成敗尚不見，天下安危那得知。", "始信知人是難事，堯夫非是愛吟詩。"]'),
('46d179bf-f133-4801-a02f-cc7fc1c7856a','首尾吟  其一五','邵雍','宋','宋诗','song-poetry','','[]','堯夫非是愛吟詩，詩是堯夫知幸時。',64,'全唐诗/poet.song.22000.json','["堯夫非是愛吟詩，詩是堯夫知幸時。", "日未出前朝象帝，天纔春處謁庖犧。", "三盃五盞自勸酒，一局兩局無爭棋。", "韶濩不知何似樂，堯夫非是愛吟詩。"]'),
('820d5411-c64b-4080-8aa4-233cc8f7359d','首尾吟  其一六','邵雍','宋','宋诗','song-poetry','','[]','堯夫非是愛吟詩，詩是堯夫自勵時。',64,'全唐诗/poet.song.22000.json','["堯夫非是愛吟詩，詩是堯夫自勵時。", "適道全由就師學，出塵須是稟天資。", "好賢只恐知人晚，樂善惟憂見事遲。", "多謝友朋常見教，堯夫非是愛吟詩。"]'),
('ad9dd852-347b-4299-b5aa-e86607de6a10','首尾吟  其一七','邵雍','宋','宋诗','song-poetry','','[]','堯夫非是愛吟詩，詩是堯夫得意時。',64,'全唐诗/poet.song.22000.json','["堯夫非是愛吟詩，詩是堯夫得意時。", "正得意時常起舞，至麾毫處輒能飛。", "南溟萬里鵬初舉，遼海千年鶴乍歸。", "豈止一詩而已矣，堯夫非是愛吟詩。"]'),
('5b574e4a-5e40-446a-a2c3-3d6b8cf4c833','首尾吟  其一八','邵雍','宋','宋诗','song-poetry','','[]','堯夫非是愛吟詩，詩是堯夫可歎時。',64,'全唐诗/poet.song.22000.json','["堯夫非是愛吟詩，詩是堯夫可歎時。", "固有命焉剛不信，是無天也果能欺。", "才高正被聰明使，身貴方爲利害移。", "無計柰何春又老，堯夫非是愛吟詩。"]'),
('28f6ac13-8606-4ed4-982f-41731103cacf','首尾吟  其一九','邵雍','宋','宋诗','song-poetry','','["\u534e\u5c71"]','堯夫非是愛吟詩，詩是堯夫筆逸時。',64,'全唐诗/poet.song.22000.json','["堯夫非是愛吟詩，詩是堯夫筆逸時。", "蒼海有神搜鯨鯢，陸沉無水藏蛟螭。", "岌嶪五千仞華嶽，汪洋十萬頃黄陂。", "都與收來入近題，堯夫非是愛吟詩。"]'),
('24662aec-09f1-4d25-9c69-d2344e0b3c6a','首尾吟  其二○','邵雍','宋','宋诗','song-poetry','','[]','堯夫非是愛吟詩，詩是堯夫出入時。',64,'全唐诗/poet.song.22000.json','["堯夫非是愛吟詩，詩是堯夫出入時。", "春初暖兮日遲遲，秋初涼兮雲微微。", "輕風動垂柳依依，細雨過芳草萋萋。", "林下小車遊未歸，堯夫非是愛吟詩。"]'),
('c99d8032-220e-4b43-a247-097645773187','首尾吟  其二一','邵雍','宋','宋诗','song-poetry','','[]','堯夫非是愛吟詩，詩是堯夫試硯時。',64,'全唐诗/poet.song.22000.json','["堯夫非是愛吟詩，詩是堯夫試硯時。", "玉未琢前猶索辨，金經煅後更何疑。", "當時掉臂人皆笑，今日摇頭誰不知。", "天外鳳凰飛處別，堯夫非是愛吟詩。"]'),
('352f3261-1285-4251-9dad-e4b02e3c5d43','首尾吟  其二二','邵雍','宋','宋诗','song-poetry','','[]','堯夫非是愛吟詩，詩是堯夫試筆時。',64,'全唐诗/poet.song.22000.json','["堯夫非是愛吟詩，詩是堯夫試筆時。", "以至死生猶處了，自餘榮辱可知之。", "適居堂上行堂上，或在水湄言水湄。", "不止省心兼省力，堯夫非是愛吟詩。"]'),
('6bda36d4-57c4-47b5-a6ef-5e2c3738cd35','首尾吟  其二三','邵雍','宋','宋诗','song-poetry','','[]','堯夫非是愛吟詩，詩是堯夫試墨時。',64,'全唐诗/poet.song.22000.json','["堯夫非是愛吟詩，詩是堯夫試墨時。", "十室邑中須有信，三人行處豈無師。", "謀謨不講還疎畧，思慮傷多又忸怩。", "機會失時尋不得，堯夫非是愛吟詩。"]'),
('88527f4f-7a00-4d6a-a615-5e893dc5757f','首尾吟  其二四','邵雍','宋','宋诗','song-poetry','','[]','堯夫非是愛吟詩，詩是堯夫語道時。',64,'全唐诗/poet.song.22000.json','["堯夫非是愛吟詩，詩是堯夫語道時。", "天聽雖高只些子，人情相去沒多兒。", "無聲無臭儘休也，不忮不求還得之。", "雖有丹青亦難狀，堯夫非是愛吟詩。"]'),
('c736685a-70c2-4a14-851d-22b6440958d2','首尾吟  其二五','邵雍','宋','宋诗','song-poetry','','[]','堯夫非是愛吟詩，詩是堯夫語物時。',64,'全唐诗/poet.song.22000.json','["堯夫非是愛吟詩，詩是堯夫語物時。", "物盛物衰隨氣候，人榮人瘁逐推移。", "天邊新月有時待，水上落花何處追。", "皆是世間常事耳，堯夫非是愛吟詩。"]'),
('11dcf8c4-610b-4736-a0aa-3dd2e167af4e','首尾吟  其二六','邵雍','宋','宋诗','song-poetry','','[]','堯夫非是愛吟詩，詩是堯夫語事時。',64,'全唐诗/poet.song.22000.json','["堯夫非是愛吟詩，詩是堯夫語事時。", "天若可升非待勸，神如無驗不須祈。", "人當常上易施設，事過面前難改移。", "世盛世衰非一日，堯夫非是愛吟詩。"]'),
('b2b6464e-81f6-4a81-859b-83cd873943f5','首尾吟  其二七','邵雍','宋','宋诗','song-poetry','','[]','堯夫非是愛吟詩，詩是堯夫登閣時。',64,'全唐诗/poet.song.22000.json','["堯夫非是愛吟詩，詩是堯夫登閣時。", "往事千年徒渺漭，斜陽一片漫光輝。", "伊川洛川水似線，太室少室峰如錐。", "爭者從來有閑氣，堯夫非是愛吟詩。"]'),
('6f5f97c5-afac-406e-ad12-139b0ba75f56','首尾吟  其二八','邵雍','宋','宋诗','song-poetry','','[]','堯夫非是愛吟詩，詩是堯夫隠几時。',64,'全唐诗/poet.song.22000.json','["堯夫非是愛吟詩，詩是堯夫隠几時。", "尺寸光陰須愛惜，分毫頭角莫矜馳。", "酒因勸客小盞飲，句到驚人大筆麾。", "無日何嘗不自得，堯夫非是愛吟詩。"]'),
('873812d8-24d1-468e-9a65-38d1aec6a1be','首尾吟  其二九','邵雍','宋','宋诗','song-poetry','','[]','堯夫非是愛吟詩，詩是堯夫詠史時。',64,'全唐诗/poet.song.22000.json','["堯夫非是愛吟詩，詩是堯夫詠史時。", "曠古第成千覺夢，中原都入一枰棋。", "唐虞玉帛煙光紫，湯武干戈草色萋。", "觀古事多今可見，堯夫非是愛吟詩。"]'),
('72e2159b-46ce-49e6-a546-5fcb7d5b6f95','首尾吟  其三○','邵雍','宋','宋诗','song-poetry','','[]','堯夫非是愛吟詩，詩是堯夫對酒時。',64,'全唐诗/poet.song.22000.json','["堯夫非是愛吟詩，詩是堯夫對酒時。", "處世雖無一分善，行身誤有四方知。", "大凡觀物須生意，既若成章必見辭。", "詩者志之所之也，堯夫非是愛吟詩。"]'),
('d57addbe-b9f0-4c1e-8372-85d20b6b00ac','首尾吟  其三一','邵雍','宋','宋诗','song-poetry','','[]','堯夫非是愛吟詩，詩是堯夫半老時。',64,'全唐诗/poet.song.22000.json','["堯夫非是愛吟詩，詩是堯夫半老時。", "肥遯雖無潤屋物，勞謙却有克家兒。", "筋骸幸且粗康健，談笑不妨閑滑稽。", "六十二年無事客，堯夫非是愛吟詩。"]'),
('f0e62e95-23c1-4447-8b74-499cbe29b337','首尾吟  其三二','邵雍','宋','宋诗','song-poetry','','[]','堯夫非是愛吟詩，詩是堯夫自笑時。',64,'全唐诗/poet.song.22000.json','["堯夫非是愛吟詩，詩是堯夫自笑時。", "閑散何嘗遠人事，語言時復洩天機。", "至微勳業有難立，儘大功名或易爲。", "成敗一歸思慮外，堯夫非是愛吟詩。"]'),
('cb8cec03-317d-430a-840c-d9e132af9bf4','首尾吟  其三三','邵雍','宋','宋诗','song-poetry','','[]','堯夫非是愛吟詩，詩是堯夫讓僕時。',64,'全唐诗/poet.song.22000.json','["堯夫非是愛吟詩，詩是堯夫讓僕時。", "止會摇頭道又錯，柰何轉脚復爲非。", "比圖爲家效功力，更却與物生瑕疵。", "失在知人不無過，堯夫非是愛吟詩。"]'),
('4a9f00a4-9d80-49cc-81e3-d5113c03d541','首尾吟  其三四','邵雍','宋','宋诗','song-poetry','','[]','堯夫非是愛吟詩，詩是堯夫可歎時。',64,'全唐诗/poet.song.22000.json','["堯夫非是愛吟詩，詩是堯夫可歎時。", "大器晚成當自重，小人難養又何疑。", "既無一日九遷則，安有終朝三褫之。", "若向槿花注遠到，堯夫非是愛吟詩。"]'),
('6371e654-d779-48e0-b36a-7219a01194ed','首尾吟  其三五','邵雍','宋','宋诗','song-poetry','','[]','堯夫非是愛吟詩，詩是堯夫樂事時。',64,'全唐诗/poet.song.22000.json','["堯夫非是愛吟詩，詩是堯夫樂事時。", "慷慨丈夫無後悔，分明男子有前知。", "在尋常時觀執守，當倉卒處看施爲。", "善事沒身而已矣，堯夫非是愛吟詩。"]'),
('6e1c29ed-3ef3-48e9-9422-28ee0cef89e6','首尾吟  其三六','邵雍','宋','宋诗','song-poetry','','[]','堯夫非是愛吟詩，詩是堯夫自喜時。',64,'全唐诗/poet.song.22000.json','["堯夫非是愛吟詩，詩是堯夫自喜時。", "名在士人當盛世，生於中國作男兒。", "良辰美景忍虛廢，驟雨飄風無定期。", "過此焉能事追悔，堯夫非是愛吟詩。"]'),
('4632bb82-bd53-4888-8e5a-7fe2f518176d','首尾吟  其三七','邵雍','宋','宋诗','song-poetry','','[]','堯夫非是愛吟詩，詩是堯夫喜老時。',64,'全唐诗/poet.song.22000.json','["堯夫非是愛吟詩，詩是堯夫喜老時。", "好話說時常愈疾，善人逢處每忘機。", "此心是物難爲動，其志唯天然後知。", "詩是堯夫分付處，堯夫非是愛吟詩。"]'),
('c81013a0-a0d5-49f0-8058-7c69e03b1edb','首尾吟  其三八','邵雍','宋','宋诗','song-poetry','','[]','堯夫非是愛吟詩，詩是堯夫贊仲尼。',64,'全唐诗/poet.song.22000.json','["堯夫非是愛吟詩，詩是堯夫贊仲尼。", "大事既去止可歎，皇綱已墜如何追。", "由茲春秋無義戰，所以定哀多微辭。", "絕筆獲麟之一句，堯夫非是愛吟詩。"]'),
('4df296b0-3595-4988-a904-e20ccfc5ec82','首尾吟  其三九','邵雍','宋','宋诗','song-poetry','','[]','堯夫非是愛吟詩，詩是堯夫自在時。',64,'全唐诗/poet.song.22000.json','["堯夫非是愛吟詩，詩是堯夫自在時。", "何處不行芳草地，誰家不望小車兒。", "花枝好處安詳折，酒盞滿時撋就持。", "閑氣虛名都忘了，堯夫非是愛吟詩。"]'),
('9bfeaf96-3f31-41bd-a488-7e2bb3f3ecf5','首尾吟  其四○','邵雍','宋','宋诗','song-poetry','','[]','堯夫非是愛吟詩，詩是堯夫自負時。',64,'全唐诗/poet.song.22000.json','["堯夫非是愛吟詩，詩是堯夫自負時。", "暖日纔從桃李過，涼風又向芰荷吹。", "月華正似金波溜，雪片還如柳絮飛。", "此樂太平然後見，堯夫非是愛吟詩。"]'),
('163a8f32-6c7c-4818-aa01-83661e584d97','首尾吟  其四一','邵雍','宋','宋诗','song-poetry','','[]','堯夫非是愛吟詩，詩是堯夫自得時。',64,'全唐诗/poet.song.22000.json','["堯夫非是愛吟詩，詩是堯夫自得時。", "風露清時收翠潤，山川秀處摘新奇。", "揄揚物性多存體，拂掠人情薄用辭。", "遺味正宜涵泳處，堯夫非是愛吟詩。"]'),
('1c4739b6-9127-4721-b56d-307e5d73a143','首尾吟  其四二','邵雍','宋','宋诗','song-poetry','','[]','堯夫非是愛吟詩，詩是堯夫默坐時。',64,'全唐诗/poet.song.22000.json','["堯夫非是愛吟詩，詩是堯夫默坐時。", "天意教閑須有謂，人心剛動似無知。", "煙輕柳葉眉閑皺，露重花枝淚靜垂。", "應恨堯夫無一語，堯夫非是愛吟詩。"]'),
('03f61175-6df5-4753-b803-4c5b70349603','首尾吟  其四三','邵雍','宋','宋诗','song-poetry','','[]','堯夫非是愛吟詩，詩是堯夫晚望時。',64,'全唐诗/poet.song.22000.json','["堯夫非是愛吟詩，詩是堯夫晚望時。", "恰見花開便花謝，纔聞春至又春歸。", "流鶑啼處春猶在，杜宇來時花已飛。", "春至花開春去謝，堯夫非是愛吟詩。"]'),
('0eaa9147-8333-4131-9939-154cc96e3d86','首尾吟  其四四','邵雍','宋','宋诗','song-poetry','','[]','堯夫非是愛吟詩，詩是堯夫春出時。',64,'全唐诗/poet.song.22000.json','["堯夫非是愛吟詩，詩是堯夫春出時。", "一點兩點小雨過，三聲五聲流鶑啼。", "盃深似錦花間醉，車穩如茵草上歸。", "更在太平無事日，堯夫非是愛吟詩。"]'),
('e4000710-613b-4206-ac08-78d8734d6f8c','首尾吟  其四五','邵雍','宋','宋诗','song-poetry','','[]','堯夫非是愛吟詩，詩是堯夫入夏時。',64,'全唐诗/poet.song.22000.json','["堯夫非是愛吟詩，詩是堯夫入夏時。", "醪酒竹間留客飲，清風水畔向人吹。", "嬋娟月色滿軒檻，菡萏花香盈袖衣。", "樂莫樂于無事樂，堯夫非是愛吟詩。"]'),
('21308173-3710-441a-9c17-9fcb97e12da6','首尾吟  其四六','邵雍','宋','宋诗','song-poetry','','[]','堯夫非是愛吟詩，詩是堯夫秋出時。',64,'全唐诗/poet.song.22000.json','["堯夫非是愛吟詩，詩是堯夫秋出時。", "樓上清風猶足喜，水邊芳草未全衰。", "纔涼便可停新酒，薄暮初能著夾衣。", "都沒人間浪憂事，堯夫非是愛吟詩。"]'),
('22168934-05dc-4eea-bc80-e9d23b275c90','首尾吟  其四七','邵雍','宋','宋诗','song-poetry','','[]','堯夫非是愛吟詩，詩是堯夫自喜時。',64,'全唐诗/poet.song.22000.json','["堯夫非是愛吟詩，詩是堯夫自喜時。", "不用虛名矜智數，且無閑氣撓心脾。", "酒佳驀地泛一𤮕，花好有時簪兩枝。", "更縱無人訝狂怪，堯夫非是愛吟詩。"]'),
('bed0899d-a135-410f-8bc3-4ce3b774bd59','首尾吟  其四八','邵雍','宋','宋诗','song-poetry','','[]','堯夫非是愛吟詩，詩是堯夫確論時。',64,'全唐诗/poet.song.22000.json','["堯夫非是愛吟詩，詩是堯夫確論時。", "若以後時爲失計，必將先手作知幾。", "三千賓客成何夢，百二山河付阿誰。", "弄巧既多翻作拙，堯夫非是愛吟詩。"]'),
('f6706bfe-3c8a-4e22-b22c-f00b1a0aeac3','首尾吟  其四九','邵雍','宋','宋诗','song-poetry','','[]','堯夫非是愛吟詩，詩是堯夫會計時。',64,'全唐诗/poet.song.22000.json','["堯夫非是愛吟詩，詩是堯夫會計時。", "進退雲山爲主判，陶鎔水竹是兼司。", "鶑花舊管三千首，風月初收二百題。", "歲暮又須行考課，堯夫非是愛吟詩。"]'),
('19deb12e-4515-486b-99ab-60022f36d799','首尾吟  其五○','邵雍','宋','宋诗','song-poetry','','[]','堯夫非是愛吟詩，詩是堯夫覺老時。',64,'全唐诗/poet.song.22000.json','["堯夫非是愛吟詩，詩是堯夫覺老時。", "不動已求如孟子，無言又欲學宣尼。", "能知同道道亦得，始信先天天弗違。", "六十三年無事客，堯夫非是愛吟詩。"]'),
('b81ff09f-3296-46ed-9c8f-47874079bf9e','首尾吟  其五一','邵雍','宋','宋诗','song-poetry','','[]','堯夫非是愛吟詩，詩是堯夫贊易時。',64,'全唐诗/poet.song.22000.json','["堯夫非是愛吟詩，詩是堯夫贊易時。", "火在內而刑寡妻，風行外而令庶黎。", "老成人爲福之基，騃孺子爲禍之梯。", "此理昭然多不知，堯夫非是愛吟詩。"]'),
('e892cb89-6d0a-485d-9602-89140e4c039b','首尾吟  其五二','邵雍','宋','宋诗','song-poetry','','[]','堯夫非是愛吟詩，詩是堯夫記所思。',64,'全唐诗/poet.song.22000.json','["堯夫非是愛吟詩，詩是堯夫記所思。", "少日過從都似夢，老年光景只如飛。", "快心事固難强覓，到手物如何不爲。", "欲俟河清人壽幾，堯夫非是愛吟詩。"]'),
('38590649-69b1-40a8-9e02-5f661ea13662','首尾吟  其五三','邵雍','宋','宋诗','song-poetry','','[]','堯夫非是愛吟詩，詩是堯夫重惜時。',64,'全唐诗/poet.song.22000.json','["堯夫非是愛吟詩，詩是堯夫重惜時。", "萬里焦勞無所訴，九重深邃莫能知。", "二年斯得誠爲晚，七日言誅未是遲。", "本固邦寧王道在，堯夫非是愛吟詩。"]'),
('b51de423-b220-4e94-8b41-dcd6b5fb6a20','首尾吟  其五四','邵雍','宋','宋诗','song-poetry','','[]','堯夫非是愛吟詩，詩是堯夫髣髴時。',64,'全唐诗/poet.song.22000.json','["堯夫非是愛吟詩，詩是堯夫髣髴時。", "寫字吟詩爲潤色，通經達道是鎡基。", "經綸亦可爲餘事，性命方能盡所爲。", "可謂一生男子事，堯夫非是愛吟詩。"]'),
('6673509e-7e4f-4975-817d-03e80c4da8ce','首尾吟  其五五','邵雍','宋','宋诗','song-poetry','','[]','堯夫非是愛吟詩，詩是堯夫拍手時。',64,'全唐诗/poet.song.22000.json','["堯夫非是愛吟詩，詩是堯夫拍手時。", "此路清閑都屬我，這般歡喜更饒誰。", "將何勢力爲憑藉，著甚言辭與指揮。", "遷怒飾非何更有，堯夫非是愛吟詩。"]'),
('9555ece1-21db-4089-a370-20d23a0cc688','首尾吟  其五六','邵雍','宋','宋诗','song-poetry','','[]','堯夫非是愛吟詩，詩是堯夫試手時。',64,'全唐诗/poet.song.22000.json','["堯夫非是愛吟詩，詩是堯夫試手時。", "善死自明非不死，有知誰道勝無知。", "楊朱眼淚惟能泣，宋玉心胸只解悲。", "爲報西風漫相侮，堯夫非是愛吟詩。"]'),
('d62d012d-4bff-4519-b700-a0165cffea2c','首尾吟  其五七','邵雍','宋','宋诗','song-poetry','','[]','堯夫非是愛吟詩，詩是堯夫憶昔時。',64,'全唐诗/poet.song.22000.json','["堯夫非是愛吟詩，詩是堯夫憶昔時。", "天下只知才可處，人間不信事難爲。", "眼觀秋水斜陽遠，淚洒西風黄葉飛。", "此意如今都去盡，堯夫非是愛吟詩。"]'),
('91e30c5a-8478-48e2-8556-ba0204c34a72','首尾吟  其五八','邵雍','宋','宋诗','song-poetry','','[]','堯夫非是愛吟詩，詩是堯夫相度時。',64,'全唐诗/poet.song.22000.json','["堯夫非是愛吟詩，詩是堯夫相度時。", "合放手時須放手，得開眉處且開眉。", "狂情多見好人喜，僻性少爲他物移。", "只恨一般言不到，堯夫非是愛吟詩。"]'),
('4be7c982-5ef2-4448-a14a-fd46b39fd2aa','首尾吟  其五九','邵雍','宋','宋诗','song-poetry','','[]','堯夫非是愛吟詩，詩是堯夫樂物時。',64,'全唐诗/poet.song.22000.json','["堯夫非是愛吟詩，詩是堯夫樂物時。", "天地精英都已得，鬼神情狀又能知。", "陶真意向辭中見，借論言從意外移。", "始信詩能通造化，堯夫非是愛吟詩。"]'),
('d9e7bedb-bdeb-40d0-97ca-35f59b336615','首尾吟  其六○','邵雍','宋','宋诗','song-poetry','','[]','堯夫非是愛吟詩，詩是堯夫不樂時。',64,'全唐诗/poet.song.22000.json','["堯夫非是愛吟詩，詩是堯夫不樂時。", "明月恰圓還却缺，好花纔盛又成衰。", "返魂丹向何人用，續命湯於甚處施。", "天聽雖高只些子，堯夫非是愛吟詩。"]'),
('49fb8376-95d3-4e6f-9c3f-a4895f208f9c','首尾吟  其六一','邵雍','宋','宋诗','song-poetry','','[]','堯夫非是愛吟詩，詩是堯夫春盡時。',64,'全唐诗/poet.song.22000.json','["堯夫非是愛吟詩，詩是堯夫春盡時。", "有意落花猶去住，無情流水任東西。", "鶑傳信處音聲切，燕訴寃時言語低。", "似此誤人事多少，堯夫非是愛吟詩。"]'),
('146de58a-7c1d-4a48-8402-e3f277914ec0','首尾吟  其六二','邵雍','宋','宋诗','song-poetry','','[]','堯夫非是愛吟詩，詩是天津秋盡時。',64,'全唐诗/poet.song.22000.json','["堯夫非是愛吟詩，詩是天津秋盡時。", "見慣不驚新物盛，話長難說故人稀。", "雲疎煙淡山仍遠，露冷天高草已衰。", "頼有餘樽自斟酌，堯夫非是愛吟詩。"]'),
('7af2ac8f-c4a2-461f-8795-0dea259b2281','首尾吟  其六三','邵雍','宋','宋诗','song-poetry','','[]','堯夫非是愛吟詩，詩是堯夫代記時。',64,'全唐诗/poet.song.22000.json','["堯夫非是愛吟詩，詩是堯夫代記時。", "官職固難稱太史，文章却欲學宣尼。", "能歸豈謝陶元亮，善聽何慙鍾子期。", "德若不孤吾道在，堯夫非是愛吟詩。"]'),
('75a9944b-04ca-4571-8efd-e864ea2f0ac4','首尾吟  其六四','邵雍','宋','宋诗','song-poetry','','[]','堯夫非是愛吟詩，詩是堯夫曠望時。',64,'全唐诗/poet.song.22000.json','["堯夫非是愛吟詩，詩是堯夫曠望時。", "一片園林擁京國，幾層樓觀犯雲霓。", "朝昏天氣屢變易，今古人情旋合離。", "欲問遠山惟斂黛，堯夫非是愛吟詩。"]'),
('c3665543-848b-43d6-9a23-c87f9f971680','首尾吟  其六五','邵雍','宋','宋诗','song-poetry','','[]','堯夫非是愛吟詩，詩是閑觀蔬圃時。',64,'全唐诗/poet.song.22000.json','["堯夫非是愛吟詩，詩是閑觀蔬圃時。", "暖地春初纔欝欝，宿根秋末却披披。", "韭葱蒜薤青遮隴，蕷芋薑蘘綠滿畦。", "時到皆能弄精彩，堯夫非是愛吟詩。"]'),
('55ea18a5-8a24-4b1b-82db-3801ab0e2fda','首尾吟  其六六','邵雍','宋','宋诗','song-poetry','','[]','堯夫非是愛吟詩，詩是堯夫窮理時。',64,'全唐诗/poet.song.22000.json','["堯夫非是愛吟詩，詩是堯夫窮理時。", "語愛何嘗過父子，講和曾未若夫妻。", "恩多意思翻成恨，歡極情懷却似悲。", "何事人間不如此，堯夫非是愛吟詩。"]'),
('646620e0-3f12-496c-8eac-2a5e9086ee40','首尾吟  其六七','邵雍','宋','宋诗','song-poetry','','[]','堯夫非是愛吟詩，詩是堯夫重惜時。',64,'全唐诗/poet.song.22000.json','["堯夫非是愛吟詩，詩是堯夫重惜時。", "西晉浮誇時可歎，南梁崇尚事堪悲。", "仲尼豈欲輕辭魯，孟子何嘗便去齊。", "儀鳳不來人老去，堯夫非是愛吟詩。"]'),
('6f415562-13fc-417f-9119-86069b284ab6','首尾吟  其六八','邵雍','宋','宋诗','song-poetry','','[]','堯夫非是愛吟詩，詩是堯夫自足時。',64,'全唐诗/poet.song.22000.json','["堯夫非是愛吟詩，詩是堯夫自足時。", "開口笑多無若我，同心言少更爲誰。", "田園管勾憑諸子，樽俎安排仰老妻。", "不信人間有憂事，堯夫非是愛吟詩。"]'),
('930e510a-2dd8-46ba-b222-f4b775fdb90e','首尾吟  其六九','邵雍','宋','宋诗','song-poetry','','[]','堯夫非是愛吟詩，詩是堯夫獨酌時。',64,'全唐诗/poet.song.22000.json','["堯夫非是愛吟詩，詩是堯夫獨酌時。", "一盞兩盞至三盞，五題七題或十題。", "只知人事是太古，不信我身非伏羲。", "爲幸居多宜自樂，堯夫非是愛吟詩。"]'),
('8d43462e-1490-4a0c-b312-342fdaa2db2f','首尾吟  其七○','邵雍','宋','宋诗','song-poetry','','[]','堯夫非是愛吟詩，詩是堯夫切慮時。',64,'全唐诗/poet.song.22000.json','["堯夫非是愛吟詩，詩是堯夫切慮時。", "千世萬世所遭遇，聖人賢人曾施爲。", "當初何故盡有說，在後可能都沒辭。", "事既不同時又異，堯夫非是愛吟詩。"]'),
('e9354bf5-fbe3-4d0e-bbbf-9adfe0653102','首尾吟  其七一','邵雍','宋','宋诗','song-poetry','','[]','堯夫非是愛吟詩，詩是堯夫强少時。',64,'全唐诗/poet.song.22000.json','["堯夫非是愛吟詩，詩是堯夫强少時。", "筇杖蔾杖到手拄，南園北園隨意之。", "酒醺不怕暖生面，花好儘教香惹衣。", "六十四年無事客，堯夫非是愛吟詩。"]'),
('52e51723-bf5d-4e4c-844f-670a9201503d','首尾吟  其七二','邵雍','宋','宋诗','song-poetry','','[]','堯夫非是愛吟詩，詩是堯夫自顧時。',64,'全唐诗/poet.song.22000.json','["堯夫非是愛吟詩，詩是堯夫自顧時。", "若有意時非語話，都無情處是肝脾。", "方將憂己到未到，何暇責人知不知。", "因喜聖賢用心遠，堯夫非是愛吟詩。"]'),
('1d231945-644e-4f8f-b7d2-f0c995860b96','首尾吟  其七三','邵雍','宋','宋诗','song-poetry','','[]','堯夫非是愛吟詩，詩是堯夫自得時。',64,'全唐诗/poet.song.22000.json','["堯夫非是愛吟詩，詩是堯夫自得時。", "已把樂爲心事業，更將安作道樞機。", "未來身上休思念，既入手中須指揮。", "迎刃何煩多顧慮，堯夫非是愛吟詩。"]'),
('e601f386-1ef3-489b-a487-27dcbb3c85df','首尾吟  其七四','邵雍','宋','宋诗','song-poetry','','[]','堯夫非是愛吟詩，詩是堯夫鑑誡時。',64,'全唐诗/poet.song.22000.json','["堯夫非是愛吟詩，詩是堯夫鑑誡時。", "意淺不知多則惑，心靈須識動之微。", "行凶既有人誅戮，心善豈無天保持。", "讀易不惟明禍福，堯夫非是愛吟詩。"]'),
('26a19eff-ef2e-4107-8075-a3b23c933346','首尾吟  其七五','邵雍','宋','宋诗','song-poetry','','[]','堯夫非是愛吟詩，詩是堯夫贊易時。',64,'全唐诗/poet.song.22000.json','["堯夫非是愛吟詩，詩是堯夫贊易時。", "八卦小成皆有主，三才大備畧無遺。", "陰陽消長既未已，動靜吉凶那不知。", "爲見至神功效遠，堯夫非是愛吟詩。"]'),
('4a5ca29f-b4b9-489b-bc17-5c92e2ff1ef9','首尾吟  其七六','邵雍','宋','宋诗','song-poetry','','[]','堯夫非是愛吟詩，詩是堯夫贊易時。',64,'全唐诗/poet.song.22000.json','["堯夫非是愛吟詩，詩是堯夫贊易時。", "大道備人皆有謂，上天生物固無私。", "雖知同道道亦得，未若先天天弗違。", "過此聖人猶不語，堯夫非是愛吟詩。"]'),
('8a62ba17-a916-44f4-b1e6-df59a4bdeb93','首尾吟  其七七','邵雍','宋','宋诗','song-poetry','','[]','堯夫非是愛吟詩，詩是堯夫十月時。',64,'全唐诗/poet.song.22000.json','["堯夫非是愛吟詩，詩是堯夫十月時。", "寒日無光天色遠，陰雲不動柳絲垂。", "園林葉盡鳥未散，道路風多人更稀。", "滿目時光口難道，堯夫非是愛吟詩。"]'),
('33027b71-ad47-49be-8637-bdd8f9f3ded1','首尾吟  其七八','邵雍','宋','宋诗','song-poetry','','[]','堯夫非是愛吟詩，詩是堯夫可愛時。',64,'全唐诗/poet.song.22000.json','["堯夫非是愛吟詩，詩是堯夫可愛時。", "已著意時仍著意，未加辭處與加辭。", "物皆有理我何者，天且不言人代之。", "代了天工無限說，堯夫非是愛吟詩。"]'),
('649d27b2-03df-469a-952b-92aad86c89c6','首尾吟  其七九','邵雍','宋','宋诗','song-poetry','','[]','堯夫非是愛吟詩，詩是堯夫不著棋。',64,'全唐诗/poet.song.22000.json','["堯夫非是愛吟詩，詩是堯夫不著棋。", "大智大謀難忘設，小機小數肯輕爲。", "泥沙用處寧無惜，螻蟻驅時忍更窺。", "天下也宜留一路，堯夫非是愛吟詩。"]'),
('7a9976ef-e933-4ef4-a65a-9958dae0cf54','首尾吟  其八○','邵雍','宋','宋诗','song-poetry','','[]','堯夫非是愛吟詩，詩是堯夫歡喜時。',64,'全唐诗/poet.song.22000.json','["堯夫非是愛吟詩，詩是堯夫歡喜時。", "歡喜焉能便休得，語言須且畧形之。", "胸中所有事既說，天下固無人數殊。", "更不防閑尋罅漏，堯夫非是愛吟詩。"]'),
('c629a5c8-eec3-4917-9693-b2256f455805','首尾吟  其八一','邵雍','宋','宋诗','song-poetry','','[]','堯夫非是愛吟詩，詩是堯夫先見時。',64,'全唐诗/poet.song.22000.json','["堯夫非是愛吟詩，詩是堯夫先見時。", "直在胸中貧亦樂，屈於人下貴奚爲。", "誰何藥可醫無病，多少金能買不疑。", "遲老更逢春不老，堯夫非是愛吟詩。"]'),
('44278b52-c9a6-4488-ac86-2672715c8836','首尾吟  其八二','邵雍','宋','宋诗','song-poetry','','[]','堯夫非是愛吟詩，詩是堯夫不忍時。',64,'全唐诗/poet.song.22000.json','["堯夫非是愛吟詩，詩是堯夫不忍時。", "戾氣中人爲疾病，和氣養物號清微。", "世情非利莫能動，士節待窮然後知。", "尚口乃窮非我事，堯夫非是愛吟詩。"]'),
('5ddbbf73-f71e-40a4-a240-11590152043b','首尾吟  其八三','邵雍','宋','宋诗','song-poetry','','[]','堯夫非是愛吟詩，詩是堯夫恨月時。',64,'全唐诗/poet.song.22000.json','["堯夫非是愛吟詩，詩是堯夫恨月時。", "見說天長在甚處，照教人老待奚爲。", "嬋娟東面才如鑑，屈曲西邊却皺眉。", "由此遂多悲與喜，堯夫非是愛吟詩。"]'),
('e6bf1fc1-c273-426c-873b-8b66a7f610ba','首尾吟  其八四','邵雍','宋','宋诗','song-poetry','','[]','堯夫非是愛吟詩，詩是堯夫愛月時。',64,'全唐诗/poet.song.22000.json','["堯夫非是愛吟詩，詩是堯夫愛月時。", "松上見時偏淡潔，懷中照處特光輝。", "何如亭午更休轉，不柰才圓又却虧。", "青女素娥應有恨，堯夫非是愛吟詩。"]'),
('4e6b2dbc-46b0-4099-bc5a-31363e0b9db9','首尾吟  其八五','邵雍','宋','宋诗','song-poetry','','[]','堯夫非是愛吟詩，詩是堯夫中夜時。',64,'全唐诗/poet.song.22000.json','["堯夫非是愛吟詩，詩是堯夫中夜時。", "擁被不眠還展轉，披衣却坐忽尋思。", "死生有命尚能處，道德由人却不知。", "須是安之以無事，堯夫非是愛吟詩。"]'),
('65de6b3f-1f7f-4ff5-bea7-c7d4d0499205','首尾吟  其八六','邵雍','宋','宋诗','song-poetry','','[]','堯夫非是愛吟詩，詩是堯夫訪友時。',64,'全唐诗/poet.song.22000.json','["堯夫非是愛吟詩，詩是堯夫訪友時。", "青眼主人偶不在，白頭老叟還空歸。", "幾家大第橫斜照，一片殘春啼子規。", "獨往獨來還獨坐，堯夫非是愛吟詩。"]'),
('9043b964-7875-48f7-a627-f41dd0dcde43','首尾吟  其八七','邵雍','宋','宋诗','song-poetry','','[]','堯夫非是愛吟詩，詩是堯夫信脚時。',64,'全唐诗/poet.song.22000.json','["堯夫非是愛吟詩，詩是堯夫信脚時。", "高祖宅前花似錦，魏王堤畔柳如絲。", "因閑看水行來遠，就便遊園歸去遲。", "每遇好風還眷眷，堯夫非是愛吟詩。"]'),
('455bb661-0fe3-4a15-bbe3-df19ae2cb551','首尾吟  其八八','邵雍','宋','宋诗','song-poetry','','[]','堯夫非是愛吟詩，詩是堯夫忖度時。',64,'全唐诗/poet.song.22000.json','["堯夫非是愛吟詩，詩是堯夫忖度時。", "先見固能無後悔，至誠方始有前知。", "己之欲處人須欲，心可欺時天可欺。", "只被世人難易地，堯夫非是愛吟詩。"]'),
('50829635-0318-453b-be06-7c270fe6ac66','首尾吟  其八九','邵雍','宋','宋诗','song-poetry','','[]','堯夫非是愛吟詩，詩是堯夫揮麈時。',64,'全唐诗/poet.song.22000.json','["堯夫非是愛吟詩，詩是堯夫揮麈時。", "每見賓朋須欵曲，更和言語不思惟。", "方將與物同休戚，何暇共人爭是非。", "天地與人同一體，堯夫非是愛吟詩。"]'),
('84fc7ebe-0e68-4b40-906f-a57baaa648e1','首尾吟  其九○','邵雍','宋','宋诗','song-poetry','','[]','堯夫非是愛吟詩，詩是堯夫恣縱時。',64,'全唐诗/poet.song.22000.json','["堯夫非是愛吟詩，詩是堯夫恣縱時。", "在世上官雖不做，出人間事却能知。", "待天春暖秋涼日，是我東遊西泛時。", "多少寬平好田地，堯夫非是愛吟詩。"]'),
('50df83ac-1df0-4446-9089-99652c6c474d','首尾吟  其九一','邵雍','宋','宋诗','song-poetry','','[]','堯夫非是愛吟詩，詩是堯夫服老時。',64,'全唐诗/poet.song.22000.json','["堯夫非是愛吟詩，詩是堯夫服老時。", "簡尺每稱林下士，過從或著道家衣。", "須將賢傑同星漢，直把身心比鹿麋。", "六十五年無事客，堯夫非是愛吟詩。"]'),
('486b45d5-aca5-44c3-93ce-be3d82ebad9c','首尾吟  其九二','邵雍','宋','宋诗','song-poetry','','[]','堯夫非是愛吟詩，詩是堯夫睡覺時。',64,'全唐诗/poet.song.22000.json','["堯夫非是愛吟詩，詩是堯夫睡覺時。", "夢後舊歡初髣髴，酒醒前事略依稀。", "任經生死心無異，雖隔江湖路不迷。", "因向此中觀至理，堯夫非是愛吟詩。"]'),
('edcdcb9b-8dc4-4e02-b1d3-b4d241eabefe','首尾吟  其九三','邵雍','宋','宋诗','song-poetry','','[]','堯夫非是愛吟詩，詩是堯夫注思時。',64,'全唐诗/poet.song.22000.json','["堯夫非是愛吟詩，詩是堯夫注思時。", "事少全由心意足，病多休道藥難醫。", "情當少日須思老，志在安時莫忘危。", "天道分明人自昧，堯夫非是愛吟詩。"]'),
('b9f38483-02e3-4ca8-b24c-819704e6680d','首尾吟  其九四','邵雍','宋','宋诗','song-poetry','','[]','堯夫非是愛吟詩，詩是堯夫行己時。',64,'全唐诗/poet.song.22000.json','["堯夫非是愛吟詩，詩是堯夫行己時。", "政在我時心必盡，事關人處力難爲。", "人如負我我何預，我若辜人人有詞。", "就責莫如躬自厚，堯夫非是愛吟詩。"]'),
('6611a527-3081-4837-84f3-454f7087437a','首尾吟  其九五','邵雍','宋','宋诗','song-poetry','','[]','堯夫非是愛吟詩，詩是堯夫自省時。',64,'全唐诗/poet.song.22000.json','["堯夫非是愛吟詩，詩是堯夫自省時。", "義若不爲無勇也，幸如有過必知之。", "面前地惡猶能掃，心上田荒何所欺。", "從諫如流是難事，堯夫非是愛吟詩。"]'),
('ae7c1847-39f1-430b-a113-ab4e692324a4','首尾吟  其九六','邵雍','宋','宋诗','song-poetry','','[]','堯夫非是愛吟詩，詩是堯夫盡性時。',64,'全唐诗/poet.song.22000.json','["堯夫非是愛吟詩，詩是堯夫盡性時。", "若聖與仁雖不敢，樂天知命又何疑。", "恢恢志意方閑暇，綽綽情懷正坦夷。", "心逸日休難狀處，堯夫非是愛吟詩。"]'),
('f70810c2-b22d-4d4e-bc3f-af44ab3d24d3','首尾吟  其九七','邵雍','宋','宋诗','song-poetry','','[]','堯夫非是愛吟詩，詩是堯夫用畜時。',64,'全唐诗/poet.song.22000.json','["堯夫非是愛吟詩，詩是堯夫用畜時。", "史籍始終明治亂，經書表裏見安危。", "庖羲可作三才主，孔子當爲萬世師。", "不止前言與往行，堯夫非是愛吟詩。"]'),
('c44a65df-560b-4a34-9dff-8b2d7a22e599','首尾吟  其九八','邵雍','宋','宋诗','song-poetry','','[]','堯夫非是愛吟詩，詩是堯夫出入時。',64,'全唐诗/poet.song.22000.json','["堯夫非是愛吟詩，詩是堯夫出入時。", "草軟沙平月陂下，雲輕日淡上陽西。", "花深柳暗銅馳陌，風暖鶑嬌金谷堤。", "盡是堯夫行樂處，堯夫非是愛吟詩。"]'),
('cfe17b9c-b55e-4b2e-909d-cb3549f80b01','首尾吟  其九九','邵雍','宋','宋诗','song-poetry','','[]','堯夫非是愛吟詩，詩看春秋後語時。',64,'全唐诗/poet.song.22000.json','["堯夫非是愛吟詩，詩看春秋後語時。", "七國縱橫如破的，九州吞吐若枰棋。", "君臣自作逋逃主，將相無非市井兒。", "篆入草書猶不誤，堯夫非是愛吟詩。"]'),
('f0f6af1a-8e23-4f01-85a2-24d868a1d6c8','首尾吟  其一○○','邵雍','宋','宋诗','song-poetry','','[]','堯夫非是愛吟詩，詩是堯夫晚步時。',64,'全唐诗/poet.song.22000.json','["堯夫非是愛吟詩，詩是堯夫晚步時。", "信意遂過高祖宅，因行更上魏王堤。", "設如終久全無託，何似當初都不知。", "料得鬼神知此意，堯夫非是愛吟詩。"]'),
('999ae17f-057b-4117-a1b4-dedee5d308ca','首尾吟  其一○一','邵雍','宋','宋诗','song-poetry','','[]','堯夫非是愛吟詩，詩是堯夫處困時。',64,'全唐诗/poet.song.22000.json','["堯夫非是愛吟詩，詩是堯夫處困時。", "事體極時觀道妙，人情盡處看天機。", "孝慈親和未必見，松柏歲寒然後知。", "匪石未聞心可轉，堯夫非是愛吟詩。"]'),
('f92ef6c4-ad84-4660-a46d-d1fea95a2eea','首尾吟  其一○二','邵雍','宋','宋诗','song-poetry','','[]','堯夫非是愛吟詩，詩是堯夫處否時。',64,'全唐诗/poet.song.22000.json','["堯夫非是愛吟詩，詩是堯夫處否時。", "信道而行安有悔，樂天之外更何疑。", "受疑始見周公旦，經阨方明孔仲尼。", "大聖大神猶不免，堯夫非是愛吟詩。"]'),
('57af015d-c502-4fba-b1aa-ee7fa220ceac','首尾吟  其一○三','邵雍','宋','宋诗','song-poetry','','[]','堯夫非是愛吟詩，詩是堯夫無柰時。',64,'全唐诗/poet.song.22000.json','["堯夫非是愛吟詩，詩是堯夫無柰時。", "眼下見榮還見辱，心中疑是又疑非。", "上陽宮殿空遺堵，金谷園林但落暉。", "天若有言人可問，堯夫非是愛吟詩。"]'),
('ea08a83b-360b-4269-86e6-6dd4a20d3627','首尾吟  其一○四','邵雍','宋','宋诗','song-poetry','','[]','堯夫非是愛吟詩，詩是堯夫擲筆時。',64,'全唐诗/poet.song.22000.json','["堯夫非是愛吟詩，詩是堯夫擲筆時。", "事體順時爲物理，人情安處是天機。", "堅如金石猶能動，靈若鬼神何可欺。", "此外更無言語道，堯夫非是愛吟詩。"]'),
('35f1c22c-913e-44e3-8830-a0989042d718','首尾吟  其一○五','邵雍','宋','宋诗','song-poetry','','[]','堯夫非是愛吟詩，詩是堯夫自詫時。',64,'全唐诗/poet.song.22000.json','["堯夫非是愛吟詩，詩是堯夫自詫時。", "許大天時猶可測，些兒人事豈難知。", "崑崗美玉人難識，滄海明珠世莫窺。", "由是堯夫卿自詫，堯夫非是愛吟詩。"]'),
('79837f06-ca4e-4129-b07c-9feefddd4ad0','首尾吟  其一○六','邵雍','宋','宋诗','song-poetry','','[]','堯夫非是愛吟詩，詩是堯夫慎獨時。',64,'全唐诗/poet.song.22000.json','["堯夫非是愛吟詩，詩是堯夫慎獨時。", "人壽百年無以過，心遊萬仞待何爲。", "爲謀須求心無愧，作事莫幸人不知。", "誠盡鬼神猶且懼，堯夫非是愛吟詩。"]'),
('a9d96a25-0bd7-4123-8f7f-1a6c94a0c2b4','首尾吟  其一○七','邵雍','宋','宋诗','song-poetry','','[]','堯夫非是愛吟詩，詩是堯夫慎與時。',64,'全唐诗/poet.song.22000.json','["堯夫非是愛吟詩，詩是堯夫慎與時。", "初作事時分可否，始親人處定安危。", "殊鄉忠信同思善，異世奸邪共喜私。", "豈待較量然後見，堯夫非是愛吟詩。"]'),
('0802bed8-49c6-4476-9c77-2069c4a1b17b','首尾吟  其一○八','邵雍','宋','宋诗','song-poetry','','[]','堯夫非是愛吟詩，詩是堯夫樂事時。',64,'全唐诗/poet.song.22000.json','["堯夫非是愛吟詩，詩是堯夫樂事時。", "天道虧盈如橐籥，聖人言語似蓍龜。", "光陰去後繩難繫，筋力衰時藥不醫。", "莫把閑愁伴殘照，堯夫非是愛吟詩。"]'),
('57d43b9c-b866-4265-8199-50baf71cb3d5','首尾吟  其一○九','邵雍','宋','宋诗','song-poetry','','[]','堯夫非是愛吟詩，詩是堯夫重惜時。',64,'全唐诗/poet.song.22000.json','["堯夫非是愛吟詩，詩是堯夫重惜時。", "爭向儘時須便信，柰何真處却生疑。", "既稱有客告曾子，豈爲無人毀仲尼。", "父子君臣獨未免，堯夫非是愛吟詩。"]'),
('1ce5aa8b-177c-40dd-909a-0b7e5bb20e0a','首尾吟  其一一○','邵雍','宋','宋诗','song-poetry','','[]','堯夫非是愛吟詩，詩是堯夫掩卷時。',64,'全唐诗/poet.song.22000.json','["堯夫非是愛吟詩，詩是堯夫掩卷時。", "時過猶能用歸妹，物傷長懼入明夷。", "夏商盛日何由見，唐漢衰年爭忍思。", "畎畝不忘天下處，堯夫非是愛吟詩。"]'),
('ea2f4150-257d-4039-bb65-6852d550a8b8','首尾吟  其一一一','邵雍','宋','宋诗','song-poetry','','[]','堯夫非是愛吟詩，詩是堯夫愛物時。',64,'全唐诗/poet.song.22000.json','["堯夫非是愛吟詩，詩是堯夫愛物時。", "曉事情懷須洒落，出塵言語必新奇。", "山川秀拔寧無孕，天地精英自有歸。", "粹氣始能生粹物，堯夫非是愛吟詩。"]'),
('c8af7585-107e-43bf-ab32-eac91608008c','首尾吟  其一一二','邵雍','宋','宋诗','song-poetry','','[]','堯夫非是愛吟詩，詩是堯夫默識時。',64,'全唐诗/poet.song.22000.json','["堯夫非是愛吟詩，詩是堯夫默識時。", "日月既來還却往，園林纔盛又成衰。", "登山高下雖然見，臨水淺深那不知。", "世上高深事無限，堯夫非是愛吟詩。"]'),
('c188aacb-d89c-46ec-833c-553b0b2a13d0','首尾吟  其一一三','邵雍','宋','宋诗','song-poetry','','[]','堯夫非是愛吟詩，詩是堯夫自試時。',64,'全唐诗/poet.song.22000.json','["堯夫非是愛吟詩，詩是堯夫自試時。", "事體待諳然後信，人情非久莫能知。", "同霑雨露蒿萊質，獨出雪霜松柏姿。", "見慣不如身歷過，堯夫非是愛吟詩。"]'),
('09bf7f51-955b-463d-b8fb-f759e9f83039','首尾吟  其一一四','邵雍','宋','宋诗','song-poetry','','[]','堯夫非是愛吟詩，詩是堯夫可歎時。',64,'全唐诗/poet.song.22000.json','["堯夫非是愛吟詩，詩是堯夫可歎時。", "只被人間多用詐，遂令天下盡生疑。", "樽前揖讓三盃酒，坐上交爭一局棋。", "小大不同而已矣，堯夫非是愛吟詩。"]'),
('fddbd67d-e1db-4a75-b43a-71dcb731103a','首尾吟  其一一五','邵雍','宋','宋诗','song-poetry','','[]','堯夫非是愛吟詩，詩是堯夫凭式時。',64,'全唐诗/poet.song.22000.json','["堯夫非是愛吟詩，詩是堯夫凭式時。", "亂法柰何非獨古，措刑安得見於茲。", "當時既有少正卯，今日寧無孔仲尼。", "時世不同人一也，堯夫非是愛吟詩。"]'),
('2119bb4c-673b-4d25-9d3d-6d2b181dc02b','首尾吟  其一一六','邵雍','宋','宋诗','song-poetry','','[]','堯夫非是愛吟詩，詩是堯夫自信時。',64,'全唐诗/poet.song.22000.json','["堯夫非是愛吟詩，詩是堯夫自信時。", "必欲全然無後悔，直須曉了有前知。", "言忠能盡己所有，事善任他人致疑。", "外物從來自難必，堯夫非是愛吟詩。"]'),
('c1533082-6766-40da-9eef-b9e9687334c5','首尾吟  其一一七','邵雍','宋','宋诗','song-poetry','','[]','堯夫非是愛吟詩，詩是堯夫無必時。',64,'全唐诗/poet.song.22000.json','["堯夫非是愛吟詩，詩是堯夫無必時。", "或讓或爭時既往，相因相革事難齊。", "羲軒堯舜前規矩，湯武桓文舊範圍。", "一筆寫成還抹了，堯夫非是愛吟詩。"]'),
('59168915-b813-4e9e-a215-2e0cb01d1005','首尾吟  其一一八','邵雍','宋','宋诗','song-poetry','','[]','堯夫非是愛吟詩，詩是堯夫何所爲。',64,'全唐诗/poet.song.22000.json','["堯夫非是愛吟詩，詩是堯夫何所爲。", "睡思動時親甕牖，幽情發處旁盆池。", "尋芳更用小車去，得句仍將大筆麾。", "餘事不妨閑潤色，堯夫非是愛吟詩。"]'),
('6c35c1da-2ba6-490b-b2d0-25f5a63029f3','首尾吟  其一一九','邵雍','宋','宋诗','song-poetry','','[]','堯夫非是愛吟詩，詩是堯夫詫老時。',64,'全唐诗/poet.song.22000.json','["堯夫非是愛吟詩，詩是堯夫詫老時。", "金玉過從舊朋友，糟糠歡喜老夫妻。", "瓦燒酒盞連醅飲，紙畫棋盤就地圍。", "六十六年無事客，堯夫非是愛吟詩。"]'),
('89d089ba-01dd-475e-98aa-275921bc8a62','首尾吟  其一二○','邵雍','宋','宋诗','song-poetry','','[]','堯夫非是愛吟詩，詩是堯夫樂靜時。',64,'全唐诗/poet.song.22000.json','["堯夫非是愛吟詩，詩是堯夫樂靜時。", "藥裏君臣慵點對，琴中文武倦更移。", "鼎間龍虎忘看守，棋上山河廢指揮。", "亦恐因而害天性，堯夫非是愛吟詩。"]'),
('7246aa8f-d8f7-4d23-a220-2fe57f5d7e5d','首尾吟  其一二一','邵雍','宋','宋诗','song-poetry','','[]','堯夫非是愛吟詩，詩是堯夫談笑時。',64,'全唐诗/poet.song.22000.json','["堯夫非是愛吟詩，詩是堯夫談笑時。", "國士待人能盡意，山翁道我會開眉。", "盞隨酒量徐徐飲，榻逐花陰旋旋移。", "此樂再尋非易得，堯夫非是愛吟詩。"]'),
('b893e5e8-d87c-4701-b8f1-c0f058d15c5e','首尾吟  其一二二','邵雍','宋','宋诗','song-poetry','','[]','堯夫非是愛吟詩，詩是堯夫驚駭時。',64,'全唐诗/poet.song.22000.json','["堯夫非是愛吟詩，詩是堯夫驚駭時。", "暮雨朝雲纔半日，春華秋葉未多時。", "即今世態已堪歎，過此人情更可知。", "一暑一寒何太急，堯夫非是愛吟詩。"]'),
('9d1e12e6-a19c-4e08-b397-54b05ab018c0','首尾吟  其一二三','邵雍','宋','宋诗','song-poetry','','[]','堯夫非是愛吟詩，詩是堯夫自詫時。',64,'全唐诗/poet.song.22000.json','["堯夫非是愛吟詩，詩是堯夫自詫時。", "事少事多都在己，人憂人喜更由誰。", "壺中日月明長在，洞裏乾坤春不歸。", "誰道光陰如過隙，堯夫非是愛吟詩。"]'),
('fd239e65-6831-4257-a7dc-ece87e921b88','首尾吟  其一二四','邵雍','宋','宋诗','song-poetry','','[]','堯夫非是愛吟詩，詩是堯夫疎散時。',64,'全唐诗/poet.song.22000.json','["堯夫非是愛吟詩，詩是堯夫疎散時。", "早是小詩無檢束，那堪大字更狂迷。", "既貪李杜精神好，又愛歐王格韻奇。", "餘事不妨閑戲弄，堯夫非是愛吟詩。"]'),
('b4f0b480-5219-468d-b0f2-ba9252dc5ea3','首尾吟  其一二五','邵雍','宋','宋诗','song-poetry','','[]','堯夫非是愛吟詩，詩是堯夫語事時。',64,'全唐诗/poet.song.22000.json','["堯夫非是愛吟詩，詩是堯夫語事時。", "舉動苟能循義理，辨明安用致言辭。", "艱難圖處費心力，容易來時省指揮。", "欲蓋而彰事多矣，堯夫非是愛吟詩。"]'),
('f4b81d09-6875-4cb5-bc65-20acff28a14c','首尾吟  其一二六','邵雍','宋','宋诗','song-poetry','','[]','堯夫非是愛吟詩，詩是堯夫得意時。',64,'全唐诗/poet.song.22000.json','["堯夫非是愛吟詩，詩是堯夫得意時。", "物向物中觀要妙，人於人上看幾微。", "物中要妙眼前見，人上幾微心裏知。", "且是有金無處買，堯夫非是愛吟詩。"]'),
('83f5274a-8acb-4731-85f0-6d19f74f31da','首尾吟  其一二七','邵雍','宋','宋诗','song-poetry','','[]','堯夫非是愛吟詩，詩是堯夫不强時。',64,'全唐诗/poet.song.22000.json','["堯夫非是愛吟詩，詩是堯夫不强時。", "事到强爲須涉跡，人能知止是先機。", "面前自有好田地，天下豈無平路坡。", "省力事多人不做，堯夫非是愛吟詩。"]'),
('d8d755a1-2015-4880-9b11-d43a26d48539','首尾吟  其一二八','邵雍','宋','宋诗','song-poetry','','[]','堯夫非是愛吟詩，詩是堯夫得意時。',64,'全唐诗/poet.song.22000.json','["堯夫非是愛吟詩，詩是堯夫得意時。", "這意著何言語道，此情惟用喜歡追。", "仙家氣象閑中見，真宰功夫靜處知。", "不必深山更深處，堯夫非是愛吟詩。"]'),
('3d7526a2-4a2f-4cdb-b51c-82b4a21582f6','首尾吟  其一二九','邵雍','宋','宋诗','song-poetry','','[]','堯夫非是愛吟詩，詩是堯夫喜老時。',64,'全唐诗/poet.song.22000.json','["堯夫非是愛吟詩，詩是堯夫喜老時。", "明著衣冠爲士子，高談仁義作男兒。", "敢於世上明開眼，肯向人間浪皺眉。", "六十七年無事客，堯夫非是愛吟詩。"]'),
('4c30ed8e-342b-4d03-99a4-3cc283c10af6','首尾吟  其一三○','邵雍','宋','宋诗','song-poetry','','[]','堯夫非是愛吟詩，詩是堯夫難老時。',64,'全唐诗/poet.song.22000.json','["堯夫非是愛吟詩，詩是堯夫難老時。", "齒暮乍逢新歲月，眼明初見舊親知。", "歡情此去未伏減，飲量近來差覺低。", "六十七年無事客，堯夫非是愛吟詩。"]'),
('5eff642d-57bc-4f41-9faa-d0c62424627c','首尾吟  其一三一','邵雍','宋','宋诗','song-poetry','','[]','堯夫非是愛吟詩，詩是堯夫慎動時。',64,'全唐诗/poet.song.22000.json','["堯夫非是愛吟詩，詩是堯夫慎動時。", "枉道干名名亦失，怫民從欲欲還隳。", "號爲賢者能從善，名日小人能飾非。", "大佞似忠非易辨，堯夫非是愛吟詩。"]'),
('73f211a5-09c4-41bf-a98f-e03b7c1db522','首尾吟  其一三二','邵雍','宋','宋诗','song-poetry','','[]','堯夫非是愛吟詩，詩是堯夫有激時。',64,'全唐诗/poet.song.22000.json','["堯夫非是愛吟詩，詩是堯夫有激時。", "留在胸中防作恨，發于詞上恐成疵。", "芝蘭見處須收採，金玉逢時莫棄遺。", "到此堯夫常自賀，堯夫非是愛吟詩。"]'),
('2c5fb19f-a37a-49fe-bae9-b4b2e36b15df','首尾吟  其一三三','邵雍','宋','宋诗','song-poetry','','[]','堯夫非是愛吟詩，詩是堯夫有愧時。',64,'全唐诗/poet.song.22000.json','["堯夫非是愛吟詩，詩是堯夫有愧時。", "空受半來天下拜，却無些子自家爲。", "心能盡處我自慰，力不周時人亦知。", "只恨一般言未得，堯夫非是愛吟詩。"]'),
('a5aa856e-b1ac-4e42-ac16-991fc7c0e72a','首尾吟  其一三四','邵雍','宋','宋诗','song-poetry','','[]','堯夫非是愛吟詩，詩是堯夫詫劍時。',64,'全唐诗/poet.song.22000.json','["堯夫非是愛吟詩，詩是堯夫詫劍時。", "當煅煉時分勁節，到磨礱處發光輝。", "長蛇封豕休撩亂，狡免妖狐莫陸離。", "此器養來年歲久，堯夫非是愛吟詩。"]'),
('2e93a752-b7e2-461e-91a7-ae2e10c5dd9b','過比干墓','邵雍','宋','宋诗','song-poetry','','[]','精誠皦於日，發出爲忠辭。',48,'全唐诗/poet.song.22000.json','["精誠皦於日，發出爲忠辭。", "方寸已盡破，獨夫猶不知。", "高墳臨大道，老木無柔枝。", "千古存遺像，翻爲諂子嗤。"]'),
('a39a8037-c7da-403d-a5e4-b15f3db06a4c','自遣','邵雍','宋','宋诗','song-poetry','','[]','讀書忘歲月，人競笑蹉跎。',48,'全唐诗/poet.song.22000.json','["讀書忘歲月，人競笑蹉跎。", "但得甘旨足，寧辭辛苦多。", "龍泉去鋩刃，蝸角亦風波。", "知我爲親老，不知將謂何。"]'),
('671dc68c-9193-4da4-ad08-8b3781393736','其一曰春郊閑居','邵雍','宋','宋诗','song-poetry','','[]','居處雖近郭，不欲登城市。',48,'全唐诗/poet.song.22000.json','["居處雖近郭，不欲登城市。", "盡日客不來，至夜門猶閉。", "院靜春正濃，窗閑晝復寐。", "誰知藜藿中，自有詩書味。"]'),
('c0b2ef25-066d-4aee-b8fd-5da2f2d39355','其二曰春郊閑步','邵雍','宋','宋诗','song-poetry','','[]','病起復驚春，携筇看野新。',48,'全唐诗/poet.song.22000.json','["病起復驚春，携筇看野新。", "水邊逢釣者，壠上見耕人。", "訪彼形容苦，酬予家業貧。", "自慙功濟力，未得遂生民。"]'),
('46640314-f38b-47d3-8a79-41f3b9cd2945','其三曰春郊芳草','邵雍','宋','宋诗','song-poetry','','[]','春風必有刀，離腸被君斷。',48,'全唐诗/poet.song.22000.json','["春風必有刀，離腸被君斷。", "春風既無刀，芳草何人剪。", "腸斷不復接，草剪益還生。", "誰人有芳酒，爲我高歌傾。"]'),
('d440aa49-594d-4d80-a687-335aa9d0ef93','其四曰春郊花開','邵雍','宋','宋诗','song-poetry','','[]','桃李正芬敷，花繁覆弊廬。',48,'全唐诗/poet.song.22000.json','["桃李正芬敷，花繁覆弊廬。", "亂香尋密牖，碎影下前除。", "靜遶晝眠後，輕攀春醉餘。", "縱然觀盡日，誰敢罪狂疎。"]'),
('4316a20a-4862-4448-93c6-e82c647fa251','其五曰春郊寒食','邵雍','宋','宋诗','song-poetry','','[]','郭外花亦繁，不謂繁華失。',48,'全唐诗/poet.song.22000.json','["郭外花亦繁，不謂繁華失。", "幸非在郭中，不見繁華物。", "不寒不暖天，半陰半睛日。", "花外鞦韆鳴，月隔鞦韆出。"]'),
('692af96e-a874-40b6-9c18-c016d8f3988a','其六曰春郊晚望','邵雍','宋','宋诗','song-poetry','','[]','風暖轉鳴禽，天低薄薄陰。',48,'全唐诗/poet.song.22000.json','["風暖轉鳴禽，天低薄薄陰。", "煙容凝壠曲，雨意弄河心。", "柳隔高城遠，花藏舊縣深。", "獨憐身卧病，猶許後春尋。"]'),
('f0a7bd5f-6bff-4a1b-8082-40fa7577566c','其七曰春郊雨中','邵雍','宋','宋诗','song-poetry','','[]','九野散漫漫，連昏鳥道間。',48,'全唐诗/poet.song.22000.json','["九野散漫漫，連昏鳥道間。", "坐中迷遠樹，門外失前山。", "襏襫耕夫喜，幈幪居者閑。", "騷人正凝黯，天際意初還。"]'),
('26fd07b1-07dd-4cd3-b2aa-f4bc660ef807','其八曰春郊雨後','邵雍','宋','宋诗','song-poetry','','[]','雨歇蕩餘春，天光露太真。',48,'全唐诗/poet.song.22000.json','["雨歇蕩餘春，天光露太真。", "茵鋪芳草軟，錦濯爛花新。", "風觸鶑簧健，煙舒柳带勻。", "如何當此景，閑卧度昌辰。"]'),
('45499eee-90c3-4cb3-9807-f663af2f488a','其九曰春郊舊酒','邵雍','宋','宋诗','song-poetry','','[]','花開風雨後，忍病欲消磨。',48,'全唐诗/poet.song.22000.json','["花開風雨後，忍病欲消磨。", "未是疎狂極，其如閑頓何。", "梁間新燕亂，天外去鴻多。", "總是灰心事，冥焉晝午過。"]'),
('28ae2a70-13c7-46ee-8d44-ca8831e25fd1','其十曰春郊花落','邵雍','宋','宋诗','song-poetry','','[]','春暮多風雨，離披滿後園。',48,'全唐诗/poet.song.22000.json','["春暮多風雨，離披滿後園。", "曉餘殘片擁，睛外亂紅翻。", "香徑難留裛，嬌心絕弄繁。", "成蹊是桃李，狼智尚無言。"]'),
('084b8f48-9330-4b32-810e-6c22ba41e78a','寄楊軒','邵雍','宋','宋诗','song-poetry','','[]','淇水清且泚，泉源發吾地。',24,'全唐诗/poet.song.22000.json','["淇水清且泚，泉源發吾地。", "流到君家時，盡是思君意。"]'),
('d44c1b1e-30b6-43ae-b004-6ef3464ecd1c','對花','邵雍','宋','宋诗','song-poetry','','[]','新花色鮮艷，故花色憔悴。',24,'全唐诗/poet.song.22000.json','["新花色鮮艷，故花色憔悴。", "明朝花更開，新花何有異。"]'),
('7f7784a1-a7b1-4035-81cf-fe20fad7d7c0','曉物吟','邵雍','宋','宋诗','song-poetry','','[]','曉物情人爲曉事，知時態者號知人。',64,'全唐诗/poet.song.22000.json','["曉物情人爲曉事，知時態者號知人。", "知人淺後却成害，曉事過時還不淳。", "鉛錫點金終是假，丹青畫馬妄求真。", "奈何近世人多愛，惡紫之心殊未申。"]'),
('0f5d26fc-ecd8-4a85-b849-868ed1e634d4','詠世','邵雍','宋','宋诗','song-poetry','','[]','福藝俱全不可逃，無能無福謾徒勞。',32,'全唐诗/poet.song.22000.json','["福藝俱全不可逃，無能無福謾徒勞。", "福微藝廣終須貴，靠福無能久不高。"]'),
('05ab0d3f-c70b-4a19-9a9c-263cfad190a0','富貴','邵雍','宋','宋诗','song-poetry','','[]','富貴如將智力求，仲尼年少合封侯。',32,'全唐诗/poet.song.22000.json','["富貴如將智力求，仲尼年少合封侯。", "世人不解青天意，空使身心半夜愁。"]'),
('d33dc73c-cd51-4908-a1f7-9cceb477be96','破釜','邵雍','宋','宋诗','song-poetry','','[]','有一破釜多故舊，掉向空房不照顧。',112,'全唐诗/poet.song.22000.json','["有一破釜多故舊，掉向空房不照顧。", "上面𡋯土塵埃生，兩璺到耳連底透。", "叫得將來錮露人，拈得與他交覷部。", "羊皮鞴袋扇風急，旋去爐上煉金汁。", "烹向破釜竅眼中，錮露還同如舊日。", "釜有□□人有病，人病還同釜有紊。", "破釜錮露上依然，人□□□枉喪命。"]'),
('7832a160-1779-4c40-bf10-c54278574ae3','五相','邵雍','宋','宋诗','song-poetry','','[]','北巷通南陌，門連五相家。',24,'全唐诗/poet.song.22000.json','["北巷通南陌，門連五相家。", "水分池對岸，牆隔樹交花。"]'),
('c4401889-24ba-4b35-baf6-ce46d532c178','呈富相風箏','邵雍','宋','宋诗','song-poetry','','[]','秋風一繫入雲端，合國人皆仰面觀。',32,'全唐诗/poet.song.22000.json','["秋風一繫入雲端，合國人皆仰面觀。", "好向丹霄休索線，等閑勢斷却收難。"]'),
('f5298d75-a045-4e6b-8aa7-b02c3b5e3771','擔折','邵雍','宋','宋诗','song-poetry','','[]','禹士力生頭，都知閑做弄。',24,'全唐诗/poet.song.22000.json','["禹士力生頭，都知閑做弄。", "直待擔子折，恁待柴束重。"]'),
('db9a11ee-742b-4f35-9403-a736861436f3','相笑','邵雍','宋','宋诗','song-poetry','','[]','白雲耕叟說方知，遥指西南舊殿基。',32,'全唐诗/poet.song.22000.json','["白雲耕叟說方知，遥指西南舊殿基。", "更有笑人君不見，道傍橋是墓前碑。"]'),
('8bbac3c1-7949-4ad3-b8ac-b43e08351daa','歡笑','邵雍','宋','宋诗','song-poetry','','[]','剗平荆棘蓋樓臺，樓上笙簧鼎沸開。',32,'全唐诗/poet.song.22000.json','["剗平荆棘蓋樓臺，樓上笙簧鼎沸開。", "歡笑未絕兵火起，從前荆棘却生來。"]'),
('9ee878d0-fab7-4378-a014-30df7199bf2d','首尾吟','邵雍','宋','宋诗','song-poetry','','[]','堯夫非是愛吟詩，詩是堯夫讚易時。',64,'全唐诗/poet.song.22000.json','["堯夫非是愛吟詩，詩是堯夫讚易時。", "士昧固難分體用，人靈豈不異蓍龜。", "吉凶只向面前决，動靜何煩心上疑。", "由此敢開天下口，堯夫非是愛吟詩。"]'),
('75b434d1-9163-430a-ab54-512af06eebaf','秋日','邵雍','宋','宋诗','song-poetry','','[]','滿目平原百里賒，寂寥深處見人家。',64,'全唐诗/poet.song.22000.json','["滿目平原百里賒，寂寥深處見人家。", "三間草屋無樵爨，一□□□有野花。", "遠出小童尋路徑，歸來老叟带煙霞。", "數聲起笛寒山暮，光照柴門月滿斜。"]'),
('9d011694-2342-4876-8e9b-6d47cfff0418','聞少華崩','邵雍','宋','宋诗','song-poetry','','[]','熙寧壬子歲，少華忽然崩。',47,'全唐诗/poet.song.22000.json','["熙寧壬子歲，少華忽然崩。", "七社民俱死，九泉神不寧。", "昔天無駭，曠古未之聆。", "燮理陰陽者，如何略不驚。"]'),
('5942d2e4-e14f-49c7-bfdd-31bf3425d683','秋夜','邵雍','宋','宋诗','song-poetry','','[]','耿耿銀河秋夜長，起來無寐□思量。',64,'全唐诗/poet.song.22000.json','["耿耿銀河秋夜長，起來無寐□思量。", "思量了後迷還悶，煩惱到頭徒□□。", "□□□□□計較，夢中說夢轉尋常。", "回頭萬事□□迹，空□語言爭知長。"]'),
('80f45d1f-7c8f-4be7-9691-13b979b81981','晝寢房','邵雍','宋','宋诗','song-poetry','','[]','晝寢房中好避乖，中堂有客寄書來。',32,'全唐诗/poet.song.22000.json','["晝寢房中好避乖，中堂有客寄書來。", "多因只是名和利，放向床頭不拆開。"]'),
('c069ff53-d7c5-4c03-b353-4f432cd14556','選官圖','邵雍','宋','宋诗','song-poetry','','[]','虛名虛利太無端，自方□□寸進難。',32,'全唐诗/poet.song.22000.json','["虛名虛利太無端，自方□□寸進難。", "大抵人生只如此，采來誰不做高官。"]'),
('7659c29c-edb7-4595-b3f0-041d98f77cad','暮春吟','邵雍','宋','宋诗','song-poetry','','[]','許大春工造物華，一場狼藉但堪嗟。',64,'全唐诗/poet.song.22000.json','["許大春工造物華，一場狼藉但堪嗟。", "群芳委盡綠陰密，遊騎去殘紅日斜。", "臺上喧呼成蝶夢，眼前零落空楊花。", "人間萬事卒如此，□□莊□□□□。"]'),
('28133eda-255a-4b99-a1ac-2e7ec7d944f2','代書寄張司封吟','邵雍','宋','宋诗','song-poetry','','[]','天機時事不相差，老後□□□□□。',64,'全唐诗/poet.song.22000.json','["天機時事不相差，老後□□□□□。", "□□□□去□□，□□□□□□□。", "□□□□□□□，□□□□□可嗟。", "唯有□風一杯酒，憶君□□□□□。"]'),
('47fd8646-2c16-492c-be8b-0b3bdadb84a7','和人語道吟','邵雍','宋','宋诗','song-poetry','','[]','吾道昭昭是可尊，豈宜他適復□□。',64,'全唐诗/poet.song.22000.json','["吾道昭昭是可尊，豈宜他適復□□。", "珠藏水底川須媚，月到天心夜不昏。", "禮樂不□□□□，詩書自可造形論。", "直須去盡秋毫迹，□□□□□□□。"]'),
('55c2e848-dc7b-4963-be6d-bf45f3231ab3','伊川吟','邵雍','宋','宋诗','song-poetry','','[]','休嗟流年隨逝水，但將清景逐閑情。',64,'全唐诗/poet.song.22000.json','["休嗟流年隨逝水，但將清景逐閑情。", "山河天下從來廣，日月林間長自明。", "幸有園林供笑傲，豈無詩酒樂昇平。", "如何更得煙霞侶，好向伊川老此生。"]'),
('2510a2e8-2a03-4c5c-a03f-88cb5dde2325','六下歲吟','邵雍','宋','宋诗','song-poetry','','[]','六十殘軀鬢已斑，繆稱仙術有□□。',64,'全唐诗/poet.song.22000.json','["六十殘軀鬢已斑，繆稱仙術有□□。", "時來孺子成功易，勢去聖人爲力難。", "雖則筋骸粗康健，柰何情意已闌珊。", "著身爭處明開眼，三十年來看世間。"]'),
('82205401-a04a-49a2-bd40-2288d7fd9895','隨緣吟','邵雍','宋','宋诗','song-poetry','','[]','得路青霄正好衝，休貪糧稻戀深籠。',64,'全唐诗/poet.song.22000.json','["得路青霄正好衝，休貪糧稻戀深籠。", "要無爲後須還朴，好自由時莫厭窮。", "百計用心終是錯，一場大夢到頭空。", "生涯澹澹隨緣過，未肯將身入彀中。"]'),
('91a7a133-9548-4028-b7aa-92670b8a864d','潛機吟','邵雍','宋','宋诗','song-poetry','','[]','世事觀開日，人情看破時。',48,'全唐诗/poet.song.22000.json','["世事觀開日，人情看破時。", "一身都是我，瘦了又還肥。", "貸聚知朋聚，財離親戚離。", "目前常見此，焉得不潜機。"]'),
('17187d50-dcd2-4cd7-8771-55aca2139bb6','無行吟','邵雍','宋','宋诗','song-poetry','','[]','無行少年子，京都來往頻。',48,'全唐诗/poet.song.22000.json','["無行少年子，京都來往頻。", "功名一生事，歌酒十年春。", "有數黄金盡，無情白髮新。", "朋從消散盡，贏得病隨身。"]'),
('c4de43b9-b942-44c1-93c5-a4bb59e51f4f','悲怒吟','邵雍','宋','宋诗','song-poetry','','[]','多怒傷人氣，多悲傷人心。',48,'全唐诗/poet.song.22000.json','["多怒傷人氣，多悲傷人心。", "□□□□□，傷心爲害深。", "害淺藥易治，害深藥難任。", "誰能知未病，何藥能相尋。"]'),
('0206d028-8e63-46bb-8b21-ad73ed362411','觀天','邵雍','宋','宋诗','song-poetry','','[]','千里南山對華山，二山中有修□□。',64,'全唐诗/poet.song.22000.json','["千里南山對華山，二山中有修□□。", "□時禾黍交搔□，□靜禽魚相與閑。", "好景盡□□揚外，虛名不顯落□□。", "□□□語無心旨，自謂羲皇正却還。"]'),
('08e47166-4405-41ab-b1c0-bbba0ed968af','人心','邵雍','宋','宋诗','song-poetry','','[]','弟兄尚路人，它人安可從。',60,'全唐诗/poet.song.22000.json','["弟兄尚路人，它人安可從。", "人心方寸間，山海幾千重。", "輕言託朋友，對面九嶷峰。", "多花必早落，桃李不如松。", "管鮑死已久，何人繼其蹤。"]'),
('d21e8501-9169-43c8-8eff-73bbc9826413','芍藥四首  其一','邵雍','宋','宋诗','song-poetry','','[]','阿姨天上舞霓裳，姊妹庭前剪雪霜。',32,'全唐诗/poet.song.22000.json','["阿姨天上舞霓裳，姊妹庭前剪雪霜。", "要與牡丹爲近侍，鉛華不待學梅妝。"]'),
('6be97aa8-7e10-4e54-922e-14a39b55cb30','芍藥四首  其二','邵雍','宋','宋诗','song-poetry','','[]','含露仙姿近玉堂，翻階美態醉紅粧。',32,'全唐诗/poet.song.22000.json','["含露仙姿近玉堂，翻階美態醉紅粧。", "對花未免須酣舞，到底昌黎是楚狂。"]'),
('787834f6-bfba-4294-a30b-3d992581cece','芍藥四首  其三','邵雍','宋','宋诗','song-poetry','','[]','一聲啼鴂畫樓東，魏紫姚黄掃地空。',32,'全唐诗/poet.song.22000.json','["一聲啼鴂畫樓東，魏紫姚黄掃地空。", "多謝化工憐寂寞，尚留芍藥殿春風。"]'),
('45c945cb-9395-4832-bede-31cd9aa4a08e','芍藥四首  其四','邵雍','宋','宋诗','song-poetry','','[]','花不能言意已知，今君慵飲更無疑。',32,'全唐诗/poet.song.22000.json','["花不能言意已知，今君慵飲更無疑。", "但知白酒留佳客，直待瓊舟覆玉彝。"]'),
('a770532b-6e56-4431-8cd5-84b12a9991fa','遊海棠西山示趙彥成','邵雍','宋','宋诗','song-poetry','','[]','東風吹雨過溪門，白白朱朱亂遠村。',64,'全唐诗/poet.song.22000.json','["東風吹雨過溪門，白白朱朱亂遠村。", "灘石已無回棹勢，岸楓猶出繫船痕。", "時危不厭江山僻，客好惟知笑語溫。", "莫上南岡看春色，海棠花下却銷魂。"]'),
('037ce4e5-798d-4dbf-8247-b00ba486fb07','觸觀物','邵雍','宋','宋诗','song-poetry','','[]','萬物備吾身，身貧道未貧。',48,'全唐诗/poet.song.22000.json','["萬物備吾身，身貧道未貧。", "觀時見物理，主敬得天真。", "心凈星辰夜，情忻草木春。", "自憐斵喪者，能作太平人。"]'),
('0e5fcf0e-2a30-4294-82a3-a6c1d2c72648','晚凉閒步','邵雍','宋','宋诗','song-poetry','','[]','得處亦多矣，風前任鬢班。',48,'全唐诗/poet.song.22000.json','["得處亦多矣，風前任鬢班。", "年過半百外，天與一生閒。", "瑩凈雲間月，分明雨後山。", "中心無所愧，對此敢開顔。"]'),
('d96bc085-c4d5-44e1-acc9-9e813765783f','王氏螟羅氏子','邵雍','宋','宋诗','song-poetry','','[]','庚星一點光無涯，日來飛入江東家。',96,'全唐诗/poet.song.22000.json','["庚星一點光無涯，日來飛入江東家。", "江東江左舊聲氣，叔氏得之真差事。", "歸來瑞光凌九霄，叔氏喜亦迎眉鬢。", "家人驚起偏物色，袖中却得真英物。", "螟蛉須信逢蜾蠃，莫惜丁寧長類我。", "他年解有速肖時，會振風流舊江左。"]'),
('7eaa12c1-e85b-44bb-bff6-5466269eb834','訓世孝弟詩  其一','邵雍','宋','宋诗','song-poetry','','[]','子孝親兮弟敬哥，休殘骨肉起風波。',64,'全唐诗/poet.song.22000.json','["子孝親兮弟敬哥，休殘骨肉起風波。", "劬勞恩重須當報，手足情深要取和。", "公藝同居今古罕，田真共處子孫多。", "如斯遐邇皆稱美，子孝親兮弟敬哥。"]'),
('03c98310-a7bd-41c3-b645-4794e710b8fb','訓世孝弟詩  其二','邵雍','宋','宋诗','song-poetry','','[]','子孝親兮弟敬哥，怡聲下氣與謙和。',64,'全唐诗/poet.song.22000.json','["子孝親兮弟敬哥，怡聲下氣與謙和。", "難兄難弟名偏重，孝子賢孫貴自多。", "負米尚能爲薄養，讀書寧不擢高科。", "仲由陳紀皆如此，子孝親兮弟敬哥。"]'),
('112e6440-6698-4394-a114-e307ef986203','訓世孝弟詩  其三','邵雍','宋','宋诗','song-poetry','','[]','子孝親兮弟敬哥，訓賢妯娌事翁婆。',64,'全唐诗/poet.song.22000.json','["子孝親兮弟敬哥，訓賢妯娌事翁婆。", "好遵孟母三遷教，須讀張公百忍歌。", "孝友睦婣兼任恤，智仁聖義與中和。", "當時曾子同楊博，子孝親兮弟敬哥。"]'),
('ad4f65a7-0aad-4255-8a60-d185e21ca5ef','訓世孝弟詩  其四','邵雍','宋','宋诗','song-poetry','','[]','子孝親兮弟敬哥，光陰擲過疾如梭。',64,'全唐诗/poet.song.22000.json','["子孝親兮弟敬哥，光陰擲過疾如梭。", "庭闈樂處兒孫樂，兄弟和時妯娌和。", "孝弟傳家名不朽，金銀滿柜富如何。", "要知美譽傳今古，子孝親兮弟敬哥。"]'),
('72de3e17-0aa8-4a59-948d-fd220c6e0a30','訓世孝弟詩  其五','邵雍','宋','宋诗','song-poetry','','[]','子孝親兮弟敬哥，天時地利與人和。',64,'全唐诗/poet.song.22000.json','["子孝親兮弟敬哥，天時地利與人和。", "莫言世事常如此，堪嘆人生有幾何。", "滿眼繁華何足貴，一家安樂值錢多。", "奇哉讓梨並懷橘，子孝親兮弟敬哥。"]'),
('23be2042-344f-4e06-90d3-0527ae2f3b82','訓世孝弟詩  其六','邵雍','宋','宋诗','song-poetry','','[]','子孝親兮弟敬哥，晨昏定省莫蹉跎。',64,'全唐诗/poet.song.22000.json','["子孝親兮弟敬哥，晨昏定省莫蹉跎。", "一門孝友真難得，百歲光陰最易過。", "和樂且耽宜自翕，彝倫攸敘在謙和。", "班衣舞罷塤箎奏，子孝親兮弟敬哥。"]'),
('c527bc11-3da3-4faa-a0d5-c1edfa362159','訓世孝弟詩  其七','邵雍','宋','宋诗','song-poetry','','[]','子孝親兮弟敬哥，丈夫休聽室人唆。',64,'全唐诗/poet.song.22000.json','["子孝親兮弟敬哥，丈夫休聽室人唆。", "眼前金帛毋嫌少，膝下兒孫不厭多。", "但得家和貧也好，若教不義富如何。", "王韓孝友垂青史，子孝親兮弟敬哥。"]'),
('0984a046-ac9d-4812-b01f-af9489ae9eb9','訓世孝弟詩  其八','邵雍','宋','宋诗','song-poetry','','[]','子孝親兮弟敬哥，休傷和氣忿爭多。',64,'全唐诗/poet.song.22000.json','["子孝親兮弟敬哥，休傷和氣忿爭多。", "偏生嫉妬偏艱窘，暗積私房暗折磨。", "不孝自然生忤逆，無仁實是出妖魔。", "但聞孝弟傳千古，子孝親兮弟敬哥。"]'),
('3b610a64-1301-45c9-ba14-dc93e5aedce0','訓世孝弟詩  其九','邵雍','宋','宋诗','song-poetry','','[]','子孝親兮弟敬哥，莫因微利遽傷和。',64,'全唐诗/poet.song.22000.json','["子孝親兮弟敬哥，莫因微利遽傷和。", "黄金柜內休嫌少，陰德冥中要積多。", "私曲豈知公直在，剛强無柰善柔何。", "古今簡籍多名譽，子孝親兮弟敬哥。"]'),
('05189237-7523-451d-8c66-afda93e8a576','訓世孝弟詩  其一○','邵雍','宋','宋诗','song-poetry','','[]','子孝親兮并敬哥，吁嗟分拆聽搬唆。',64,'全唐诗/poet.song.22000.json','["子孝親兮并敬哥，吁嗟分拆聽搬唆。", "囊中財物他嫌少，祖上田園你要多。", "夫婦眼前雖快樂，兒孫日後恐消磨。", "何如孝弟親鄉黨，子孝親兮弟敬哥。"]'),
('e9a974db-b181-4339-8ec3-1f27771e861b','訓世孝弟詩  其一一','邵雍','宋','宋诗','song-poetry','','[]','每日清晨一炷香，謝天謝地謝三光。',64,'全唐诗/poet.song.22000.json','["每日清晨一炷香，謝天謝地謝三光。", "所求處處田禾熟，惟願人人壽命長。", "國有賢臣安社稷，家無逆子惱爹娘。", "四方平靜干戈息，我若貧時也不妨。"]'),
('a885629c-b534-4944-b146-20802b60306b','睢陽五老圖','邵雍','宋','宋诗','song-poetry','','[]','政事渾如春夢閑，人情囂薄惡儒冠。',64,'全唐诗/poet.song.22000.json','["政事渾如春夢閑，人情囂薄惡儒冠。", "四朝遺烈承平日，兩世觀風樹大桓。", "經濟安民心不晦，保全傳嗣骨無寒。", "乾元恰似諸公意，符節還同一揆看。"]'),
('a9013da8-91a1-4858-865d-0f90f91758c8','句  其一','邵雍','宋','宋诗','song-poetry','','[]','始信畫前原有易，自從刪後更無詩。',16,'全唐诗/poet.song.22000.json','["始信畫前原有易，自從刪後更無詩。"]'),
('9a350e04-1b58-4a16-b82c-89903a764ed7','句  其二','邵雍','宋','宋诗','song-poetry','','[]','水光連夜白，雪意共雲低。',12,'全唐诗/poet.song.22000.json','["水光連夜白，雪意共雲低。"]'),
('990770ce-6f88-44c3-81d7-9e9f2dcfaed3','句  其三','邵雍','宋','宋诗','song-poetry','','[]','遂令高卧人，欹枕看兒戲。',12,'全唐诗/poet.song.22000.json','["遂令高卧人，欹枕看兒戲。"]'),
('c62efa6f-cc89-4f14-9270-b043efe6de79','句','吳傳正','宋','宋诗','song-poetry','','[]','從此天津南畔景，不教都屬邵堯夫。',16,'全唐诗/poet.song.22000.json','["從此天津南畔景，不教都屬邵堯夫。"]'),
('7fc7b989-5e37-4985-8a53-d34d447c4b9f','和堯夫安樂窩中好打乖吟','任逵','宋','宋诗','song-poetry','','[]','安樂先生醉便歌，莊篇徒爾說焚和。',64,'全唐诗/poet.song.22000.json','["安樂先生醉便歌，莊篇徒爾說焚和。", "有名有守同應少，無事無求得最多。", "勝處林泉供放適，清時風月助吟哦。", "能拋憂責忘勞外，不縱逍遥更待何。"]'),
('162e2583-c84d-4f79-bd97-46786bee1b2f','中秋待月終夕陰晦偶書','吳中復','宋','宋诗','song-poetry','','[]','待月西樓上，平秋氣象分。',48,'全唐诗/poet.song.22000.json','["待月西樓上，平秋氣象分。", "輝光唯此夜，遮掩奈浮雲。", "紅燭燈交爛，清香篆自薰。", "明年好景在，何處會多聞。"]'),
('5dc2dcf4-5ba5-47f8-acb8-4e2a12459edf','齊山圖','吳中復','宋','宋诗','song-poetry','','[]','當時齊映爲州日，從此山因姓得名。',64,'全唐诗/poet.song.22000.json','["當時齊映爲州日，從此山因姓得名。", "却自牧之賦詩後，每逢秋至菊含情。", "行尋古洞諸峯峭，坐看寒溪數曲清。", "夢到亦須塵慮息，那堪圖畫入神京。"]'),
('c8bb6975-bd8f-4b6a-9d54-12bcc7865db8','和承諫議','吳中復','宋','宋诗','song-poetry','','[]','瘴霧日消嵐氣靜，颶風朝息海波閑。',32,'全唐诗/poet.song.22000.json','["瘴霧日消嵐氣靜，颶風朝息海波閑。", "安期嘗餌菖薄在，馬援應無薏苡還。"]'),
('c5915acb-30de-42f2-ab11-64c3fc243f96','謝惠茶','吳中復','宋','宋诗','song-poetry','','[]','我聞蒙山之巔多秀嶺，煙巖抱合五峯頂。',34,'全唐诗/poet.song.22000.json','["我聞蒙山之巔多秀嶺，煙巖抱合五峯頂。", "岷峨氣象壓西垂，惡草不生生菽茗。"]'),
('5b6c1ca0-b26f-499c-a67d-02a58e3b9149','江瀆泛舟','吳中復','宋','宋诗','song-poetry','','[]','曉來一雨過池塘，江瀆祠前館宇凉。',64,'全唐诗/poet.song.22000.json','["曉來一雨過池塘，江瀆祠前館宇凉。", "翠水細風翻晝浪，紅蕖微露浥秋香。", "欲停畫舫收船檝，旋折圓荷當羽觴。", "逃暑豈須河朔飲，遲留車馬到斜陽。"]'),
('d15a9cd3-3abe-4d91-9ffb-fde68a68f7f7','游琴臺墨池','吳中復','宋','宋诗','song-poetry','','[]','尋春景物乍晴暄，連月餘寒花未繁。',64,'全唐诗/poet.song.22000.json','["尋春景物乍晴暄，連月餘寒花未繁。", "犬子琴臺餘古寺，揚雄墨沼但空園。", "池邊宿草交加綠，林外鳴禽相鬭喧。", "秀麥漸漸摇暖日，幾重蒼翠滿郊原。"]'),
('ac3ec998-387c-4a02-8692-7aa1b0738c5e','西樓','吳中復','宋','宋诗','song-poetry','','[]','信美他鄉地，登臨有故樓。',48,'全唐诗/poet.song.22000.json','["信美他鄉地，登臨有故樓。", "清風破大暑，明月轉高秋。", "朝暮岷山秀，東西錦水流。", "賓朋逢好景，把酒爲遲留。"]'),
('2371628c-7cad-4e53-b7cd-4be018af42eb','衆熙亭','吳中復','宋','宋诗','song-poetry','','[]','亭枕方塘上，軒開四照新。',48,'全唐诗/poet.song.22000.json','["亭枕方塘上，軒開四照新。", "花涵清露曉，風卷綠波春。", "日暖眠汀鷺，荷翻躍錦鱗。", "熙熙遊宴地，行樂慰西人。"]'),
('75b42fb2-2e37-4f1f-8e01-d03914e08d73','竹洞','吳中復','宋','宋诗','song-poetry','','[]','陰森過百步，屈曲鎖莓苔。',48,'全唐诗/poet.song.22000.json','["陰森過百步，屈曲鎖莓苔。", "翠色寒無改，清風時自來。", "葉籠蒼玉幹，路入碧雲堆。", "吏散無公事，支筇到幾回。"]'),
('9bc5db3f-cb69-4319-8b37-2d29578a2e87','方物亭','吳中復','宋','宋诗','song-poetry','','[]','草木蟲魚部，披尋自古無。',48,'全唐诗/poet.song.22000.json','["草木蟲魚部，披尋自古無。", "飛沉天産異，生植土風殊。", "物色隨心匠，形容記繪圖。", "虛亭玩真意，浩思滿江湖。"]'),
('5da215a2-e8b1-4c30-b498-5b93aacaece4','翠柏亭','吳中復','宋','宋诗','song-poetry','','[]','衆木墜黄葉，皴皮抱翠枝。',48,'全唐诗/poet.song.22000.json','["衆木墜黄葉，皴皮抱翠枝。", "自然根性在，不爲雪霜移。", "靈潤承多露，清陰貫四時。", "婆娑歲寒意，每到坐遲遲。"]'),
('beba740b-8ce0-4a28-b805-76ba8d9d9d02','圓通庵','吳中復','宋','宋诗','song-poetry','','[]','坐對圓通境，陶然勝靜齋。',48,'全唐诗/poet.song.22000.json','["坐對圓通境，陶然勝靜齋。", "觀空無物我，扣寂外形骸。", "燕坐埋遺照，虛名莫疚懷。", "人間憂樂地，所喪甚山崖。"]'),
('0ff78ad0-d92a-41ae-8144-f4b1081b1ed4','琴壇','吳中復','宋','宋诗','song-poetry','','[]','瀟灑琴壇上，賢侯養道情。',48,'全唐诗/poet.song.22000.json','["瀟灑琴壇上，賢侯養道情。", "無今亦無古，求意不求聲。", "林邃風初靜，雲收月乍明。", "拂絃成一弄，塵思浩然清。"]'),
('20463b26-07e9-4dfa-aefc-edf2bc667f8d','流杯亭','吳中復','宋','宋诗','song-poetry','','[]','結客乘公暇，流觴逐浩歌。',48,'全唐诗/poet.song.22000.json','["結客乘公暇，流觴逐浩歌。", "亂峯晴倒影，曲水宛迴波。", "小海逢元巳，蘭亭記永和。", "西州行樂事，應比晉賢多。"]'),
('42832891-00c9-4aec-ad79-0522b5273d9a','喬柟亭','吳中復','宋','宋诗','song-poetry','','[]','古木西園勝，亭延上客過。',48,'全唐诗/poet.song.22000.json','["古木西園勝，亭延上客過。", "色無花卉妬，堅爲雪霜多。", "幹育千年秀，根含一氣和。", "明堂求厚棟，可得老巖阿。"]'),
('87a94abd-fae0-40b1-9422-5ab3b2d76686','錦亭','吳中復','宋','宋诗','song-poetry','','[]','簾幕臨彫檻，窗疎照爛霞。',48,'全唐诗/poet.song.22000.json','["簾幕臨彫檻，窗疎照爛霞。", "園林初過雨，風日猛催花。", "香入遊人袖，紅堆刺史家。", "四時俱好景，終不似春華。"]'),
('250e38a9-0b84-4527-8ce3-12e4cb85d23e','賦新繁周表權如詔亭','吳中復','宋','宋诗','song-poetry','','[]','君構義方亭，人知善教成。',48,'全唐诗/poet.song.22000.json','["君構義方亭，人知善教成。", "恩封新誥命，詞合舊題名。", "承襲詩庭訓，輝光里閈榮。", "如今綵衣養，藹藹振家聲。"]'),
('2391565c-36a5-4d29-8aa0-446ba3dc5c17','游海雲寺唱和詩','吳中復','宋','宋诗','song-poetry','','[]','錦里風光勝別州，海雲寺枕碧江頭。',64,'全唐诗/poet.song.22000.json','["錦里風光勝別州，海雲寺枕碧江頭。", "連郊瑞麥青黄秀，遶路鳴泉深淺流。", "彩石池邊成故事，茂林坡上憶前遊。", "綠樽好伴衰翁醉，十月殘春不少留。"]'),
('6bc098f8-a80d-4eed-954c-0a34f96f3e16','續和簽判太博遊海雲','吳中復','宋','宋诗','song-poetry','','[]','海雲摸石近東城，莽蒼春郊去路平。',64,'全唐诗/poet.song.22000.json','["海雲摸石近東城，莽蒼春郊去路平。", "遶寺溪光照金絡，夾堤柳色混青旌。", "榴花新釀盈樽淥，玉柄高談照座清。", "上客西州勝京口，給鮮牛炙旋供烹。"]'),
('146ff2b0-b69b-4e77-af54-9e2d029d9c30','江左謂海棠爲川紅','吳中復','宋','宋诗','song-poetry','','[]','靚妝濃淡蕊蒙茸，高下池臺細細風。',64,'全唐诗/poet.song.22000.json','["靚妝濃淡蕊蒙茸，高下池臺細細風。", "却恨韶華偏蜀土，更無顔色似川紅。", "尋香只恐三春暮，把酒欣逢一笑同。", "子美詩才猶閣筆，至今寂寞錦城中。"]'),
('d22cdfc7-c3f1-417a-8a3d-4660ea41a0c0','衆樂亭二首  其一','吳中復','宋','宋诗','song-poetry','','[]','賢侯新葺水雲鄉，虛閣崢嶸綠渺茫。',64,'全唐诗/poet.song.22000.json','["賢侯新葺水雲鄉，虛閣崢嶸綠渺茫。", "波面長橋步明月，人家疎影带殘陽。", "風中白鳥侵煙去，雨後紅蕖擁袖香。", "從此郡圖添故事，歲時遺愛似甘棠。"]'),
('5fb63f69-8202-4ea2-82f1-94678a7a0c24','衆樂亭二首  其二','吳中復','宋','宋诗','song-poetry','','[]','煙波空闊岸低回，草綠花紅處處堆。',64,'全唐诗/poet.song.22000.json','["煙波空闊岸低回，草綠花紅處處堆。", "一片湖光分島溆，四邊山色入樓臺。", "從來未有吾民樂，此地欣逢剌史來。", "目斷鄞江何日到，京師只得畫圖開。"]'),
('c57df59f-3e87-4d7f-85ad-a51d8df9cfc0','覽齊山寺陳鴻斷碑','吳中復','宋','宋诗','song-poetry','','[]','翠琰何年沉朽壤，羨師尋訪得其餘。',64,'全唐诗/poet.song.22000.json','["翠琰何年沉朽壤，羨師尋訪得其餘。", "應同湘水斷碑字，難辨韓陵片石書。", "汩沒身名真夢幻，變遷時月易丘墟。", "收藏且作山中物，莫問陳鴻記事初。"]'),
('1ebbf628-5f83-476c-bd1b-79e848f15359','閏春三月二日陪行之秘監遊柏谷寺','吳中復','宋','宋诗','song-poetry','','[]','寶界嶔岑路入雲，閏餘三月屬芳辰。',64,'全唐诗/poet.song.22000.json','["寶界嶔岑路入雲，閏餘三月屬芳辰。", "烟林未動陰森地，山杏寒開寂寞春。", "潞子嶺頭銷白日，神農祠畔柅朱輪。", "乘閑自是逍遥事，誰羨襄陽倒載人。"]'),
('5e944d71-667d-4f85-aebc-f25de7cd0843','句  其一','吳中復','宋','宋诗','song-poetry','','[]','前有牧之之風流，後有元之之篇詠。',16,'全唐诗/poet.song.22000.json','["前有牧之之風流，後有元之之篇詠。"]'),
('27a7e29c-62b6-488d-ad6f-df7ce5c5e491','句  其二','吳中復','宋','宋诗','song-poetry','','[]','鯨魚有浪春濤闊，銅鼓無聲夜柝閑。',16,'全唐诗/poet.song.22000.json','["鯨魚有浪春濤闊，銅鼓無聲夜柝閑。"]'),
('a780d304-19c0-4cee-b2b0-de0ec5525f26','句  其三','吳中復','宋','宋诗','song-poetry','','[]','莫愛荔子紅，歲作嘉州孽。',12,'全唐诗/poet.song.22000.json','["莫愛荔子紅，歲作嘉州孽。"]'),
('3404dda2-d963-447b-b45b-b78ed410e2dd','送吳中復守長沙','郭獬','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','初登西漢文章府，便領吳王第一州。',32,'全唐诗/poet.song.22000.json','["初登西漢文章府，便領吳王第一州。", "繞郭白雲衡嶽近，滿帆明月洞庭秋。"]'),
('0c43b28b-708c-4b63-904f-d6b71f715740','句','胡枚','宋','宋诗','song-poetry','','[]','西梁萬里何時到，爭似懷沙入九泉。',16,'全唐诗/poet.song.22000.json','["西梁萬里何時到，爭似懷沙入九泉。"]'),
('7f1a17c8-9d75-4ea0-b95e-742976647127','送程給事知越州','陳升之','宋','宋诗','song-poetry','','[]','早年交契最綢繆，垂老江城爲少留。',64,'全唐诗/poet.song.22000.json','["早年交契最綢繆，垂老江城爲少留。", "瀕海新城築金壘，瑣闈初遠邃廷旒。", "過家燕坐多賓樂，到郡公餘放吏休。", "滿目湖山何處勝，蓬萊高閣正清秋。"]'),
('745897ff-09a9-48ca-b971-ca96a2269161','和參寥寄秦少游','釋元淨','宋','宋诗','song-poetry','','[]','巖棲木食已皤然，交舊何人慰眼前。',64,'全唐诗/poet.song.22000.json','["巖棲木食已皤然，交舊何人慰眼前。", "素與晝公心印合，每思秦子意珠圓。", "當年步月來幽谷，柱杖穿雲冒夕煙。", "臺閣山林本無異，故應文字未離禪。"]'),
('0d6c2006-3855-498b-96fa-e5d3ddf90803','和蘇子由','釋元淨','宋','宋诗','song-poetry','','[]','春去春來冬復冬，幾思虛論未緣逢。',32,'全唐诗/poet.song.22000.json','["春去春來冬復冬，幾思虛論未緣逢。", "歙溪道賞兄遺跡，勿少龍泓一老龍。"]'),
('5a20b5d0-ac98-4210-8655-828fe759d342','龍井新亭','釋元淨','宋','宋诗','song-poetry','','[]','暇政去旌斾，杖策訪林邱。',120,'全唐诗/poet.song.22000.json','["暇政去旌斾，杖策訪林邱。", "人惟尚求舊，況悲蒲柳秋。", "雲谷一臨照，聲光半載留。", "軒眉獅子峯，洗眼蒼龍湫。", "路穿亂石脚，亭蔽重岡頭。", "湖山一日盡，萬象掌中浮。", "煮茗欵道論，奠爵致龍優。", "過溪雖犯戒，茲意亦風流。", "自惟日老病，當期安養游。", "願公歸廟堂，用慰天下憂。"]'),
('670d13eb-923a-450a-8cc9-e1e0507607a2','和佛印','釋元淨','宋','宋诗','song-poetry','','[]','久仰真風揚四海，今朝邂逅欲生蓮。',64,'全唐诗/poet.song.22000.json','["久仰真風揚四海，今朝邂逅欲生蓮。", "法燈晃耀皆蒙照，佛印靈玄孰可傳。", "諸子叢林禪裏老，十方塵剎上中天。", "爍迦羅眼周三際，豁破羣迷量廓然。"]'),
('51c2be3b-e396-4452-a545-eb349df53ce1','次趙清獻公詩','釋元淨','宋','宋诗','song-poetry','','[]','南極星臨釋子家，杳然十里稅青華。',32,'全唐诗/poet.song.22000.json','["南極星臨釋子家，杳然十里稅青華。", "公年自爾增仙籍，幾度龍泓詩貢茶。"]'),
('7f44abc0-aac2-42ec-b206-3f585eb55915','龍井十題 風篁嶺','釋元淨','宋','宋诗','song-poetry','','[]','風篁蔭修嶺，挺節含虛心。',24,'全唐诗/poet.song.22000.json','["風篁蔭修嶺，挺節含虛心。", "悠悠往還客，孰不聆清音。"]'),
('29f2b6fe-bdd9-4f4e-aaf8-c89eb3a9526f','龍井亭','釋元淨','宋','宋诗','song-poetry','','[]','虛亭亂石間，中有潛虬府。',24,'全唐诗/poet.song.22000.json','["虛亭亂石間，中有潛虬府。", "澄湛源莫窮，旱歲爲靈雨。"]'),
('68c88ef9-e7f9-4298-b368-e6ce6ec60e0e','歸隠橋','釋元淨','宋','宋诗','song-poetry','','[]','謝講竺峰寺，歸隠新此橋。',24,'全唐诗/poet.song.22000.json','["謝講竺峰寺，歸隠新此橋。", "院幽結林表，身老寄煙霄。"]'),
('0b762ebb-9f28-4dd0-bd33-a6e078f5bf26','潮音堂','釋元淨','宋','宋诗','song-poetry','','[]','真說無所示，真聽無所聞。',24,'全唐诗/poet.song.22000.json','["真說無所示，真聽無所聞。", "海潮山外過，妙響入深雲。"]'),
('914d634f-8fd0-41a0-8b1e-f076634acf7f','坤泉','釋元淨','宋','宋诗','song-poetry','','[]','物外老餘生，泉發幽巖裏。',24,'全唐诗/poet.song.22000.json','["物外老餘生，泉發幽巖裏。", "自可給瓶盂，不羨滄溟水。"]'),
('19abe508-6889-4251-a5ca-9562e90a9de5','訥齋','釋元淨','宋','宋诗','song-poetry','','[]','憶昔毗耶老，杜口有誰聽。',24,'全唐诗/poet.song.22000.json','["憶昔毗耶老，杜口有誰聽。", "還聞寂寞裏，其辯過雷霆。"]'),
('66d9451a-5c09-48f5-b75f-7bf956d4b694','寂室','釋元淨','宋','宋诗','song-poetry','','[]','心寂寂自絕，此意爲君說。',24,'全唐诗/poet.song.22000.json','["心寂寂自絕，此意爲君說。", "寒雲嵌空亭，獨有月照雪。"]'),
('5ad6053d-c04f-4e8b-801b-2ad06dfe7f26','照閣','釋元淨','宋','宋诗','song-poetry','','[]','高峯御皎月，深壑瀉飛湍。',24,'全唐诗/poet.song.22000.json','["高峯御皎月，深壑瀉飛湍。", "誰來白雲裏，與汝憑欄看。"]'),
('b8aeeea9-3d36-4b03-aaf0-d57b783a4e48','獅子峯','釋元淨','宋','宋诗','song-poetry','','[]','獨爾羣山裏，人稱獅子峯。',24,'全唐诗/poet.song.22000.json','["獨爾羣山裏，人稱獅子峯。", "無心自哮吼，顯晦煙雲中。"]'),
('c484c2e8-2785-40b8-a05a-08acbd22c53a','薩埵石','釋元淨','宋','宋诗','song-poetry','','[]','巨石如掌平，兀然半青嶂。',24,'全唐诗/poet.song.22000.json','["巨石如掌平，兀然半青嶂。", "欽哉昔道人，飼虎茲嵓上。"]'),
('43add841-0bb0-441d-b599-9c8b523600da','次韻參寥子寄秦少游三絕時少游舉進士不得  其一','釋元淨','宋','宋诗','song-poetry','','[]','秦郎文字固超然，漢武憑虛意欲仙。',32,'全唐诗/poet.song.22000.json','["秦郎文字固超然，漢武憑虛意欲仙。", "底事秋來不得解，定中試爲問諸天。"]'),
('912ace4a-3631-445d-8c05-cf22c9a3afa2','次韻參寥子寄秦少游三絕時少游舉進士不得  其二','釋元淨','宋','宋诗','song-poetry','','[]','一尾追風抹萬蹄，崑崙玄圃謂朝隮。',32,'全唐诗/poet.song.22000.json','["一尾追風抹萬蹄，崑崙玄圃謂朝隮。", "回看世上無伯樂，却道鹽中勝月題。"]'),
('ff40cb0a-c808-4d1b-b130-1c08f8404c53','次韻參寥子寄秦少游三絕時少游舉進士不得  其三','釋元淨','宋','宋诗','song-poetry','','[]','得失秋毫久已明，不須聞此氣崢嶸。',32,'全唐诗/poet.song.22000.json','["得失秋毫久已明，不須聞此氣崢嶸。", "何妨却伴參寥子，無數新詩咳唾成。"]'),
('13bdc35c-337f-4277-afc7-cc089d5ed5a4','游驪山  其一','張俞','宋','宋诗','song-poetry','','[]','金玉樓臺插碧空，笙歌遞響入天風。',32,'全唐诗/poet.song.22000.json','["金玉樓臺插碧空，笙歌遞響入天風。", "當時國色並春色，盡在君王顧盼中。"]'),
('c4f89651-94dd-4dd6-ab26-ff11555316bf','游驪山  其二','張俞','宋','宋诗','song-poetry','','[]','玉帝樓前鎖碧霞，終年培養牡丹芽。',32,'全唐诗/poet.song.22000.json','["玉帝樓前鎖碧霞，終年培養牡丹芽。", "不防野鹿踰坦入，銜出宮中第一花。"]'),
('d81ad78b-4ea6-4d30-af1c-174d1c8b2003','題溫湯驛  其一','張俞','宋','宋诗','song-poetry','','[]','夢魂飛入瑶臺路，九霞宮裏曾相遇。',32,'全唐诗/poet.song.22000.json','["夢魂飛入瑶臺路，九霞宮裏曾相遇。", "壺天好景自愁人，春水泛花何處去。"]'),
('80c7143e-52c1-4e73-a927-ba718c83b771','題溫湯驛  其二','張俞','宋','宋诗','song-poetry','','[]','昨夜過溫湯，夢與楊妃浴。',24,'全唐诗/poet.song.22000.json','["昨夜過溫湯，夢與楊妃浴。", "敢將豫讓炭，却對卞和玉。"]'),
('ae1cc87e-f075-4c6f-a49c-1692a480b1b6','題溫湯驛  其三','張俞','宋','宋诗','song-poetry','','[]','同歡一宵間，平生萬事足。',24,'全唐诗/poet.song.22000.json','["同歡一宵間，平生萬事足。", "想得唐明皇，暢哉暢哉福。"]'),
('d0e1dd44-6b85-44cc-b0ca-8a666fa7786e','題漢州妓項帊羅','張俞','宋','宋诗','song-poetry','','[]','蜀國佳人號細腰，東臺御史惜妖嬈。',32,'全唐诗/poet.song.22000.json','["蜀國佳人號細腰，東臺御史惜妖嬈。", "從今喚作楊臺柳，舞盡春風萬萬條。"]'),
('2ac45593-9806-4535-be15-7a5188b227d0','楚中作','張俞','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','渺渺洞庭野，蕭蕭黄鶴樓。',120,'全唐诗/poet.song.22000.json','["渺渺洞庭野，蕭蕭黄鶴樓。", "水通雲夢浦，人渡沔陽舟。", "廣澤侵吳壤，孤城接郢丘。", "山分三楚斷，溪入九江流。", "寂寞休兵月，紛紜戰國秋。", "吳生來赤壁，魏武定荆州。", "六代憑形勢，羣雄死寇讐。", "淒涼帝子宅，浩蕩禰衡洲。", "萬里浮雲暮，千年故國愁。", "武昌宮不見，麋鹿自羣游。"]'),
('ffb1f750-3203-4a9a-9f9f-5c5f73240dbc','蠶婦','張俞','宋','宋诗','song-poetry','','["\u53e4\u8bd7\u4e09\u767e\u9996", "\u611f\u4f24", "\u5b8b\u8bd7", "\u5987\u5973", "\u540c\u60c5"]','昨日到城廓，歸來淚滿巾。',24,'全唐诗/poet.song.22000.json','["昨日到城廓，歸來淚滿巾。", "徧身羅綺者，不是養蠶人。"]'),
('8483b27b-4b6a-43ac-ac96-bbcdf550d555','郴州道','張俞','宋','宋诗','song-poetry','','[]','南土殊風氣，冬林葉盡丹。',24,'全唐诗/poet.song.22000.json','["南土殊風氣，冬林葉盡丹。", "越天無雁度，楚澤有龍蟠。"]'),
('78de01f4-bc21-4c04-ab46-dfdc9e48665f','白雲樓','張俞','宋','宋诗','song-poetry','','[]','城上新開百尺樓，白雲人伴白雲留。',32,'全唐诗/poet.song.22000.json','["城上新開百尺樓，白雲人伴白雲留。", "山川半倚三吳勝，江漢常吞七澤流。"]'),
('8da57952-7404-405b-8c0e-fe47242e4369','車湖','張俞','宋','宋诗','song-poetry','','[]','憶昔車公居此地，遺墟繚繞臨清淵。',32,'全唐诗/poet.song.22000.json','["憶昔車公居此地，遺墟繚繞臨清淵。", "惜哉斷石文尚在，野老不識投波瀾。"]'),
('d5efbfc7-65c1-4d88-8d3b-e3398ccf221e','廣州','張俞','宋','宋诗','song-poetry','','[]','越地春生草，春城瞰渺茫。',36,'全唐诗/poet.song.22000.json','["越地春生草，春城瞰渺茫。", "朔風驚瘴海，霧雨破南荒。", "巨舶通蕃國，孤雲遠帝鄉。"]'),
('ffa73aee-d9d2-4bfb-91b2-16304621c1ac','嘉州','張俞','宋','宋诗','song-poetry','','[]','城分二江急，樹入九峯開。',24,'全唐诗/poet.song.22000.json','["城分二江急，樹入九峯開。", "地隔犍牂繞，人從楚蜀來。"]'),
('9d5fb422-15a0-4818-9af5-7f9a566c12aa','丈人觀','張俞','宋','宋诗','song-poetry','','[]','精氣騰井絡，下臨羣嶽尊。',24,'全唐诗/poet.song.22000.json','["精氣騰井絡，下臨羣嶽尊。", "元真戴天坐，執印朝軒轅。"]'),
('52e40c99-5532-4303-9e54-99d5bb92c136','除日萬州臨江亭','張俞','宋','宋诗','song-poetry','','[]','南浦逢除日，天涯有去舟。',24,'全唐诗/poet.song.22000.json','["南浦逢除日，天涯有去舟。", "蠻城和雨閉，峽水带春流。"]'),
('47320100-bd8f-4a61-a9f2-1b3be9108769','岑公巖','張俞','宋','宋诗','song-poetry','','[]','池光復涵澈，萬象皆鏡入。',48,'全唐诗/poet.song.22000.json','["池光復涵澈，萬象皆鏡入。", "亭觀出浮雲，彤彤映邦域。", "左右浮屠宮，巋然爭嶪岌。", "孰云南浦陋，今始逢藻飾。"]'),
('3c33ccec-2070-46d4-8634-fbbf5cf841e5','韓信壇','張俞','宋','宋诗','song-poetry','','[]','漢用亡臣策，登壇授鉞時。',24,'全唐诗/poet.song.22000.json','["漢用亡臣策，登壇授鉞時。", "須知數仞土，曾立太平基。"]'),
('4f3fdc4d-4dca-400c-abd5-078f64eff746','博望侯墓','張俞','宋','宋诗','song-poetry','','[]','九譯使車通，君王悅戰鋒。',24,'全唐诗/poet.song.22000.json','["九譯使車通，君王悅戰鋒。", "爭殘四夷國，只在一枝筇。"]'),
('02feb691-4a14-47e2-8298-215fb049a997','題隠真谷','張俞','宋','宋诗','song-poetry','','[]','綿綿褒斜路，窈窈鄭真谷。',24,'全唐诗/poet.song.22000.json','["綿綿褒斜路，窈窈鄭真谷。", "斯人已千載，高誼猶在目。"]'),
('96d80354-99f6-40fa-9eb0-e607b867c3fa','除夜宿黄沙館書懷','張俞','宋','宋诗','song-poetry','','[]','窮年撫劍獨無眠，世路危疑倦往還。',32,'全唐诗/poet.song.22000.json','["窮年撫劍獨無眠，世路危疑倦往還。", "夜半無人殘月白，狐鳴梟嘯滿空山。"]'),
('cba4cf76-0d21-4971-bd50-bf0286aa40cc','歲窮雨夜獨卧山齋','張俞','宋','宋诗','song-poetry','','[]','歲晏雲深誰與遊，嵓房終夜雨如秋。',32,'全唐诗/poet.song.22000.json','["歲晏雲深誰與遊，嵓房終夜雨如秋。", "不知海上三山夢，何似人間萬戶侯。"]'),
('a3246c04-47a5-4772-a939-4034ffbbbaeb','朱槿花二首  其一','張俞','宋','宋诗','song-poetry','','[]','風雨無人弄晚芳，野橋千樹鬭紅房。',32,'全唐诗/poet.song.22000.json','["風雨無人弄晚芳，野橋千樹鬭紅房。", "朝榮暮落成何事，可笑紛華不久長。"]'),
('9ebb1d39-260d-4ca8-a28c-ed6716a9bab8','朱槿花二首  其二','張俞','宋','宋诗','song-poetry','','[]','朝菌一年迷晦朔，靈蓂千歲換春秋。',32,'全唐诗/poet.song.22000.json','["朝菌一年迷晦朔，靈蓂千歲換春秋。", "如何槿艷無終日，獨倚欄干爲爾羞。"]'),
('5724f7f3-ea9c-45c4-8804-b5ccc11873a4','翠微寺','張俞','宋','宋诗','song-poetry','','[]','翠微寺本翠微宮，樓閣亭臺數十重。',32,'全唐诗/poet.song.22000.json','["翠微寺本翠微宮，樓閣亭臺數十重。", "天子不來僧又死，樵夫時倒一株松。"]'),
('2a8fc1c3-cbe3-42b6-b6f1-2df33fea5c9b','陪孫之翰太傅登成都樓','張俞','宋','宋诗','song-poetry','','[]','齪齪古之人，傷心廣陵廢。',180,'全唐诗/poet.song.22000.json','["齪齪古之人，傷心廣陵廢。", "遂弦蕪城歌，半夜一揮涕。", "蕙紈隨草衰，藻黼歸塵翳。", "魂石斂邱封，歌堂從水逝。", "薰光杳沈滅，吞恨徒千歲。", "我懷吳蜀國，禍亂若符契。", "目覽臺城墟，心感君王世。", "干戈日馳逐，狼虎爭吞噬。", "山河實天塹，城闕巍地肺。", "霸力不久炎，倏忽如焚薙。", "空餘萬雉城，岌倚寒雲際。", "麋鹿玩苹陰，狐狸栖棘衛。", "江漢含嗚咽，岷峨抱迢遞。", "荒村煙花遥，落日寒風厲。", "因知市朝人，自古悲興替。"]'),
('2023422c-d7bf-4943-a2b8-8fbf0c79fc13','謁白帝廟','張俞','宋','宋诗','song-poetry','','[]','孤山扞江口，上有白帝祠。',216,'全唐诗/poet.song.22000.json','["孤山扞江口，上有白帝祠。", "橫視天下險，萬流皆俯窺。", "古殿鎖神物，悲風出陰帷。", "天昏瓦棟折，狐鼠亦生威。", "優巫日鼓舞，鬼怪生奔馳。", "雷霆卷蛟窟，雹火燒松枝。", "入戶精魄動，有如陰兵隨。", "吁哉漢盜亂，海內遂崩離。", "赤龍始潛躍，逐鹿過秦時。", "公孫奮神劍，定蜀圖安危。", "隴坻開北戶，荆門啟東陲。", "長驅百萬衆，日鬭天下師。", "羣豪插羽翼，與漢爭雄雌。", "兩帝不並立，興亡良可悲。", "天運雖有在，聖賢豈無爲。", "昭皇攬英傑，襲軌奄重基。", "風雲共浩蕩，千古餘寒碑。", "威神竟不沒，萬里震南夷。"]'),
('7006c279-5a3f-4f06-8e81-9c7629deacf1','邛州青霞嶂','張俞','宋','宋诗','song-poetry','','[]','霧山瓊合自雲川，戶有清溪種玉田。',32,'全唐诗/poet.song.22000.json','["霧山瓊合自雲川，戶有清溪種玉田。", "萬本桃花不知處，幾人曾得問秦年。"]'),
('978b9f96-d5f0-4c3f-8956-865eb094dba3','邛州青霞嶂 題西山臨江亭','張俞','宋','宋诗','song-poetry','','[]','南北逢除日，天涯有去舟。',48,'全唐诗/poet.song.22000.json','["南北逢除日，天涯有去舟。", "蠻城和雨閉，峽水带春流。", "不負新年感，惟多故國愁。", "甯無賀新酒，徒此事羈囚。"]'),
('3a80f76e-977b-4363-acbe-a59b9e2faddf','遊靈巖','張俞','宋','宋诗','song-poetry','','[]','玉文山後靈巖寺，四百年來選佛場。',32,'全唐诗/poet.song.22000.json','["玉文山後靈巖寺，四百年來選佛場。", "滿地白雲關不住，石泉流出落花香。"]'),
('50a305cf-ac0c-448e-b7ec-59813ec564be','句  其一','張俞','宋','宋诗','song-poetry','','[]','高光如有嗣，吳魏豈勝誅。',12,'全唐诗/poet.song.22000.json','["高光如有嗣，吳魏豈勝誅。"]'),
('5e0bb87d-47a9-4d52-87ba-8ff6d1270250','句  其二','張俞','宋','宋诗','song-poetry','','[]','可勝亡國恨，猶有愛山心。',12,'全唐诗/poet.song.22000.json','["可勝亡國恨，猶有愛山心。"]'),
('ec43c21d-8259-4949-8f9d-ba5007aa7934','句  其三','張俞','宋','宋诗','song-poetry','','[]','萬頃碧波看不盡，一拳孤岫望中明。',16,'全唐诗/poet.song.22000.json','["萬頃碧波看不盡，一拳孤岫望中明。"]'),
