('c14470af-e26a-43a8-88fa-1064e3325c33','句  其五','張俞','宋','宋诗','song-poetry','','[]','與誰天末分青髻，長向人間畫翠哦。',16,'全唐诗/poet.song.22000.json','["與誰天末分青髻，長向人間畫翠哦。"]'),
('22eb3022-da57-4ae7-a29f-557f5e1d9885','句  其六','張俞','宋','宋诗','song-poetry','','[]','真人自有龍蹻術，可笑長生事戰爭。',16,'全唐诗/poet.song.22000.json','["真人自有龍蹻術，可笑長生事戰爭。"]'),
('2425e52a-47f5-4eaf-9145-b17f70f6f36a','句  其七','張俞','宋','宋诗','song-poetry','','[]','欲作外臣誰是友，白雲孤鶴在巖扉。',16,'全唐诗/poet.song.22000.json','["欲作外臣誰是友，白雲孤鶴在巖扉。"]'),
('e666e30e-709e-49e2-8ddf-1fa6617a32de','句  其八','張俞','宋','宋诗','song-poetry','','[]','昔乃荆棘荒，今爲蕙蘭襲。',12,'全唐诗/poet.song.22000.json','["昔乃荆棘荒，今爲蕙蘭襲。"]'),
('d7d9258d-fbc8-425b-baec-3cc8c0fc788a','句  其九','張俞','宋','宋诗','song-poetry','','[]','康樂有情遥寄想，青谿句在十三峯。',16,'全唐诗/poet.song.22000.json','["康樂有情遥寄想，青谿句在十三峯。"]'),
('21441e32-3505-451b-9096-0feec1653392','句  其一○','張俞','宋','宋诗','song-poetry','','[]','生涯自笑惟詩在，旋種芭蕉聽雨聲。',16,'全唐诗/poet.song.22000.json','["生涯自笑惟詩在，旋種芭蕉聽雨聲。"]'),
('93432c88-333b-4582-a84a-15552e4f945f','句  其一一','張俞','宋','宋诗','song-poetry','','[]','獨得萬古意。',6,'全唐诗/poet.song.22000.json','["獨得萬古意。"]'),
('4b57f428-0382-4267-bdc1-45a91dc789d4','宿上清宮','勾台符','宋','宋诗','song-poetry','','[]','寄宿翠微顛，身疑入半天。',24,'全唐诗/poet.song.22000.json','["寄宿翠微顛，身疑入半天。", "曉鐘鳴物外，殘月落巖前。"]'),
('f2b0ed46-ee7b-47a0-bdf5-2e0db2c8bad4','延慶宮','勾台符','宋','宋诗','song-poetry','','[]','一簇樓臺地，嵯峨四面函。',24,'全唐诗/poet.song.22000.json','["一簇樓臺地，嵯峨四面函。", "路盤七折嶺，坐對六時巖。"]'),
