('be6cbf1f-bf9c-4ab0-ba64-cf650d877f4b','句  其五','勾台符','宋','宋诗','song-poetry','','[]','酷愛青城好山色，終年不出白雲門。',16,'全唐诗/poet.song.22000.json','["酷愛青城好山色，終年不出白雲門。"]'),
('cd726b33-8e25-4b0e-8c56-cabcb9e7cbc9','句  其六','勾台符','宋','宋诗','song-poetry','','[]','右執范賢袂，左拍薛昌肩。',24,'全唐诗/poet.song.22000.json','["右執范賢袂，左拍薛昌肩。", "舉頭傲白日，長嘯揭青天。"]'),
('f82c9798-88e2-4cca-8879-dc51eef3d6fe','逍遥峯訪李覯不遇','饒子尚','宋','宋诗','song-poetry','','[]','疊嶂南奔似躍龍，逍遥樓畔識奇蹤。',64,'全唐诗/poet.song.22000.json','["疊嶂南奔似躍龍，逍遥樓畔識奇蹤。", "雲根盤地三千丈，石徇參天第一峯。", "歲久已知蒼蘚合，曉爲常怪翠雲封。", "肩輿却過株槎路，曙色嵐光隔幾重。"]'),
('e4835d50-9947-4b76-b953-4980b13c2e22','過董孝君祠','杜醇','宋','宋诗','song-poetry','','[]','湖環闞麓任清漣，古廟塵埋自漢傳。',64,'全唐诗/poet.song.22000.json','["湖環闞麓任清漣，古廟塵埋自漢傳。", "劍吐寒芒憤已雪，碑刊軼事墨猶鮮。", "芳名百世留青史，至行千年啟後賢。", "爵祿可辭甘海曲，富春耕釣與駢肩。"]'),
('078298e9-a04c-4b98-b80a-18fa29cb36b8','贈乾明寺繡尼集句','曹希藴','宋','宋诗','song-poetry','','[]','睡起楊花滿繡床，爲他人作嫁衣裳。',32,'全唐诗/poet.song.22000.json','["睡起楊花滿繡床，爲他人作嫁衣裳。", "因過行院逢僧話，始覺空門氣味長。"]'),
('6984458b-1b98-478e-9e4b-fd266ab913f0','新月','曹希藴','宋','宋诗','song-poetry','','[]','禁鼓初聞第一敲，乍看新月出林梢。',32,'全唐诗/poet.song.22000.json','["禁鼓初聞第一敲，乍看新月出林梢。", "誰家寶鑑新磨出，匣小參差蓋不交。"]'),
('eee2abf7-a34d-42b5-a532-92b03f10b3e5','句','曹希藴','宋','宋诗','song-poetry','','[]','記得小軒岑寂夜，月移疏影上東牆。',16,'全唐诗/poet.song.22000.json','["記得小軒岑寂夜，月移疏影上東牆。"]'),
('d0abf9c6-b151-4c22-967b-ba0f1abbae6f','寄睦州蘇七使君','張伯玉','宋','宋诗','song-poetry','','[]','闊步曾飛到廣寒，一麾聊頓野雲間。',64,'全唐诗/poet.song.22000.json','["闊步曾飛到廣寒，一麾聊頓野雲間。", "虬蟠澗底未失水，鶴在籠中且看山。", "舊日笑談猶壯否，近來書信亦稀還。", "嚴灘桐嶺宜秋醉，却恐才高不奈閒。"]'),
('2c03fe6b-8f5d-4b33-93b1-fb47dba82b31','桐廬蘇七太守通判晏魯望遠寄倡和之什輒伸記美','張伯玉','宋','宋诗','song-poetry','','[]','桐君圃外州，樹石最清幽。',72,'全唐诗/poet.song.22000.json','["桐君圃外州，樹石最清幽。", "水截三吳秀，山當百粵秋。", "巖坰無俗土，宅舍有高樓。", "畫隼真才望，題輿雅唱酬。", "灘聲環醉枕，鷺影入茶甌。", "蚤晚陪清躅，梯雲奉俊游。"]'),
('1481fddf-3ae0-4dfa-9c06-befcaa344063','寄新定蘇七太守','張伯玉','宋','宋诗','song-poetry','','[]','聞道銀符渡睦溪，桐山應爲長清暉。',64,'全唐诗/poet.song.22000.json','["聞道銀符渡睦溪，桐山應爲長清暉。", "漁翁幾十迎舟拜，沙鳥成雙夾斾飛。", "檢點簿書茶貢蚤，體量風物橘奴肥。", "題輿自媿來何晚，未得雲中矚使威。"]'),
('30b8bc42-403e-40c6-b117-d260e7e7b02f','之官新定同年李郎中以詩賦別即事感懷次韻上答','張伯玉','宋','宋诗','song-poetry','','[]','雨後驚濤激箭催，爲君停櫂把離杯。',64,'全唐诗/poet.song.22000.json','["雨後驚濤激箭催，爲君停櫂把離杯。", "宦遊向老令人笑，別恨傷春觸處來。", "故國未歸江令宅，全家且上子陵臺。", "如今遇酒伸眉醉，休問多才與不才。"]'),
('3f66eae5-fe7f-4e92-8abc-8e17a4f5f3a5','之官新定寓興三首  其一','張伯玉','宋','宋诗','song-poetry','','[]','關山雨雪征人淚，京洛風塵倦客心。',32,'全唐诗/poet.song.22000.json','["關山雨雪征人淚，京洛風塵倦客心。", "誰信子陵溪上去，一川秋淨滌煩襟。"]'),
('9fcacf0f-b37d-4b24-84b5-4e4f86fb52c4','之官新定寓興三首  其二','張伯玉','宋','宋诗','song-poetry','','[]','汴水東浮不繫舟，到官無事只輕鷗。',32,'全唐诗/poet.song.22000.json','["汴水東浮不繫舟，到官無事只輕鷗。", "不才自古僥天幸，請却俸錢溪上游。"]'),
('c19ada91-2226-4d1e-8f13-acc5562c6121','之官新定寓興三首  其三','張伯玉','宋','宋诗','song-poetry','','[]','溪山千古絕浮埃，時拂朝衣上釣臺。',32,'全唐诗/poet.song.22000.json','["溪山千古絕浮埃，時拂朝衣上釣臺。", "却恐被它漁父笑，糟醨不啜又閒來。"]'),
('17c36538-d0bf-47b6-93f4-d854173c7cfd','之官新定却寄并州通判王幾道','張伯玉','宋','宋诗','song-poetry','','[]','新定與并門，天南天北人。',48,'全唐诗/poet.song.22000.json','["新定與并門，天南天北人。", "扁舟江外客，別乘塞垣身。", "朔馬驚鳴橐，秋鱸上釣綸。", "何時敘離闊，把酒碧嵩春。"]'),
('b83f3eb5-19b3-4136-9626-9bdf4d8db848','七里灘','張伯玉','宋','宋诗','song-poetry','','[]','漱玉鳴珠七里灘，到今猶照客星寒。',32,'全唐诗/poet.song.22000.json','["漱玉鳴珠七里灘，到今猶照客星寒。", "盧奴有水徒千頃，未得高賢一瞬看。"]'),
('93e33a55-3300-4b47-b58e-6b7c2d118d4f','舟次子陵釣臺','張伯玉','宋','宋诗','song-poetry','','[]','十載從軍去又來，强爲顔面走塵埃。',64,'全唐诗/poet.song.22000.json','["十載從軍去又來，强爲顔面走塵埃。", "久慚簪笏未歸去，且喜妻孥共此來。", "旋擷岸蔬供野飯，欲題巖壁拂蒼苔。", "子陵昔日誠高趣，未必全家上釣臺。"]'),
('49a95952-280a-442b-8206-94ab2f3c2e0f','睦州','張伯玉','宋','宋诗','song-poetry','','[]','千家樓閣麗朝暉，人到于今說釣磯。',64,'全唐诗/poet.song.22000.json','["千家樓閣麗朝暉，人到于今說釣磯。", "雨後數峯驕欲鬭，春來兩港活如飛。", "高吟多謝沈家令，中酒長憐杜紫微。", "更愛嚴城無鎖處，白雲摇漾去還歸。"]'),
('82cb241d-bb98-4d07-bb27-1634e72acb49','送交代倅車晏十一魯望','張伯玉','宋','宋诗','song-poetry','','[]','魯望江南客，風騷獵將壇。',180,'全唐诗/poet.song.22000.json','["魯望江南客，風騷獵將壇。", "高吟得意處，清韻逼人寒。", "場屋聲華舊，襟靈渤澥寬。", "閨門盡羔鴈，庭野列芝蘭。", "僶勉來新定，淹留就小官。", "酒論浩劫飲，山欲上天看。", "待月高峯寺，聽猿七里灘。", "入雲移翠簜，鑿石引鳴湍。", "一日交符去，芳風善繼難。", "紅塵久離闊，白首此相歡。", "留方醫鶴膝，貺別遺漁竿。", "虎杏甯知用，松筠幸未殘。", "路長分驥騄，火烈辨琅玕。", "沙際多平仲，鴒原有謝安。", "卷舒知自得，不用苦彈冠。"]'),
('cb287bc6-181a-421a-864c-468710033b44','監州新定却寄并州舊僚','張伯玉','宋','宋诗','song-poetry','','[]','久從光祿長城戍，却到嚴陵舊釣灘。',64,'全唐诗/poet.song.22000.json','["久從光祿長城戍，却到嚴陵舊釣灘。", "休問簿書邊報急，且聽宅舍水聲寒。", "舟浮南渡雲千里，睡起東窗日數竿。", "寄語晉溪溪上月，楚天雖遠一般看。"]'),
('e244f0f4-5a31-4101-bccb-d0c2d143caf5','同年李郎中以詩見寄仍許見過次韻和答','張伯玉','宋','宋诗','song-poetry','','[]','新定溪山國，病懷忻所依。',48,'全唐诗/poet.song.22000.json','["新定溪山國，病懷忻所依。", "桐君談藥妙，嚴瀨得魚肥。", "吏退鈔書譜，朋來典道衣。", "軒車如顧我，春酒上苔磯。"]'),
('efb05301-5c85-431e-a23d-411371c796b9','烏龍寺祈雨回馬上口占','張伯玉','宋','宋诗','song-poetry','','[]','官曹苦覊束，祈靈得幽便。',96,'全唐诗/poet.song.22000.json','["官曹苦覊束，祈靈得幽便。", "夾路松披紛，躡石煙分練。", "迎軒玉泉響，鳴騶沙鳥散。", "曉日破霜陰，前峯藹葱蒨。", "逶迤步高閣，窈窕出雲漢。", "坐來清思生，語餘疏磬緩。", "方將塵滓滌，還憂簿書亂。", "偃旆拂歸韉，回首青猿斷。"]'),
('bf4bb09a-affc-4482-add3-c67b1e410329','西湖樓','張伯玉','宋','宋诗','song-poetry','','["\u897f\u6e56"]','積水照層峯，登臨誰與同。',48,'全唐诗/poet.song.22000.json','["積水照層峯，登臨誰與同。", "望來生羽翼，醉欲上煙空。", "細細濕花雨，疏疏開袖風。", "新安江上景，盡屬此樓中。"]'),
('143177cd-81ee-481f-b06b-75f1be8906e3','玉泉祈雨','張伯玉','宋','宋诗','song-poetry','','[]','南州富潨射，萬壑縱奔瀨。',72,'全唐诗/poet.song.22000.json','["南州富潨射，萬壑縱奔瀨。", "茲泉一何高，夐與寥廓對。", "邈非猿鳥到，迅恐巖磝碎。", "霜落天地清，玉立江海外。", "人區未蒙澤，蛟龍茲有待。", "淺石諒難渟，當與雲漲會。"]'),
('93a23546-27b8-4854-9549-d7fb4de02641','登烏龍山寺閣','張伯玉','宋','宋诗','song-poetry','','[]','桐川本無塵，況此幽閣逈。',144,'全唐诗/poet.song.22000.json','["桐川本無塵，況此幽閣逈。", "萬木含秋聲，一軒與天浄。", "前峯翠分滴，後谷語相應。", "檻下江雲歸，檐前古雪凝。", "巖僧對游客，湛若寒冰瑩。", "百慮緣心空，獨飯隨疏磬。", "嗟余本林壑，謬與世紛競。", "一作市朝人，幾傷麋鹿性。", "舊山別來久，蘿蔓鎖幽徑。", "長恐客沈深，未得歸期定。", "息中來此境，時覺襟韻勝。", "猶媿招隠心，聯爲小山詠。"]'),
('73ffb464-0a02-45cd-856d-ce3b787a19f0','後庵試茶','張伯玉','宋','宋诗','song-poetry','','[]','郡僻好藏身，心閒久無事。',84,'全唐诗/poet.song.22000.json','["郡僻好藏身，心閒久無事。", "前軒飽食罷，後庵取茶試。", "巖邊啟茶鑰，溪畔滌茶器。", "小竈松火然，深鐺雪花沸。", "甌中盡餘綠，物外有深意。", "濫官來此游，時得拂塵累。", "莫笑後庵茶，閒中好滋味。"]'),
('78950594-8c2f-48d1-bdce-3cf98b40e055','郡齋閒步','張伯玉','宋','宋诗','song-poetry','','[]','花木方塘小，樓臺宅院深。',48,'全唐诗/poet.song.22000.json','["花木方塘小，樓臺宅院深。", "以何消俸祿，無事任山林。", "雨雪覊游路，風沙苦戰心。", "若論當此景，不啻萬黄金。"]'),
('8a32967d-c5ed-4b13-b512-4efc3a11a0d4','到新定後却寄蘇州蔣侍郎','張伯玉','宋','宋诗','song-poetry','','[]','遂翁亭畔碧桃開，招隠溪頭畫舫回。',64,'全唐诗/poet.song.22000.json','["遂翁亭畔碧桃開，招隠溪頭畫舫回。", "曾奉雲鴻此真賞，到今羽翼出塵埃。", "閒窺玉字書千卷，渴飲金莖露一杯。", "別後霜天苦寥闊，海雲深處望公臺。"]'),
('26e5d1bf-834c-4857-b738-39111fd68111','自新定沿牒三衢舟中寓興寄所知','張伯玉','宋','宋诗','song-poetry','','[]','井落甌閩近，鄉亭百粵連。',96,'全唐诗/poet.song.22000.json','["井落甌閩近，鄉亭百粵連。", "一蓱游宦客，兩槳上灘船。", "石壅千尋浪，山圍幾匝天。", "亂篙鳴遠嶼，羣譟捧危舷。", "峽斷疑無路，汀回復濟川。", "林深羨沙鳥，村近喜人煙。", "豈昧垂堂誡，都由稍食牽。", "家山舊廬在，蚤晚賦歸田。"]'),
('3eabe3af-db76-456c-a30f-11764422772a','舟次蘭溪却寄新定太守','張伯玉','宋','宋诗','song-poetry','','[]','解纚向蕭瑟，敘別喜英豪。',48,'全唐诗/poet.song.22000.json','["解纚向蕭瑟，敘別喜英豪。", "野水征颿迥，秋天醉幕高。", "使旟標畫隼，騎吹壓霜濤。", "幾日狂酲析，思君夢更勞。"]'),
('44f5c61f-54a5-4457-bd4b-4faa20dab6bb','新安江舟中奉酬孫觀書記','張伯玉','宋','宋诗','song-poetry','','[]','十年塞外憶江山，今日扁舟縱眼看。',64,'全唐诗/poet.song.22000.json','["十年塞外憶江山，今日扁舟縱眼看。", "匝岸野花紅似簇，避人沙鳥起成團。", "放懷自古酒爲得，老筆到今詩最難。", "君解高吟我方飲，幾人能共此清歡。"]'),
('53a1f5c7-ef76-4ce1-868d-2cc4b0b352de','送清溪鄭中舍官滿還京','張伯玉','宋','宋诗','song-poetry','','[]','鄭宰金閨彥，年來解紱歸。',48,'全唐诗/poet.song.22000.json','["鄭宰金閨彥，年來解紱歸。", "囊裝輕劍在，場屋故人稀。", "水館酒初罷，霜江颿欲飛。", "無煩重回首，行矣近天暉。"]'),
('85d16435-7d55-4d87-a0f7-827ffa6238fd','桐廬官滿先寄杭州資政待郎','張伯玉','宋','宋诗','song-poetry','','[]','海角千家郡，天南一水涯。',96,'全唐诗/poet.song.22000.json','["海角千家郡，天南一水涯。", "倦游慙梗泛，多滯喜瓜時。", "弱羽誠難振，危根只自持。", "几門嘗際遇，百步亦參差。", "萬壑噴霆霧，千峯出險巇。", "牢愁客星見，孤節澗松知。", "賀厦甯無託，披雲幸有期。", "魯堂金石地，商欲再言詩。"]'),
('6cce6443-b135-4506-bcf5-0071b17b62a2','和王治臣新定即事','張伯玉','宋','宋诗','song-poetry','','[]','碧泉千脈瀉金溝，名是東南俗阜州。',64,'全唐诗/poet.song.22000.json','["碧泉千脈瀉金溝，名是東南俗阜州。", "任昉舊詩題縣石，賀齊高疊照江流。", "月明幾處游歸客，春色何人醉倚樓。", "我是江潭釣魚者，喜君相見且相留。"]'),
('d9b6bcd0-02fe-4ae1-9ba7-decd9dc19c0d','王治臣以余在告寵示嘉什','張伯玉','宋','宋诗','song-poetry','','[]','新安泉石最爲佳，多病何勞養歲華。',64,'全唐诗/poet.song.22000.json','["新安泉石最爲佳，多病何勞養歲華。", "藥好幸依桐圃近，山安惟畏酒壚賒。", "狂思逸客浮滄海，渴想仙人飲絳霞。", "欲傍重陽搘策起，菊房新小玉生芽。"]'),
('c23c4ad1-7b2d-44c1-9d05-a812957e2773','次韻王治臣九日使君席上二章  其一','張伯玉','宋','宋诗','song-poetry','','[]','楚楓丹外客颿稀，水拍長天鴈字垂。',64,'全唐诗/poet.song.22000.json','["楚楓丹外客颿稀，水拍長天鴈字垂。", "樂事喜逢千日酒，憑高正在九秋時。", "吳歈調笑歌楊葉，蠻鼓鑑閎引柘枝。", "使騎相逢且留飲，行看卓馬轡如絲。"]'),
('43bdbb2c-8dee-487d-a46b-678559a7f943','次韻王治臣九日使君席上二章  其二','張伯玉','宋','宋诗','song-poetry','','[]','新安江碧郡樓危，九日登臨醉袖垂。',64,'全唐诗/poet.song.22000.json','["新安江碧郡樓危，九日登臨醉袖垂。", "莫笑松筠歲寒地，却勝桃李豔陽時。", "清渟酒瑩紅螺面，窈窕笙攢碧玉枝。", "未必尊前歎遲暮，幾人如我始牽絲。"]'),
('3169fa7f-ff46-47db-9727-12d4d584f8bc','答延平王八使君望江亭見懷之什','張伯玉','宋','宋诗','song-poetry','','[]','望江亭上望桐江，煙水茫然隔鎖窗。',64,'全唐诗/poet.song.22000.json','["望江亭上望桐江，煙水茫然隔鎖窗。", "擢第蚤同丹桂樹，從軍俱在碧油幢。", "天遥皓月人千里，書託紅鱗錦一雙。", "開府時多家令瘦，酒旗猶恐未相降。"]'),
('c04d8df8-3591-4891-833d-e1ec50cc735b','釣臺','張伯玉','宋','宋诗','song-poetry','','[]','盡逐鯨鯢埽八區，故人惟我更無餘。',64,'全唐诗/poet.song.22000.json','["盡逐鯨鯢埽八區，故人惟我更無餘。", "雲臺功將任圖畫，天上客星閒卷舒。", "若把殺人來逐鹿，爭似全身歸釣魚。", "先生有意羲皇外，不爲林泉傲帝居。"]'),
('52c34e41-2987-4865-97cd-370d7a2881d5','罷新定至錢塘喜見孫觀書記','張伯玉','宋','宋诗','song-poetry','','[]','桐江撝袂蚤三年，把臂重來講舊篇。',64,'全唐诗/poet.song.22000.json','["桐江撝袂蚤三年，把臂重來講舊篇。", "陌上風塵成底事，鬢邊霜雪但悠然。", "虬蟠我亦思滄海，鶚薦初方上碧天。", "忍把離杯又拋擲，別愁紛泊滿春煙。"]'),
('80b9b6fd-02b1-459f-9b05-22510f37a593','至和中得倅新定今領福唐再經此郡感舊書懷因呈使君劉孝叔','張伯玉','宋','宋诗','song-poetry','','[]','十年前倅北州來，平日風情尚壯哉。',64,'全唐诗/poet.song.22000.json','["十年前倅北州來，平日風情尚壯哉。", "玉水聲中寒濯筆，石楠鄉裏夜銜杯。", "可憐白首成何事，猶得紅旌向北回。", "太守故人應笑我，踐言堪媿子陵臺。"]'),
('290e14e1-884b-4b93-9172-eb2ccab40fe9','飯芝川村舍','張伯玉','宋','宋诗','song-poetry','','[]','嫩苗苒苒頭角秀，柔桑褭褭陰影輕。',32,'全唐诗/poet.song.22000.json','["嫩苗苒苒頭角秀，柔桑褭褭陰影輕。", "茆簷飯起上馬去，一聲雨後黄鸝鳴。"]'),
('d4dc4874-1944-4c41-9254-b21a01c09c4c','宿普光寺','張伯玉','宋','宋诗','song-poetry','','[]','無端未得歸林下，又向南方擁使麾。',32,'全唐诗/poet.song.22000.json','["無端未得歸林下，又向南方擁使麾。", "夜宿禪關更蕭灑，一軒寒月照清池。"]'),
('e06641f6-ed32-4235-b696-8beedef55b31','宿桐廬縣江口','張伯玉','宋','宋诗','song-poetry','','[]','桐廬江水碧，百丈見游魚。',48,'全唐诗/poet.song.22000.json','["桐廬江水碧，百丈見游魚。", "元是新安水，流從下瀨初。", "清風寒到底，明月靜涵虛。", "塵土誰難濯，人心自不知。"]'),
('52737704-678b-4123-b307-9dac35018bc0','桐廬寺曉鐘','張伯玉','宋','宋诗','song-poetry','','[]','扁舟下桐圃，霜月滿寒潭。',48,'全唐诗/poet.song.22000.json','["扁舟下桐圃，霜月滿寒潭。", "疏鐘一聲起，清與天地參。", "春容逗萬壑，窈窕出層嵐。", "覊魂不成寐，洗耳滌塵貪。"]'),
('b81f9680-14e2-44ab-b565-8d859cc12158','桐江口見雪','張伯玉','宋','宋诗','song-poetry','','[]','無諸地無霜，從古困炎熱。',48,'全唐诗/poet.song.22000.json','["無諸地無霜，從古困炎熱。", "曉出桐江口，喜見羣峯雪。", "酌酒高颿下，歸思滿寥泬。", "從今不繫舟，泛泛老清澈。"]'),
('3132cde9-899f-4ea3-95e0-78cc91643daf','出七里瀧口望桐廬縣','張伯玉','宋','宋诗','song-poetry','','[]','瀧口波自平，滄洲分兩溪。',60,'全唐诗/poet.song.22000.json','["瀧口波自平，滄洲分兩溪。", "辛勤下百粵，乍出天一涯。", "近入桐廬市，潮水濫中泜。", "不聞湍瀨聲，沙鳥浩然飛。", "然我兩俱適，吾亦浩然歸。"]'),
('59c34145-1aca-4bb3-8d7c-289b6964eba0','龍門巖','張伯玉','宋','宋诗','song-poetry','','[]','未到子陵臺，先見龍門石。',60,'全唐诗/poet.song.22000.json','["未到子陵臺，先見龍門石。", "萬物鎮羣峯，闖然聳雙壁。", "清泉界中道，亢若高門闢。", "樵童走深徑，漁戶掩沈碧。", "白首釣魚郎，不知有行客。"]'),
('855bfcea-4032-44ae-afbf-7cc94f5cbff3','至睦州泊新安江口','張伯玉','宋','宋诗','song-poetry','','[]','前歲過此州，手持七閩節。',120,'全唐诗/poet.song.22000.json','["前歲過此州，手持七閩節。", "雖遠更憚勞，攬轡遲明發。", "回瞻七里灘，何日榜舟歇。", "幸得滿三年，解符下甌粵。", "却到新安江，依然舊澄澈。", "斂巾照江水，無白可添髮。", "州人多故吏，羅立皆磬折。", "問我此去心，復有何施設。", "興言顧諸老，謝爾相慰說。", "此度歸來心，可共嚴陵說。"]'),
('4b3c4e8f-202b-430a-9dd5-caf4498233c0','港口渡','張伯玉','宋','宋诗','song-poetry','','[]','三月悲風瑟瑟寒，小船舟檝渡溪難。',32,'全唐诗/poet.song.22000.json','["三月悲風瑟瑟寒，小船舟檝渡溪難。", "日高待得過岸去，回首修篁千萬竿。"]'),
('e2cfb05c-57d4-4545-a2b1-44008842aac3','送睦州丁郎中','張伯玉','宋','宋诗','song-poetry','','[]','雨後桐江木葉稀，坐棠無事枕閒欹。',64,'全唐诗/poet.song.22000.json','["雨後桐江木葉稀，坐棠無事枕閒欹。", "扁舟幾認嚴君釣，古壁多逢沈令詩。", "夜靜好當輪省宿，曉寒堪憶趁朝時。", "山城寂寞郎官貴，想對秋風動所思。"]'),
('35374e4b-f80c-4b96-a684-182e50484423','寄睦州朱少卿','張伯玉','宋','宋诗','song-poetry','','[]','何幸鄉枌託使麾，憶曾淮澨見風儀。',64,'全唐诗/poet.song.22000.json','["何幸鄉枌託使麾，憶曾淮澨見風儀。", "泉分龍岫成新釀，廟鎖瓊蕤換舊枝。", "二水清涵潭月夜，千峯晴捲雪雲時。", "向來蕭灑稱名郡，少緩龔黄次補期。"]'),
('a87996c6-a9fd-4a75-a95c-2e67c52966d6','經大洋吳氏別業','張伯玉','宋','宋诗','song-poetry','','[]','漸老故人少，與君茲晤言。',48,'全唐诗/poet.song.22000.json','["漸老故人少，與君茲晤言。", "方山共鄰里，好畤舊田園。", "溪色寒生枕，松陰翠入軒。", "猶憐巾子在，相對舉清尊。"]'),
('a61c783b-ed7e-42f4-b767-042c992cdd5b','新定望湖樓','張伯玉','宋','宋诗','song-poetry','','[]','龍盤山影倒寒流，十里屏風翠入樓。',64,'全唐诗/poet.song.22000.json','["龍盤山影倒寒流，十里屏風翠入樓。", "畫筆肯歸涵碧手，湖光疑對湧金秋。", "主翁愛客排三雅，漁父忘機任直鈎。", "爲訪紅雲遶花島，滿船歌舞按梁州。"]'),
('feebad31-7f5c-4eb4-99f8-e68bfdf4c5ab','同孝叔游蕭灑亭','張伯玉','宋','宋诗','song-poetry','','[]','昔日賢侯多興詠，爲憐蕭灑復潺湲。',64,'全唐诗/poet.song.22000.json','["昔日賢侯多興詠，爲憐蕭灑復潺湲。", "一橋飛處橫牛渚，二水清來見浙源。", "雨漲瀑泉添嶽面，晚晴春草带潮痕。", "好風新月相留意，只恐張綱擁使軒。"]'),
('d5d1e9ac-eaac-4595-8895-1ee042ba21d9','題思范軒二首  其一','張伯玉','宋','宋诗','song-poetry','','[]','英衮多年去竹軒，更思風節記山樊。',64,'全唐诗/poet.song.22000.json','["英衮多年去竹軒，更思風節記山樊。", "抗言后坐遺忠美，通使河源舊策存。", "詩石欲留千古永，棠陰還對一樓繁。", "使君才望須相繼，莫厭林間駐畫轓。"]'),
('d372422c-ccd7-4a86-bfc6-bd4820a47258','題思范軒二首  其二','張伯玉','宋','宋诗','song-poetry','','[]','天下儒宗不世勳，履聲今絕豈重聞。',64,'全唐诗/poet.song.22000.json','["天下儒宗不世勳，履聲今絕豈重聞。", "空餘逸韻傳流水，猶喜清風在此君。", "山倚孔祠分積翠，篆尋嚴瀨掛香雲。", "接花酬倡將三記，時拂塵篇見舊文。"]'),
('e4b7972a-4807-4a4b-9b1b-80f6e63bed24','題玉泉','張伯玉','宋','宋诗','song-poetry','','[]','靈源曾記古篇章，飛入霜筠萬丈長。',64,'全唐诗/poet.song.22000.json','["靈源曾記古篇章，飛入霜筠萬丈長。", "六月林風吹寶瑟，九秋山翠坼銀潢。", "試茶石鼎雲含液，釀酒兵厨菊有香。", "到此欲知真玉性，不爲圓折本來方。"]'),
('4170babd-618e-41f7-b6c3-9177f33c8ccb','同孝叔游玉泉','張伯玉','宋','宋诗','song-poetry','','[]','石磴松陰一化城，泉源疑透古瑶京。',64,'全唐诗/poet.song.22000.json','["石磴松陰一化城，泉源疑透古瑶京。", "僧知到耳此根靜，客來洗心諸慮清。", "星記祥光重璧合，藍田霽色暮煙生。", "潺湲似識君將去，相送出山多別情。"]'),
('74fc4bfc-9ce5-4966-9a3b-45262b165176','初夏同孝叔游普光寺','張伯玉','宋','宋诗','song-poetry','','[]','魚跳蓮葉青錢小，雪壓花枝玉燕參。',64,'全唐诗/poet.song.22000.json','["魚跳蓮葉青錢小，雪壓花枝玉燕參。", "細草使轓瞻鹿擾，微風池果落鶑含。", "滿甌春茗浮仙露，一點尖峯滴翠嵐。", "却逐歸舟更多景，晚來雌霓挂寒潭。"]'),
('3335c782-501d-4d2b-9f52-30b0cfbd7c7f','初夏同孝叔游朱氏園','張伯玉','宋','宋诗','song-poetry','','[]','凍醪盧橘助登臨，此地相逢舊有音。',64,'全唐诗/poet.song.22000.json','["凍醪盧橘助登臨，此地相逢舊有音。", "石潤自知梅信蚤，池方應爲玉流深。", "詩成千色排清砌，話久花枝轉夕陰。", "不見避疆妨底事，月樓歸去正龍吟。"]'),
('295f5542-ee45-4c1b-9558-cec9d9fae20a','留題千峯榭呈孝叔','張伯玉','宋','宋诗','song-poetry','','[]','君把元英詩集披，羣山依舊遶軒墀。',64,'全唐诗/poet.song.22000.json','["君把元英詩集披，羣山依舊遶軒墀。", "杜陵幾醉花前地，謝客曾吟日落時。", "雨過荷香兼酒美，雲深泉韻透簾遲。", "佳名大約稱千數，百萬嵐盤一一奇。"]'),
('68748f94-0e34-4d94-99dc-87fdffea475d','題新定郡齋寄孝叔二首','張伯玉','宋','宋诗','song-poetry','','[]','主人今向日邊歸，猶有清香滿謝池。',32,'全唐诗/poet.song.22000.json','["主人今向日邊歸，猶有清香滿謝池。", "爲囑西風莫摇落，不禁顦顇夕陽時。"]'),
('c28798cd-12a0-4062-bbe5-552547837d09','古後池荷','張伯玉','宋','宋诗','song-poetry','','[]','花意知君改外臺，亂紅飛盡見蒼苔。',32,'全唐诗/poet.song.22000.json','["花意知君改外臺，亂紅飛盡見蒼苔。", "縱教顔色明年在，前度劉郎肯再來。"]'),
('e2200108-5187-40ec-8246-b26234f6af98','留題玉泉山堂','張伯玉','宋','宋诗','song-poetry','','[]','動非緣境靜非禪，物物前塵現四天。',64,'全唐诗/poet.song.22000.json','["動非緣境靜非禪，物物前塵現四天。", "此地筌蹄求妙論，有時瓔絡獻諸仙。", "欲梅泉石多秋思，過夏松篁聒晝眠。", "一箇攢眉招不至，勞師香火漏沈蓮。"]'),
('15ac00a3-0a40-4f05-8602-50dd968e05d0','題新定紅渠閣','張伯玉','宋','宋诗','song-poetry','','[]','煙卷龍綃豔格殊，彩霞翻處好風俱。',64,'全唐诗/poet.song.22000.json','["煙卷龍綃豔格殊，彩霞翻處好風俱。", "幾杯仙露含秋色，一曲蟾宮在畫圖。", "雨送清香浮酒面，泉飛幽韻透城隅。", "州民多有東南美，盡應嘉招入幕無。"]'),
('e0fd415d-6026-4541-b930-f796a27bedd8','州宅','張伯玉','宋','宋诗','song-poetry','','[]','萬疊湖山煙水濱，朱門畫戟閒松筠。',64,'全唐诗/poet.song.22000.json','["萬疊湖山煙水濱，朱門畫戟閒松筠。", "登臨不踏紅塵路，燕寢長居紫府春。", "畫靜欲驂風外駕，夜寒疑是月中身。", "我慚白首方懷紱，猶得蓬萊作主人。"]'),
('69fe0f24-c7d4-472a-84b6-202b56a1c474','贈范吏部','張伯玉','宋','宋诗','song-poetry','','[]','海天東下越王州，碧城繚繞環山丘。',64,'全唐诗/poet.song.22000.json','["海天東下越王州，碧城繚繞環山丘。", "春晴紫翠堆綺屋，日暮煙雨藏朱樓。", "禹祠花底金穴峻，賀老門前銀漢秋。", "何當獨把釣竿手，笑擁一艘東去遊。"]'),
('8c5da222-a95c-4e00-8e58-24d64fe75678','答王越州蓬萊閣','張伯玉','宋','宋诗','song-poetry','','[]','書報蓬萊高閣成，越山增翠越波明。',64,'全唐诗/poet.song.22000.json','["書報蓬萊高閣成，越山增翠越波明。", "雲收海上天地靜，人在月中金翠橫。", "游女弄芳珠作珮，仙人度曲玉爲笙。", "會須長揖浮丘伯，醉聽銀河秋浪聲。"]'),
('46a317cc-494c-4cf2-8320-1fbe5cac6d3b','蓬萊閣醉歸','張伯玉','宋','宋诗','song-poetry','','[]','蓬萊閣上醉歸時，猶索芳樽步步隨。',64,'全唐诗/poet.song.22000.json','["蓬萊閣上醉歸時，猶索芳樽步步隨。", "啼鳥似來留翠佩，旁人笑爲整花枝。", "腰閒半嚲黄金印，頭上斜欹白接䍦。", "拍手向他賓從道，使君未老莫扶持。"]'),
('d269c43b-cc0c-4702-abcf-3bd3fc8e6aac','西樓晚望','張伯玉','宋','宋诗','song-poetry','','[]','疊岫斂餘霞，輕舠簇遠沙。',48,'全唐诗/poet.song.22000.json','["疊岫斂餘霞，輕舠簇遠沙。", "斜陽媚城郭，細柳雜汀花。", "兩兩聯歸騎，蕭蕭起暮鴉。", "誰知故園興，閑在使君家。"]'),
('7d445121-d4c7-4b0f-8178-d872d05e700a','逍遥堂寓興','張伯玉','宋','宋诗','song-poetry','','[]','疎竹閒花陰，了無塵土侵。',48,'全唐诗/poet.song.22000.json','["疎竹閒花陰，了無塵土侵。", "旌麾千騎長，風月一堂深。", "海氣生吟榻，煙香披醉襟。", "山翁方自得，莫問去留心。"]'),
('939f06c9-55d0-4dd3-9cb7-401e98a34447','小樓獨酌','張伯玉','宋','宋诗','song-poetry','','[]','老去春來事事慵，春陰獨酌小樓中。',64,'全唐诗/poet.song.22000.json','["老去春來事事慵，春陰獨酌小樓中。", "一千里色江南岸，二十四般花信風。", "祗有谿山迎醉目，更無塵土倦樊籠。", "鷦鷯自得誠堪笑，詩有餘狂酒有功。"]'),
('06bca45a-1daa-46cb-9eaf-7950395e12f8','清思堂晝坐','張伯玉','宋','宋诗','song-poetry','','[]','堂上蕭然晝戶開，澹松疎竹蔭蒼苔。',64,'全唐诗/poet.song.22000.json','["堂上蕭然晝戶開，澹松疎竹蔭蒼苔。", "白雲無事不肯出，幽鳥有時還自來。", "何處覆車迷徑路，幾人緩頰走塵埃。", "支離得意誰知我，自對庭花引一杯。"]'),
('5215c096-030c-4e15-9779-3c3b0f0f9def','西樓早望','張伯玉','宋','宋诗','song-poetry','','[]','纖纖初日射西樓，樓上簾旌卷繡鉤。',64,'全唐诗/poet.song.22000.json','["纖纖初日射西樓，樓上簾旌卷繡鉤。", "數襞斷雲秦望曉，一聲寒雁鑑湖秋。", "煙波憔悴西施國，風月飄零范蠡舟。", "莫向登臨動懷古，有情多爲等閑愁。"]'),
('3788c9a2-98a4-40f6-a87c-81d1b13bf43c','蓬萊閣閒望寫懷','張伯玉','宋','宋诗','song-poetry','','[]','越絕開華國，姚虞啟後昆。',288,'全唐诗/poet.song.22000.json','["越絕開華國，姚虞啟後昆。", "昔聞句允霸，今作帝王藩。", "地得東南重，山侔岳瀆尊。", "平湖來萬壑，翠袖列千門。", "市井魚鹽合，居人組繡繁。", "牙旗開物表，州宅倚雲根。", "六郡趨麟節，三峰出雉垣。", "秦游前事廢，禹畫舊書存。", "雁鶩來還去，鯨波吐復吞。", "菱歌秋溆遠，江信暮潮渾。", "石古寒松偃，樓危晝靄昏。", "冷光濃可截，秀色淨無痕。", "露嫋還堤柳，風飛列寺旛。", "深林藏杞梓，芳徑雜蘭蓀。", "巧笑花爭艷，嬉遊玉鬭溫。", "畫船鵰鷁迅，絳袖綺霞翻。", "有意皆行樂，無憂可蒔萱。", "鄉惟知俎豆，土亦賁丘樊。", "巨舶聯艘至，交衢百貸蕃。", "敲冰呈巧手，織素競交鴛。", "麗圃紅柑亞，通畦紫芋蹲。", "茶先春入焙，筍带雪黏盆。", "異萼隨時坼，清香觸處歕。", "吳趨慙種蠡，楚些陋湘沅。"]'),
('5db98c34-2128-4be9-bc6c-49f09046b4cb','春日登望海亭','張伯玉','宋','宋诗','song-poetry','','[]','望海亭前春色深，風光澹澹海沈沈。',64,'全唐诗/poet.song.22000.json','["望海亭前春色深，風光澹澹海沈沈。", "潮如世路來還去，山带城蕪古到今。", "坐見微雲生別岸，吟驚幽鳥起層陰。", "勸君莫苦憑高望，驚動子牟千里心。"]'),
('958afd0e-ee0c-4b18-87f2-ebd300a66fbf','再題州宅','張伯玉','宋','宋诗','song-poetry','','[]','昔覽微之州宅篇，待將屏障寫山川。',64,'全唐诗/poet.song.22000.json','["昔覽微之州宅篇，待將屏障寫山川。", "更看白傅明月句，欲上高樓跨紫煙。", "盤紆星斗旁六郡，零落風騷三百年。", "喬木自存人自遠，可憐香案舊神仙。"]'),
('acfba930-d210-4771-b306-762b0901c21e','清思堂曉雪初霽望飛來山','張伯玉','宋','宋诗','song-poetry','','[]','密雪曉初霽，朝陽靄融融。',96,'全唐诗/poet.song.22000.json','["密雪曉初霽，朝陽靄融融。", "隠几高堂上，坐對飛來峰。", "梵塔倚天半，樓臺出煙中。", "岧然金銀闕，瑰碧交玲瓏。", "漸轉皎日高，杳杳聞疎鐘。", "天和發秀彩，灝氣如騰虹。", "況予世慮疎，久矣渟心胸。", "更臨物外趣，愈覺萬緣空。"]'),
('1caf407e-2296-4b2c-a2c5-2eb08d75f1e1','西園醉歸','張伯玉','宋','宋诗','song-poetry','','[]','向晚西園飲乍闌，山公酩酊上輕鞍。',64,'全唐诗/poet.song.22000.json','["向晚西園飲乍闌，山公酩酊上輕鞍。", "東方千騎隨車出，南國佳人夾路看。", "縱目漸迷山色遠，迴頭猶憶水聲寒。", "歸來未放賓游散，更賦新題刻燭觀。"]'),
('575f9e08-49f4-426d-b4a1-1b00d88885f6','鑑湖晚歸','張伯玉','宋','宋诗','song-poetry','','[]','會稽太守無事時，緩带長作漁樵嬉。',128,'全唐诗/poet.song.22000.json','["會稽太守無事時，緩带長作漁樵嬉。", "大航平榻引賓從，談笑晚從湖上歸。", "湖邊居人望簇簇，湖岸花木情依依。", "環峰晻靄天四垂，淥水蕩漾雙紅旗。", "城頭疊角已平西，船上樽酒含餘輝。", "冷風徐引江鵠飛，白雲迴首清猿啼。", "漁謳菱棹煙火微，使人却厭千騎隨。", "歸來樓閣上燈後，時覺天風清滿衣。"]'),
('8f0eff79-7497-46b9-b968-f698888ff53f','會稽山','張伯玉','宋','宋诗','song-poetry','','[]','稽山何崔嵬，奠此東南區。',108,'全唐诗/poet.song.22000.json','["稽山何崔嵬，奠此東南區。", "羣山狀趨附，萬壑流縈紆。", "疇昔大禹來，簡計天下書。", "諸侯率麏至，萬玉爭鳬趨。", "防風獨强梁，後至行趦趄。", "天威不可捨，敗骨盈高車。", "至今憔悴煙，慘澹藏封隅。", "遂令百世後，尊王無異圖。", "乃知聖人心，賞罰盡貽謨。"]'),
('ee09149f-6dfc-41c3-99bd-0b9c9300ccf1','五雲谿醉歸','張伯玉','宋','宋诗','song-poetry','','[]','每日谿頭醉臉紅，歸來庭院夕陽中。',32,'全唐诗/poet.song.22000.json','["每日谿頭醉臉紅，歸來庭院夕陽中。", "依稀聽得家人語，扶起五雲谿上翁。"]'),
('980d7be3-88d5-4c47-aa9e-766b3ebec641','書應天寺壁','張伯玉','宋','宋诗','song-poetry','','[]','城郭鏁山林，自無塵土侵。',48,'全唐诗/poet.song.22000.json','["城郭鏁山林，自無塵土侵。", "一峰來海上，高塔起天心。", "世路有盈縮，靈泉無淺深。", "使君今老矣，閒處得閒吟。"]'),
('693967d9-531a-4b94-8957-0d3aad529bbb','題禹廟','張伯玉','宋','宋诗','song-poetry','','[]','寶穴千峰下，嚴祠一水傍。',48,'全唐诗/poet.song.22000.json','["寶穴千峰下，嚴祠一水傍。", "夜聲滄海近，秋勢越山長。", "薄葬超前古，貽謀啟後王。", "萬靈何以報，終古詠懷襄。"]'),
('b133b6b5-9889-404e-a66a-10f586d31597','訪禹穴至陽明洞','張伯玉','宋','宋诗','song-poetry','','[]','宛委山前艤畫船，攀蘿漸入太霄邊。',64,'全唐诗/poet.song.22000.json','["宛委山前艤畫船，攀蘿漸入太霄邊。", "因尋大禹藏書穴，深入陽明古洞天。", "萬壑秋光含細籟，數峰寒玉立蒼煙。", "寶函金篆久稀闊，欲就皇人講數篇。"]'),
('59aa36fb-853c-440d-90a0-d417fb56905f','早謁禹廟','張伯玉','宋','宋诗','song-poetry','','[]','曉出五雲扃，皎日麗初宿霧歛嚴祠款靈祕。',28,'全唐诗/poet.song.22000.json','["曉出五雲扃，皎日麗初宿霧歛嚴祠款靈祕。", "拂衽天風散，不聽。"]'),
('44b64afc-aea5-4373-a90d-492e3ae4ec8f','九日蕺山戒珠寺戲呈僚友','張伯玉','宋','宋诗','song-poetry','','[]','秦望山前曉雁斜，蕺山雲外看黄花。',64,'全唐诗/poet.song.22000.json','["秦望山前曉雁斜，蕺山雲外看黄花。", "誰能蔕芥關心緒，且插茱萸伴物華。", "歲計簿書寧有盡，日生公事了無涯。", "樽前況有兵厨酒，不待兵厨酒亦賒。"]'),
('b368ac10-502c-4fd4-8019-3ffc46de6888','書大禹寺壁','張伯玉','宋','宋诗','song-poetry','','[]','蕭寺禹祠傍，人閒白日長。',48,'全唐诗/poet.song.22000.json','["蕭寺禹祠傍，人閒白日長。", "諷經聞海穴，洗鉢動湖光。", "臺殿留風月，煙雲起棟梁。", "遊人晚囘首，松竹自蒼蒼。"]'),
('abd98d6b-6e87-4b82-b105-ae76e2500c0d','遊大禹寺迴馬上口占','張伯玉','宋','宋诗','song-poetry','','[]','永日躋雲峰，向晚下秋讞。',120,'全唐诗/poet.song.22000.json','["永日躋雲峰，向晚下秋讞。", "却望碧城中，樓臺翠煙滿。", "前旌擁歸騎，緩轡徐馭隠。", "曠望寫予心，平波海天遠。", "顧予疇昔志，本以鋤犁挽。", "敢望麋鹿資，遘此雲龍旦。", "金門容竊步，玉殿叨靈睠。", "復此千騎來，日逐紛華戰。", "平生知退意，長畏歲月晚。", "行當引初服，還把芰荷翦。"]'),
('3ea55379-2338-48a1-99f6-14cf25394341','寄毛都官','張伯玉','宋','宋诗','song-poetry','','[]','寄問副車毛國鎮，別來風味久如何。',64,'全唐诗/poet.song.22000.json','["寄問副車毛國鎮，別來風味久如何。", "蓬萊閣上誰同飲，宛委山前幾番歌。", "應向蘭亭摛彩筆，曾教西子畫清蛾。", "若還問我今何似，比著前春醉更多。"]'),
('ee92813d-34b3-4188-93b8-4d5f859abc51','送花趙提刑','張伯玉','宋','宋诗','song-poetry','','[]','蓬萊閣上牡丹開，盡日凭欄望外臺。',32,'全唐诗/poet.song.22000.json','["蓬萊閣上牡丹開，盡日凭欄望外臺。", "不敢登門謁樽酒，且教山僕送花來。"]'),
('87696b1f-1c96-4b8d-8b0c-e052937c9984','寄會稽刁景純學士','張伯玉','宋','宋诗','song-poetry','','[]','雨後稽山紫翠毫，使君千騎壓雲鼇。',64,'全唐诗/poet.song.22000.json','["雨後稽山紫翠毫，使君千騎壓雲鼇。", "樓臺日暖花木麗，河漢夜凉絲竹高。", "瀛館久淹騏驥足，越人今識鳳凰毛。", "江南老守思離闊，夢想時過白鷺濤。"]'),
('a3544093-6d47-45b8-b882-be91bfba8674','和國鎮晚秋齋中見寄','張伯玉','宋','宋诗','song-poetry','','[]','越國風光與衆殊，貳車才調世應無。',64,'全唐诗/poet.song.22000.json','["越國風光與衆殊，貳車才調世應無。", "晴樓對酌雲平海，夜榻分題月滿湖。", "吟嘯江山君好手，主張詩酒我非夫。", "行當乞挂朱輪去，別作香山九老圖。"]'),
('9157ee37-99a9-494a-9cdb-ad9beae84be4','得越','張伯玉','宋','宋诗','song-poetry','','[]','尺一除書與會稽，陋儒何以報天輝。',64,'全唐诗/poet.song.22000.json','["尺一除書與會稽，陋儒何以報天輝。", "豈惟大幕張紅旆，更得全家住翠微。", "千騎晚隨龍節去，一帆春送鷁舟飛。", "支離莫道攘空臂，乞得越州金印歸。"]'),
('f164838a-49c2-4cf0-b658-b938b8b54854','清明日','張伯玉','宋','宋诗','song-poetry','','[]','每年每遇清明節，把酒尋花特地忙。',32,'全唐诗/poet.song.22000.json','["每年每遇清明節，把酒尋花特地忙。", "今日江城衰病起，佛前新火一鑢香。"]'),
('3b565c0e-1c58-4e3e-a6f0-e7f4bdebe5ba','正旦呈諸僚友','張伯玉','宋','宋诗','song-poetry','','[]','拂霧酴酥酒滿巡，越山如鬣水如鱗。',64,'全唐诗/poet.song.22000.json','["拂霧酴酥酒滿巡，越山如鬣水如鱗。", "日邊雖望龍庭遠，海上初傳鳳曆新。", "好景融融來破雪，和風細細欲黏人。", "莫言老守無心計，排比賓僚醉過春。"]'),
('cab8eb4c-15ae-47dc-8f18-ea4849b11d32','臘日喜雪','張伯玉','宋','宋诗','song-poetry','','[]','臘雪常聞百厲銷，今年臘日雪飄飄。',32,'全唐诗/poet.song.22000.json','["臘雪常聞百厲銷，今年臘日雪飄飄。", "山公預喜明年熟，擘畫開春買酒瓢。"]'),
('ef6f8d46-0efc-4905-b95c-5b97fb7cc75c','明月泉','張伯玉','宋','宋诗','song-poetry','','[]','至今千丈松，猶伴數巖雪。',24,'全唐诗/poet.song.22000.json','["至今千丈松，猶伴數巖雪。", "不見纖塵飛，寒泉皓明月。"]'),
('ee7693c3-9410-4ba1-adf7-411db703f759','贈陳虞卿','張伯玉','宋','宋诗','song-poetry','','[]','東吳王孫歸挂冠，玉絲紅鱠滿雕盤。',64,'全唐诗/poet.song.22000.json','["東吳王孫歸挂冠，玉絲紅鱠滿雕盤。", "狂吟但覺日月久，醉舞不知天地寬。", "小圃移花山客瘦，夜窗擣藥橘童寒。", "新書近日成多少，且告先生旋借看。"]'),
('83796ca3-1b60-4d86-8f03-c06c4e4699a2','虎丘','張伯玉','宋','宋诗','song-poetry','','[]','東客從來過虎丘，橘花渡口維扁舟。',96,'全唐诗/poet.song.22000.json','["東客從來過虎丘，橘花渡口維扁舟。", "闔閭宮殿不可見，但對古塔寒颼飀。", "憶昔夫差全勝日，水犀十萬橫吳鉤。", "楚山既掘荆人冢，越嶺仍將句踐囚。", "豈謂西施能破國，誰知麋鹿上臺遊。", "唯有吳王在時月，夜深閑照劍池頭。"]'),
('b834227a-c48f-4b68-93fb-2f87359df01f','滬瀆','張伯玉','宋','宋诗','song-poetry','','[]','泛泛松江水，迢迢笠澤邊。',24,'全唐诗/poet.song.22000.json','["泛泛松江水，迢迢笠澤邊。", "萬年知禹力，灌溉有餘功。"]'),
('274022f7-3168-4ec4-acde-8e7dec3c914b','蘇小小墓','張伯玉','宋','宋诗','song-poetry','','[]','小小仙蹤去不還，空標遺塚落人間。',32,'全唐诗/poet.song.22000.json','["小小仙蹤去不還，空標遺塚落人間。", "錢塘門地家何地，回首臨平隔斷山。"]'),
('f6c89b79-ccee-4a0b-a6dd-f374f59ed1ae','題月波樓','張伯玉','宋','宋诗','song-poetry','','[]','烟波萬里浮舟國，雲木華亭鶴唳鄉。',32,'全唐诗/poet.song.22000.json','["烟波萬里浮舟國，雲木華亭鶴唳鄉。", "欲駐野王船一餉，數聲風笛肯相將。"]'),
('bef2f6d4-600b-462c-b8bd-21a83f4d8ed5','詩一首','張伯玉','宋','宋诗','song-poetry','','[]','令狐太守好權奇，畫樓新建月波暉。',64,'全唐诗/poet.song.22000.json','["令狐太守好權奇，畫樓新建月波暉。", "風光似逐水仙去，物色如從雲漢歸。", "春澹瀛洲浮海曲，濤驚渤澥起天圍。", "從今便作月波唱，醉拍姮娥金縷衣。"]'),
('6feaa887-b1d8-4b5a-8995-ec8fdc2ee6d3','王敦城','張伯玉','宋','宋诗','song-poetry','','[]','晉氏開霸圖，潛飛入堅壁。',48,'全唐诗/poet.song.22000.json','["晉氏開霸圖，潛飛入堅壁。", "夢日有餘祥，留鞭無舊跡。", "雖矜錢鳳計，終墮太真策。", "不作忠良臣，高城有何益。"]'),
('d7deb85a-333c-4805-9132-ce6b9d3952a3','齊山圖','張伯玉','宋','宋诗','song-poetry','','[]','東南真賞有齊山，路隔江湖到者難。',64,'全唐诗/poet.song.22000.json','["東南真賞有齊山，路隔江湖到者難。", "絕筆掃成千仞翠，數峯高挂一堂寒。", "林僧舊居雲泉侶，刺史今爲待從官。", "還似東陽重涵碧，丹青寫入雍州看。"]'),
('7e1d034a-10d4-4f08-8e8a-f70303709fc2','遥題錢公輔衆樂亭','張伯玉','宋','宋诗','song-poetry','','[]','句章太守錢君倚，湖上新爲衆樂亭。',64,'全唐诗/poet.song.22000.json','["句章太守錢君倚，湖上新爲衆樂亭。", "花木豈徒遊子愛，笙歌長與郡人聽。", "坐來高韻天風起，飲罷餘香夕雨零。", "安得凭闌縱吟筆，玉觴遥對數峯青。"]'),
('c50628da-41f0-4eb7-bf8b-f70625b66c82','遊叔虞祠','張伯玉','宋','宋诗','song-poetry','','[]','廟中桐葉手中文，閑讀高碑拂素塵。',64,'全唐诗/poet.song.22000.json','["廟中桐葉手中文，閑讀高碑拂素塵。", "異隴歸禾曾是主，徒林射兕獨留神。", "關河莫問周秦事，花木誰分漢魏春。", "惟有門前舊溪水，秋風幽咽送行人。"]'),
('a183a433-9f80-4078-b120-a022d6f70798','句','張伯玉','宋','宋诗','song-poetry','','[]','紅梅花下一樽酒，拋擲清香是負伊。',16,'全唐诗/poet.song.22000.json','["紅梅花下一樽酒，拋擲清香是負伊。"]'),
('baa6696b-b5ed-4bed-a728-dc1a5e0c9720','親祀南郊詩','蔡襄','宋','宋诗','song-poetry','','[]','天畀元統，赤運開祉。',240,'全唐诗/poet.song.22000.json','["天畀元統，赤運開祉。", "聖祖神宗，海域平砥。", "思皇真考，嶽封汾祀。", "餌係戎胡，包束戈矢。", "丕顯靈德，光被萬里。", "民壽而康，恩及蕭葦。", "恭惟皇帝，繼文之始。", "兢兢日慎，夙夜勤只。", "哀憐困窮，有如在己。", "惟刑是卹，弗繇怒喜。", "躬服儉約，黜棄浮侈。", "罔有逸欲，日惟三紀。", "大中則經，興亡則史。", "陰陽時序，日緯躔軌。", "樂律本原，禮法根柢。", "兵韜術數，萬微精旨。", "該通變貫，咸燭厥理。", "歲舍壬午，盜發南鄙。", "帝日汝青，治辨行李。", "毋大誅割，定患則已。", "獵獵靈旗，啟道徑指。", "兇渠踣仆，俘徒授耳。", "嶺服既平，勳賞周被。", "封歿錄孥，門戶曄暐。"]'),
('ac1dd582-d98d-4b49-829f-480c6a86f4d5','御筆賜字詩','蔡襄','宋','宋诗','song-poetry','','[]','皇華使者臨清晨，手開寶軸香煤新。',224,'全唐诗/poet.song.22000.json','["皇華使者臨清晨，手開寶軸香煤新。", "沿名與字發深旨，宸毫灑落奎鉤文。", "精神高遠照日月，勢力雄健生風雲。", "混然氣質不可寫，乃知學到非天真。", "緘藏自語價希代，誰顧四壁嗟空貧。", "臣聞帝舜優聖域，臯陶大禹爲其鄰。", "吁俞敕戒成典要，垂覆後世如穹旻。", "陛下仁明如舜禹，豪英進用司鴻鈞。", "臣襄材智最駑下，豈有志業通經綸。", "獨是丹誠抱忠樸，常欲贊奏上古珍。", "又聞孔子春秋法，片言褒貶賢愚分。", "考經內省不自稱，但思至理書諸紳。", "乾坤大施入洪化，將圖報效無緣因。", "誓心願竭謨謀義，庶裨萬一唐虞君。"]'),
('f3e0a270-aef6-4ad3-a840-555aeadb978e','四賢一不肖詩 范希文','蔡襄','宋','宋诗','song-poetry','','[]','中朝鸞鶴何儀儀，慷慨大體能者誰。',272,'全唐诗/poet.song.22000.json','["中朝鸞鶴何儀儀，慷慨大體能者誰。", "之人起家用儒業，馳騁古今無所遺。", "當年得從諫官列，天庭一露胸中奇。", "矢身受責甘如薺，沃然華實相葳蕤。", "漢文不見買生久，詔書曉落東南涯。", "歸來俯首文石陛，尹以京兆天子毘。", "名都翼翼郡國首，里區百萬多占辭。", "豪宗貴倖矜意氣，半言主者承其頤。", "昂昂孤立中不倚，傳經決訟無牽羈。", "老姦黠吏束其手，衆口和附歌且怡。", "日朝黄幄邇天問，帝前大畫當今宜。", "文陳疏舉時密啟，此語多祕世莫知。", "傳者籍籍十得一，一者已足爲良醫。", "一麾出地番君國，惜此智慮無所施。", "吾君睿明廣視聽，四招邦俊隆邦基。", "廷臣諫列復鉗口，安得長喙號丹墀。", "晝歌夕寢心如疚，咄哉汝憂非汝爲。"]'),
('ed14e2a0-c618-41fe-a366-a4904304e28e','四賢一不肖詩 余安道','蔡襄','宋','宋诗','song-poetry','','[]','南方之强君子居，卓然安道襟韻孤。',256,'全唐诗/poet.song.22000.json','["南方之强君子居，卓然安道襟韻孤。", "詞科判等屢得雋，呀然鼓焰天地罏。", "三年待詔處京邑，斗粟不足榮妻孥。", "耳聞心慮朝家事，螭頭比奏帝日都。", "校書計課當序進，麗賦集仙來顯塗。", "誥墨未乾尋已奪，不奪不爲君子儒。", "前日希文坐言事，手提敕教東南趨。", "希文鯁亮素少與，失勢誰復能相扶。", "嶄然安道生頭角，氣虹萬丈橫天衢。", "臣靖胸中有屈語，舉嗌不避蕭斧誅。", "使臣仲淹在庭列，日獻陛下之嘉謨。", "刺史榮官雖重寄，奈何一郡卷不舒。", "言非由位固當罪，隨漕扁舟盡室俱。", "炎陬此去數千里，橐中狼籍惟蠹書。", "高冠長佩叢闕下，千百其羣訶爾愚。", "吾知萬世更萬世，凜凜英風激懦夫。"]'),
('d0ff63db-540e-452f-ae67-884ceb6e6da6','四賢一不肖詩 尹師魯','蔡襄','宋','宋诗','song-poetry','','[]','君子道合久以成，小人利合久以傾。',256,'全唐诗/poet.song.22000.json','["君子道合久以成，小人利合久以傾。", "世道下衰交以利，遂使周雅稱嚶鳴。", "煌煌大都足軒冕，綽有風采爲名卿。", "高名重位蓋當世，退朝歸舍賓已盈。", "脅肩諂笑不知病，指天報遇如要盟。", "一朝勢奪德未改，萬鈞已與毫釐輕。", "畏威諛上亦隨毀，矧復鼓舌加其評。", "透迤陰拱質氣厚，兩豆塞耳心無營。", "鳴呼古人不可見，今人可見誰與明。", "章章節義尹師魯，飭躬佩道爲華榮。", "希文被罪激人怒，君獨欣慕如平生。", "抗書轂下自論劾，惟善與惡宜彙征。", "削官竄逐雖適楚，一語不挂離騷經。", "當年亦有大臣逐，朋邪隠縮無主名。", "希文果若事姦險，何此吉士同其聲。", "高譚本欲悟人主，豈獨區區交友情。"]'),
('ddd8b3e2-055c-4ded-a1d8-87b112d69d99','四賢一不肖詩 歐陽永叔','蔡襄','宋','宋诗','song-poetry','','[]','先民至論推天常，補衮扶世爲儒方。',384,'全唐诗/poet.song.22000.json','["先民至論推天常，補衮扶世爲儒方。", "圜冠博带不知本，樗櫟安可施青黄。", "帝圖日盛人世出，今吾永叔誠有望。", "處心學士貴適用，異端莫得窺其牆。", "子年五月范京兆，服天子命臨鄱陽。", "二賢拜疏贖其罪，勢若止沸反揚湯。", "敕令百執無越位，諫垣何以敢封囊。", "哀來激憤抑復奮，强食不得下喉吭。", "位卑無路自聞達，目視雲闕高蒼茫。", "裁書數幅責司諫，落筆騄驥騰康莊。", "刃迎縷析解統要，其間大意可得詳。", "書日希文有本末，學通古今氣果剛。", "始自理官來祕閣，不五六歲爲天章。", "上心倚若左右手，日備顧問鄰清光。", "苟爾希文實邪佞，曷不開口論否臧。", "陰觀被譴始醜詆，摧枯拉腐奚爲彊。", "儻日希文實賢士，因言被責庸何傷。", "漢殺王章與長倩，當時豈曰誅賢良。", "惟時諫官亦結舌，不曰可諫曰罪當。", "遂今百世覽前史，往往心憤涕泗滂。", "斯言感切固已至，讀者不得令激昂。", "豈圖反我爲怨府，袖書乞憐天之傍。", "謫官一邑固分耳，恨不剖腹呈琳琅。", "我嗟時輩識君淺，但推藻翰高文場。"]'),
('819b51dd-7efb-40db-ab20-14c949899e42','四賢一不肖詩 高若訥','蔡襄','宋','宋诗','song-poetry','','[]','人稟天地中和生，氣之正者爲誠明。',256,'全唐诗/poet.song.22000.json','["人稟天地中和生，氣之正者爲誠明。", "誠明所鍾比賢傑，從容中道無欹傾。", "嘉謀讜論范京兆，激姦糾繆揚王庭。", "積羽沈舟毀銷骨，正人無徒姦者朋。", "主知膠固未遐棄，兩轓五馬猶專城。", "歐陽祕閣官職卑，欲雪忠良無路岐。", "累幅長書快幽憤，一責司諫心無疑。", "人謂高君如撻市，出見縉紳無面皮。", "高君携書奏天子，遊言容色仍怡怡。", "反謂范文謀疎闊，投彼南方誠爲宜。", "永叔忤意竄西蜀，不免一中讒人機。", "汲黯嘗糾公孫詐，弘於上前多謝之。", "上待公孫禮益厚，當時史官猶刺譏。", "司諫不能自引咎，復將已過揚當時。", "四公稱賢爾不肖，讒言易入天難欺。", "朝家若有觀風使，此語請與風人詩。"]'),
('75f009c0-15d0-4774-b690-dea348c9edea','和王勝之遊普明院','蔡襄','宋','宋诗','song-poetry','','[]','昔賢履道第，平時洛都選。',132,'全唐诗/poet.song.22000.json','["昔賢履道第，平時洛都選。", "門外多風塵，林端出臺殿。", "名園迤邐清，小徑縈紆轉。", "脩竹環數畝，可愛清不變。", "冰生流水靜，葉盡危巢見。", "晴日破雲來，遊鱼過池面。", "君意高如鴻，孤超遺健羨。", "茲遊恐難屢，歷覽豈云倦。", "放懷窮幽趣，回首抱歸戀。", "裁詩賦景物，芬葩有餘絢。", "呼童秣予馬，追閒性所便。"]'),
('7d7b1b80-4f37-4702-99f3-db372561429c','陪諸君會史館園','蔡襄','宋','宋诗','song-poetry','','[]','名園霽宿雨，春日正和柔。',132,'全唐诗/poet.song.22000.json','["名園霽宿雨，春日正和柔。", "花香泛草際，竹影摇清流。", "鳴禽自往還，遊鱼時沈浮。", "出門市朝喧，愛此林亭幽。", "况陪君子讌，飛斝更相酬。", "亦有佳人携，豔歌青眉愁。", "佳人足娛適，遠思何夷猶。", "故鄉去千里，野堂臨溪頭。", "夢寐別四載，南望無時休。", "王粲昔從軍，登樓以銷憂。", "今予豈不然，每到終遲留。"]'),
('3e9b931a-dce5-4854-ad5c-c1d54a1a1046','過白樂天墳','蔡襄','宋','宋诗','song-poetry','','[]','樂天本才士，羽儀初頡頏。',84,'全唐诗/poet.song.22000.json','["樂天本才士，羽儀初頡頏。", "脫身避禍機，遂得林泉尚。", "生愛香山遊，死亦香山葬。", "悠悠醉吟魂，終古填幽壙。", "小堂松檜間，躋攀白雲上。", "春日照伊流，素波明演漾。", "草樹豈有情，一步一囘望。"]'),
('7d30fd46-26eb-43e6-a590-04420261ebd4','楊叔武北堂夜話','蔡襄','宋','宋诗','song-poetry','','[]','歲晏物景薄，屋陰向晚饒。',144,'全唐诗/poet.song.22000.json','["歲晏物景薄，屋陰向晚饒。", "輕雲隠微月，殘雪棲枯條。", "夫君有高適，顧我慰寂寥。", "瀟灑開北堂，拂榻延良宵。", "前几陳古書，坐見千載遥。", "間亦發新句，幽思含九韶。", "神明靜外照，念慮醉中消。", "揚雄戒丹轂，顔子安一瓢。", "良玉不火變，翠柏寧霜彫。", "此心固獨往，聲利詎得招。", "罏灰寒更劃，燈灺落仍挑。", "相看數漏板，後會誡重要。"]'),
('d0d41c79-9dd5-4ecf-a4f5-ebd505f0a3e6','送胡武平出守吳興','蔡襄','宋','宋诗','song-poetry','','[]','東南有佳士，文高志清苦。',96,'全唐诗/poet.song.22000.json','["東南有佳士，文高志清苦。", "翩然請郡章，入居使君府。", "霅水生春瀾，瑩凈沙可數。", "霽日明旌旗，長風送鐃鼓。", "煙帆十丈船，湖山一抔土。", "橘嫩宴亭秋，茶香齋閣午。", "神歡所適宜，動默造幽覩。", "應念懷鉛人，垂頭證魚魯。"]'),
('19481831-726b-4e07-b4ac-dedbf60c5c2d','永叔示及聖俞酬答因奉和寄聖俞','蔡襄','宋','宋诗','song-poetry','','[]','吾友多稱君，思見寒附火。',120,'全唐诗/poet.song.22000.json','["吾友多稱君，思見寒附火。", "氣溫玉開籍，才敏鏃加笴。", "嘗於師魯書，言詞屢及我。", "乖疎久益新，慕合迎已可。", "奈何縻組綬，無路動車輠。", "近乃得百篇，能詩今信果。", "清寒水石春，怪險蛟螭鎖。", "遠念煙鴻去，呈妍露葩娜。", "古人雖已矣，風流未應墮。", "東來勿後期，山桃綴紅顆。"]'),
('613a5a71-3745-420f-a94e-2287c8cdd45a','送安思正之蜀','蔡襄','宋','宋诗','song-poetry','','[]','賤者易屈志，少年多直情。',228,'全唐诗/poet.song.22000.json','["賤者易屈志，少年多直情。", "子獨修節行，愛護如目精。", "辛勤走銓省，歷歲纔點名。", "舍居在窮巷，門戶面西城。", "妻孥愁屢空，獨爾心無營。", "驅騾從僮僕，間或造予庭。", "是時楊叔武，相值極驩誠。", "妙言發潛稸，遠意倍幽萌。", "羞諛刺俗子，指急條邊兵。", "過從豈云厭，時節忽崢嶸。", "叔武守岳陽，別去方行行。", "子今復之蜀，蜀道天險并。", "橐中無一錢，劍外幾百程。", "春風卷地來，凡草猶奮榮。", "如何使之人，憔悴氣與形。", "內富在乎我，外窮繫於生。", "此事久已判，努力敦誠明。", "吾友黄君度，實乃浮其聲。", "子往從之遊，切磨固相成。"]'),
('abc11774-2daf-4083-9f8c-1660277c1ae9','寄襄城孫主簿','蔡襄','宋','宋诗','song-poetry','','[]','昔子尚穉孩，從親來此邑。',96,'全唐诗/poet.song.22000.json','["昔子尚穉孩，從親來此邑。", "今子稽簿書，職守仍前襲。", "歲月曾未幾，風流正相及。", "新硎刃益銛，舊署墨猶溼。", "非徒使氣奮，固使家聲立。", "征調事漸繁，須材時所急。", "何不一軒翔，榮名亦可拾。", "勖子乃自省，滿顔抱羞澀。"]'),
('9615d57e-f840-4d54-a4a0-f27586a3f68b','送任山歸河東','蔡襄','宋','宋诗','song-poetry','','[]','風俗憂思深，在昔言汾絳。',288,'全唐诗/poet.song.22000.json','["風俗憂思深，在昔言汾絳。", "之人隠其間，白首甘陋巷。", "畢力事詩書，豈特專記誦。", "編年作通記，起周迄炎宋。", "甲子二十五，迴環補遺空。", "予聞春秋法，尊土正一統。", "維持生民綱，樹立大邦棟。", "上賢若游夏，鳥獸於麟鳳。", "三傳自名家，講解或失中。", "區區休預徒，奔馳困羈控。", "排闢侵異端，寖久成蠹蟲。", "仲淹著元經，劉蕡比奴從。", "去聖日彌遠，期言誰折衷。", "猶勝兒女曹，煙雲費嘲弄。", "君於春秋學，勤勞務包綜。", "向時恥飛箝，畫策尚禽縱。", "羌戎負恩德，王師壓秦雍。", "邊圉重瘡痍，堪爲買生慟。", "廟堂誅賊謀，謂與天下共。", "詔書入巖穴，丐告嘉謀貢。", "使者出河東，輒以姓名送。", "朅來遊京邑，天門如可羾。", "岧嶢雙浮雲，下有千人䢇。", "扳緣逐聲利，激射苟祿俸。"]'),
('685fc326-07c1-43f3-848c-63ba59797391','姑胥行','蔡襄','宋','宋诗','song-poetry','','[]','香涇無故流，胥臺有餘基。',144,'全唐诗/poet.song.22000.json','["香涇無故流，胥臺有餘基。", "太伯以德啟，後王結心師。", "夫差昔好戰，戈矛臨越陲。", "天蟹須食稻，未拯吳人饑。", "于今十一貢，貧甚吳王時。", "全吳古都會，腴田溉湖陂。", "雨晹適小變，數米不足炊。", "吾知事本末，本末何由知。", "家戶徼福利，坐輸黄衣兒。", "平糴連拖漕，入朶天兵頤。", "囷窌不夕儲，勢若偷生爲。", "長慮且後顧，荀卿有良規。"]'),
('1afac4a0-fefa-4850-b93b-37511ae347d4','泊吳江寄胡武平','蔡襄','宋','宋诗','song-poetry','','[]','遥夜吳江瀕，露坐鬚成葆。',204,'全唐诗/poet.song.22000.json','["遥夜吳江瀕，露坐鬚成葆。", "天空不带雲，野逈正收潦。", "徘徊波上月，灧漾浮光好。", "清風送炎歊，翻覺秋氣早。", "乃問苕溪路，舟虞爲予道。", "水行至州下，樓臺壓煙島。", "凈居譬如仙，嘉産極富媼。", "念君鎮雅俗，適以資恬浩。", "豈不欲一往，驩誠寄鳬藻。", "縱遊窮佳賞，劇論寫幽抱。", "嗟予遠庭闈，六年見春草。", "終日諷陔蘭，無路羞羊棗。", "胡爲久去家，一慮心如擣。", "今而賜告歸，計課免讎討。", "前之奉慈顔，敢憚勤輿皁。", "北來尚何時，汀洲白蘋老。", "儻得杯酒同，爲君一醉倒。"]'),
('cc8e52c6-cfcf-4038-92ff-5a29a059b82d','遷陽道中奉寄楊正臣同年','蔡襄','宋','宋诗','song-poetry','','[]','名第同一籍，家園連七閩。',264,'全唐诗/poet.song.22000.json','["名第同一籍，家園連七閩。", "何爲別眉宇，於今十四春。", "昔子補一尉，扶病走風塵。", "歸來解組紱，宴處頤精神。", "架書括遺逸，甕酎涵清醇。", "東阡與北陌，候問通慇懃。", "或言疾良瘉，呼盧氣益振。", "或傳近詩句，平淡與古鄰。", "語之天下事，塞耳不復聞。", "寧當決引去，道固有屈伸。", "嗟予仰尺祿，對讎中祕文。", "天子誤采拔，指名填諍臣。", "力微責任重，百慮加一身。", "列章乞便郡，賜告迎慈親。", "窮冬過梨嶺，山蹊出幽榛。", "俯深下坎井，斗起攀蒼旻。", "水石齧晚沙，霜風變朝皴。", "粲粲澗中花，孤芳能自珍。", "班班雲上鳥，朝鳴亦求羣。", "歲晏時節動，天遥客愁新。", "去子無跬步，笑語絕燕秦。", "作此欲招隠，翻愧林泉人。"]'),
('5cd16b0b-0368-40dd-8c0f-3d7346030431','碧峯亭','蔡襄','宋','宋诗','song-poetry','','[]','虛亭城西隅，開檻俯臨北。',120,'全唐诗/poet.song.22000.json','["虛亭城西隅，開檻俯臨北。", "青山正相向，萬狀呈峭格。", "落日涵紫翠，深春變顔色。", "雲石抱幽致，猿鳥自娛適。", "上窮林端寺，下見海內國。", "賢侯乘閒來，四座揖佳客。", "歌吹有杯酌，筆研角文墨。", "雄談連今古，大笑一歡戚。", "嗟物亦時遇，曠久茲乃得。", "從知閩州圖，復記新名迹。"]'),
('809a01ea-bdaa-4e81-b932-932fc27732c8','憶弟','蔡襄','宋','宋诗','song-poetry','','[]','清溪曲曲抱山斜，遶溪十里薔薇花。',224,'全唐诗/poet.song.22000.json','["清溪曲曲抱山斜，遶溪十里薔薇花。", "春風吹香襲人骨，乾紅淡白相交加。", "眼睛眩晃不能視，爛如赤日凌朝霞。", "時有扁舟向中下，共疑來處從仙家。", "于時邀我臨流飲，下踞大石盤犬牙。", "平生意氣一快論，屈指世務還驚嗟。", "酒酣襞紙探强韻，胡塗醉字成亂鴉。", "侵更把火入官舍，下馬猶吟詩各誇。", "何言花落悲人世，只見溪流度歲華。", "今年初夏我復至，深叢晚艷餘孤葩。", "山川故物依然在，惟子別路幽明賒。", "想象音容杳何許，桂旗獵獵隨雲車。", "悲來獨坐蔭芳樹，涕淚揮灑霑黄沙。", "行人怪我愛溪水，那知此恨無邊涯。"]'),
('20f72deb-be8b-408e-89a1-18cced4b73d0','道中寄福州王祠部','蔡襄','宋','宋诗','song-poetry','','[]','臨津館下日銜西，風卷寒潮上碧溪。',320,'全唐诗/poet.song.22000.json','["臨津館下日銜西，風卷寒潮上碧溪。", "畫船急槳隨潮去，山川滿眼烟凄迷。", "醉起開船看潮落，林深日落哀猿啼。", "離魂復與潮東下，兀然愁坐心酸悽。", "今年賜告歸鄉里，翩翩飛鳥投故棲。", "雙親素髮喜我至，鞠撫歡笑如嬰兒。", "東阡北陌來慶問，嫗翁罍醆交持携。", "雖欲晨昏在環堵，奈何職守通金閨。", "春暮辭家就行役，幽蘭在手空萋萋。", "閩州太守意慷慨，一見歡甚無町畦。", "欲令邦人滿瞻聽，灑酒高會撾鼓鼙。", "我知君侯落落者，胸中氣象盤虹霓。", "問之當今至急務，無若羌虜方突梯。", "君言區處果得術，勢類秋隼持寒雞。", "養兵精悍不在衆，黠賊頭顱可立提。", "海隅僻郡誰與語，强欲論列懲吹齏。", "又言人生尚忠孝，二者輕重均銖圭。", "以諫名官宜盡節，健行勿縶驊騮蹄。", "別來破熱走山驛，神疲骨瘦顔容黧。", "作詩遥寄復感激，豈不戚戚論乖暌。"]'),
('4047618e-1c7c-4033-ab1e-c77e1e17668e','龜山夜泊書事','蔡襄','宋','宋诗','song-poetry','','[]','十月淮水平，瑩凈鋪寒簟。',240,'全唐诗/poet.song.22000.json','["十月淮水平，瑩凈鋪寒簟。", "浴日弄凈光，涵山碎青點。", "開帆直千里，快去曾非漸。", "盲風斗作勢，怒浪立呈險。", "枯林助呼嘷，巨蜃工騰閃。", "偎崖少休息，繫纜猶欹颭。", "忠信古云伏，奸邪神所貶。", "扣心良自安，潛祈亦羞諂。", "夜分羣籟息，天明惡雲歛。", "霜威寒更清，霽色鮮可染。", "懷安固俗喜，乘危豈予歉。", "賜告雖慶幸，被恩實慚忝。", "慈親慰衰髮，嬌兒別啼臉。", "人情足愛戀，將思輒閉掩。", "世事忽憂來，驚起類癡魘。", "金絮北餌胡，弓刀西壓陝。", "天子欲求理，羣材務搜檢。", "大明破昏醫，久弊刮痕玷。", "有如廣厦時，拙者亦磨剡。", "行路勿遲遲，流年空苒苒。"]'),
('011af0d0-d37f-4bbc-bd0d-08aee2dd2948','送楊渥赴西安主簿','蔡襄','宋','宋诗','song-poetry','','[]','余思去夏還甌閩，溫風赤日爭陶蒸。',224,'全唐诗/poet.song.22000.json','["余思去夏還甌閩，溫風赤日爭陶蒸。", "舟行夜寄浙江稜，江濤洶湧來相仍。", "雷電翕虩蛟螭騰，方牀竹簟寒生冰。", "上隴西去景色澄，青山兩向水一絙。", "猿鳥啼叫交酬應，晚樵出霧魚投罾。", "脫離滓濁躋陵兢，造託微波訊嚴陵。", "清遐可使貪者懲，山窮水盡乃攀登。", "爛柯巖岫孤崚嶒，幽邃闚矚崖險憑。", "少留觀愛喜莫勝，子官其間良足稱。", "子材又美神粹凝，萬象態度遭披凌。", "吟咏設寫踰畫繒，當有味者論淄澠。", "今予癡仕如秋蠅，飛塵滿耳汗浹膺。", "聞子大艑行可乘，骨目森竦神慮興。", "子姑去嗟予未能，送子一念魂九升。"]'),
('0fc763a1-0c09-4c72-a29e-abcfcd1233d1','贈勤師','蔡襄','宋','宋诗','song-poetry','','[]','勤爲浮屠人，形類心不偶。',144,'全唐诗/poet.song.22000.json','["勤爲浮屠人，形類心不偶。", "獨負山林棲，遠犯風塵走。", "如聞大衆居，乃是賢豪藪。", "專意學文章，韓編不離手。", "退之所尚者，豈以言深厚。", "徑馳周孔域，不爲雜說誘。", "大凡民之生，蟲豸均一醜。", "聖人酌中道，君臣與夫婦。", "飲食若衣冠，事行而易守。", "不喜釋老言，詆斥遭誣負。", "子今讀其書，無乃相紛糾。", "學本勿學末，何爲恤衆口。"]'),
('3ce89438-e183-4d81-9ca5-db744d798163','和黄介夫憶竹','蔡襄','宋','宋诗','song-poetry','','[]','君家有美竹，繞廬千百個。',240,'全唐诗/poet.song.22000.json','["君家有美竹，繞廬千百個。", "種時意慮深，別後年華過。", "顔色日益新，根本久已播。", "石間鳴溜去，烟外哀禽和。", "子特何依因，茲焉辜嘯卧。", "慈親齒髮暮，學宦非敢惰。", "風雲乖會遇，羽翼頓摧挫。", "遺經極精究，收功若計課。", "懷策遊鉅公，鯁語幾喙唾。", "忍腹大窮歸，離魂費招些。", "予嘗欲論薦，身微蟻在磨。", "藉令或指擿，聲名屢自墮。", "吾師天下賢，黠羌久未破。", "屈禮致豪英，雋材多將佐。", "古來死恩士，乃是翳桑餓。", "況子挾所能，何門不驚坐。", "丈夫感氣義，豈肯類市貨。", "行矣勿棲遲，曷日祖車軑。", "憶竹夙有尚，直節無染涴。", "勉哉困益堅，持之以爲賀。"]'),
('9bac93f3-217d-431d-bfc2-b425181444e0','李山英以疾歸田客有言山英移書石守道者因摭取其略作詩以送之','蔡襄','宋','宋诗','song-poetry','','[]','吾友守道氣剛勁，醜邪扶直出天性。',320,'全唐诗/poet.song.22000.json','["吾友守道氣剛勁，醜邪扶直出天性。", "意高身賤無所發，胸中事事先後併。", "襄嘗畏其大勇果，願以中直爲得正。", "忽聞魯士李山英，移書告之要力行。", "曰今天下最急務，邊頭戰守羌夷橫。", "異術紛回蠹化原，佞夫欺巧疵邦政。", "生民失職餽歛繁，勢若久旱方雩榮。", "安得快雨洗長空，萬物蕭森蒙大慶。", "古人有以身徇言，前者已僵後者更。", "況值朝廷上寬大，苦諫兼容天子聖。", "我疾不幸子可屬，或列封章或庭諍。", "勿學得路世俗兒，軟語妖歌日酣醟。", "乃知山英落落者，支革雖疲心愈競。", "予思物理似顛倒，難用智愚准衰盛。", "賢豪既少遇又稀，或老且困壯而病。", "就令貴顯亦迍躓，尤觸陰機石臨穽。", "一思九嘆起呼天，何等官曹司是柄。", "由來宰主都冥寞，用捨惟時窮達命。", "山英歸去亦何恨，門外無塵春色凈。", "回看名宦似浮漚，都把雄心付觴詠。"]'),
('cacf9af6-5f65-4402-b16b-b11dd5162f38','送許寺丞知古田縣','蔡襄','宋','宋诗','song-poetry','','[]','大雪擁都門，子行亦良苦。',288,'全唐诗/poet.song.22000.json','["大雪擁都門，子行亦良苦。", "予貧乏觴豆，子車誰爲祖。", "少止聽我言，於子不無補。", "于今方用兵，連年戍羌虜。", "戰死動萬計，募人填卒伍。", "賜衣靡國帑，走粟填邊庾。", "平時賦稅外，弓刀甲楯弩。", "干名應急須，筋皮角毛羽。", "前年科鞏革，農牛半斤斧。", "殺之先冒禁，不殺即鞭楚。", "江南供鵰翎，是物不棲渚。", "十倍買所無，贏利資商買。", "編紙作戰䤴，紉聯驅婦女。", "輸來不適用，空屋窠蟲鼠。", "此類如蝟毛，更僕難悉數。", "大凡歛貸財，百姓若外府。", "苟可入軍須，豈敢怨官取。", "蓋患在不均，又索非其土。", "有司失預計，臨事纔披簿。", "嚴程弗渝日，落符灑飛雨。", "使者但依違，州家不敢主。", "況復爲邑令，喑吟莫伸吐。", "其間或得才，吏手無容舞。", "子今佩縣章，所領十萬戶。"]'),
('dd7fc5d6-6274-43fe-9eb0-18658314ff53','遊鼓山靈源洞','蔡襄','宋','宋诗','song-poetry','','[]','郡樓瞻東方，嵐光瑩人目。',120,'全唐诗/poet.song.22000.json','["郡樓瞻東方，嵐光瑩人目。", "乘舟逐早潮，十里登南麓。", "雲深翳前路，樹暗迷幽谷。", "朝雞亂木魚，晏日明金屋。", "靈泉注石竇，清吹出篁竹。", "飛毫劃峭壁，勢力勿驚觸。", "捫蘿躋上峰，大空延眺矚。", "孤青浮海山，長白掛天瀑。", "況逢肥遯人，性尚自幽獨。", "西景復向城，淹留未云足。"]'),
('3321ea26-8cb8-4ccd-b91e-323dd0cdfe74','新作春野亭','蔡襄','宋','宋诗','song-poetry','','[]','太守職民治，詔書劭吾農。',96,'全唐诗/poet.song.22000.json','["太守職民治，詔書劭吾農。", "載酒事緬邈，作室當廨中。", "況憑軒牖高，中視田野功。", "澹沲沐新澤，依微生柔風。", "江潮漲新綠，山麓延朝紅。", "耕鉏時節動，歌謠聲意通。", "慙非共理材，幸遘頻年豐。", "未厭畎畝樂，駕言誰相從。"]'),
('19226826-faf2-4ce3-ba79-56a2236ec2be','春野亭待月有懷','蔡襄','宋','宋诗','song-poetry','','[]','淅瀝凉風來，空郊生暮寒。',72,'全唐诗/poet.song.22000.json','["淅瀝凉風來，空郊生暮寒。", "山氣鬰蒼蒼，江流去漫漫。", "闔關行人稀，投棲夕鳥還。", "疎鐘度林際，華月吐城端。", "徘徊待遥夜，露下明河寬。", "心朋隔萬里，獨坐起憂歎。"]'),
('45a6cfae-a1ae-481a-970e-c993e7dbab9d','送柯祕書三子歸泉應詔','蔡襄','宋','宋诗','song-poetry','','[]','祕書昔共官臨漳，時呼三子侍側傍。',192,'全唐诗/poet.song.22000.json','["祕書昔共官臨漳，時呼三子侍側傍。", "修瞳闊顙善應對，舉措不類羣兒行。", "遥知成就在他日，爾時迄今十載强。", "閩州太守無伎術，乞持符竹還故鄉。", "近觀詔書下郡國，選訪行實登俊良。", "嶷然三子復過我，衣裾飄灑凝秋霜。", "各携編軸幾百幅，互以理要充詞章。", "久之潛思叩幽眇，角牙騰觸聲礌硠。", "言歸溫陵入場屋，爭奮筆舌論短長。", "海鷹上雲出瓜翼，天馬歷地無羈韁。", "祕書多才晚未遇，有如此子傳義方。", "吾徒沉昇不須議，且看少者騰聲光。"]'),
('eeeacf10-0077-41f2-95fa-bb8956522b74','州學餞送解發進士','蔡襄','宋','宋诗','song-poetry','','[]','朝家歲取天下士，官守小大悉分治。',272,'全唐诗/poet.song.22000.json','["朝家歲取天下士，官守小大悉分治。", "育材論薦苟失宜，德業英豪苦難致。", "予嘗備員內供奉，作書參議科場事。", "鄉舉察廉未易復，責其節行在長吏。", "策之當世之大務，適時可以觀周智。", "問之六經之歸趣，知言可以見精意。", "衆賢一劃天子可，開設學校朔南被。", "世儒苟欲便有司，詔令初傳尋已置。", "今年郡國選多士，糊名仍舊搜瑕纇。", "常憂璣貝隨手遺，往往中夜起不寐。", "拆封辨號指姓名，十九冥合州人議。", "耽耽黌舍秋景長，芳殽旨酒邀賓醉。", "惜哉今樂與古異，遣士禮數不能備。", "霜天寥寥萬象清，健風開送羣飛翅。", "大明帝居一氣傍，春日照耀桐槐翠。", "勉思奇策當天心，厚祿榮名時所貴。", "時之所貴亦外物，君子存誠思遠至。"]'),
('46751540-d394-431c-b432-f9b40f69e62a','寄題滁州豐樂亭','蔡襄','宋','宋诗','song-poetry','','[]','君爲滁上守，乘間務幽尋。',120,'全唐诗/poet.song.22000.json','["君爲滁上守，乘間務幽尋。", "羣從留山阿，美望窮前林。", "良醼追佳賞，高亭曠遐臨。", "煙雲無定姿，水石唯清音。", "靜見魚鳥適，遥聞雞犬深。", "時節屢豐有，民里無欺侵。", "豈獨延衆物，因茲託沖襟。", "大筆每絕唱，芳樽寧孤斟。", "別日念已長，來期詎能今。", "安得凌風翰，相從殫歲陰。"]'),
('eba1cb0d-5f16-4c77-982e-667b9e065f0e','達觀亭','蔡襄','宋','宋诗','song-poetry','','[]','峭峻釣龍石，飛亭壓其端。',96,'全唐诗/poet.song.22000.json','["峭峻釣龍石，飛亭壓其端。", "曠徹四無際，因之名達觀。", "扳雲躋大庭，仙路何紆盤。", "秋明澄遠綠，晚霽凝新寒。", "城郭烟火稠，水陸漁樵安。", "偶暇按民俗，適遊心意歡。", "鳴絃俯清流，對酒環蒼山。", "重拂衣裾凈，從带夕嵐還。"]'),
('b97b1fa4-b5cb-45c2-bdf1-7dcdc8ce446b','聖泉','蔡襄','宋','宋诗','song-poetry','','[]','源流出何山，湧涸茲有異。',72,'全唐诗/poet.song.22000.json','["源流出何山，湧涸茲有異。", "湛然盈不泓，餘波下金地。", "清甘本無滓，渴飲得真味。", "端能發茶色，博亦資農利。", "矧茲民俗安，湓溢尤可憙。", "滿酌復携歸，良追曲肱意。"]'),
('f9fcde87-f95d-404b-be35-d2e7b09ab506','聖泉寺松徑','蔡襄','宋','宋诗','song-poetry','','[]','青松苒苒門前道，根氐堅牢顔色好。',128,'全唐诗/poet.song.22000.json','["青松苒苒門前道，根氐堅牢顔色好。", "鳴籟蕭森風雨生，紫鱗開動龍蛇老。", "天若有意別留種，百年其下無纖草。", "雷霆遶遶雪霜重，勁節支扶不顛倒。", "野姿峭拔已背時，肯要藤花彊纏抱。", "南方赤夏苦蒸濕，萬木無聲就僵槁。", "忽經密蔭少休息，肌骨便驚秋氣早。", "寄言匠者忽復顧，留作清涼除熱惱。"]'),
('6d632b33-7e89-4067-a483-17ec374020d7','釣龍臺','蔡襄','宋','宋诗','song-poetry','','[]','龍在固神物，動與風雲會。',120,'全唐诗/poet.song.22000.json','["龍在固神物，動與風雲會。", "胡爲脫淵泉，輒觸鉤綸害。", "無乃護明珠，睡目方瞢昧。", "而或嗅香餌，貪涎適霑霈。", "不爾騰角牙，自衒鱗蟲最。", "來應山嶽摇，去等蟬虵蛻。", "傳聞曠百世，茲事久晻曖。", "空餘古臺石，硉矹塵沙外。", "湍流卷白日，巖壑動清籟。", "乾坤終蒼茫，物理有否泰。"]'),
('f2c57b6e-7a43-4e76-ae0d-732e6d443628','授轉運使罷州端居術懷','蔡襄','宋','宋诗','song-poetry','','[]','被詔領均漕，前解閩州符。',96,'全唐诗/poet.song.22000.json','["被詔領均漕，前解閩州符。", "掩關謝來賓，釋然捨攣拘。", "日晏眠空齋，啼禽在高梧。", "神情已欣快，痾恙還輕辦。", "蹔閒固自適，況與塵滓殊。", "勿樂夸毗子，開眼趨畏途。", "投身試羅網，反用腴妻孥。", "精慮成長謠，鑒此非迷愚。"]'),
('41c012a0-0981-4b2b-921f-9fe6eec458f3','移居轉運宇別小欄花木','蔡襄','宋','宋诗','song-poetry','','[]','三年對小欄，花蘤見顔色。',96,'全唐诗/poet.song.22000.json','["三年對小欄，花蘤見顔色。", "紅薇開已久，春風長先得。", "素馨出南海，萬里來商舶。", "團團末利叢，緐香暑中拆。", "餘畦十數種，亦自尚風格。", "念爾幽芳性，乞致多手植。", "瑶草固微生，栽培子豈德。", "別去重來看，猶使中情惻。"]'),
('9c08eb19-5a7c-41cc-931b-01a7ec373b65','北苑十詠 出東門向北苑路','蔡襄','宋','宋诗','song-poetry','','[]','曉行東城隅，光華著諸物。',36,'全唐诗/poet.song.22000.json','["曉行東城隅，光華著諸物。", "溪漲浪花生，山晴鳥聲出。", "稍稍見人烟，川原正蒼鬰。"]'),
('77e4d3d8-1277-44a5-b083-a146227507bf','北苑十詠 北苑','蔡襄','宋','宋诗','song-poetry','','[]','蒼山走千里，斗落分兩臂。',36,'全唐诗/poet.song.22000.json','["蒼山走千里，斗落分兩臂。", "靈泉出地清，嘉卉得天味。", "入門脫世氛，官曹真傲吏。"]'),
('1f6d54ae-0d00-47b0-af9e-1500b405e625','北苑十詠 茶壟','蔡襄','宋','宋诗','song-poetry','','[]','造化曾無私，亦有意所加。',36,'全唐诗/poet.song.22000.json','["造化曾無私，亦有意所加。", "夜雨作春力，朝雲護日華。", "千萬碧玉枝，戢戢抽靈芽。"]'),
('f697693d-1fbf-4524-91e9-fd7ea445b064','北苑十詠 採茶','蔡襄','宋','宋诗','song-poetry','','[]','春衫逐紅旗，散入青林下。',36,'全唐诗/poet.song.22000.json','["春衫逐紅旗，散入青林下。", "陰崖喜先至，新苗漸盈把。", "竟携筠籠歸，更带山雲寫。"]'),
('c6c18149-4488-4ac6-8b6a-14af907100e5','北苑十詠 造茶','蔡襄','宋','宋诗','song-poetry','','[]','屑玉寸陰間，摶金新範裏。',36,'全唐诗/poet.song.22000.json','["屑玉寸陰間，摶金新範裏。", "規呈月正圓，勢動龍初起。", "焙出香色全，爭誇火候是。"]'),
('fde78ada-cce9-4e1b-b1ed-7c2e94f60448','北苑十詠 試茶','蔡襄','宋','宋诗','song-poetry','','[]','兔毫紫甌新，蟹眼青泉煮。',36,'全唐诗/poet.song.22000.json','["兔毫紫甌新，蟹眼青泉煮。", "雪凍作成花，雲閒未垂縷。", "願爾池中波，去作人間雨。"]'),
('017041f1-1f45-434e-9601-d003ee754619','北苑十詠 御井','蔡襄','宋','宋诗','song-poetry','','[]','山好水亦珍，清切甘如醴。',36,'全唐诗/poet.song.22000.json','["山好水亦珍，清切甘如醴。", "朱幹待方空，玉壁見深底。", "勿爲先渴憂，嚴扄有時啟。"]'),
('39ee7598-2215-4191-9c2b-86bd6890f1f8','北苑十詠 龍塘','蔡襄','宋','宋诗','song-poetry','','[]','泉水循除明，中坻龍矯首。',36,'全唐诗/poet.song.22000.json','["泉水循除明，中坻龍矯首。", "振足化仙陂，回晴窺畫牖。", "應當歲時旱，噓吸雲雷走。"]'),
('2b84e1e4-142f-44a4-a4c7-41c32bc7eedf','北苑十詠 鳳池','蔡襄','宋','宋诗','song-poetry','','[]','靈禽不世下，刻像成羽翼。',36,'全唐诗/poet.song.22000.json','["靈禽不世下，刻像成羽翼。", "但類醴泉飲，豈復高梧息。", "似有飛鳴心，六合定何適。"]'),
('c9526cd4-3699-4c37-8084-bdc8f241d132','修貢亭','蔡襄','宋','宋诗','song-poetry','','[]','清晨挂朝衣，盥手署新茗。',36,'全唐诗/poet.song.22000.json','["清晨挂朝衣，盥手署新茗。", "騰虯守金鑰，疾騎穿雲嶺。", "修貢貴謹嚴，作詩諭遠永。"]'),
('ce575e6d-8051-4041-95c7-fffddea93a1c','題譙國評事壁','蔡襄','宋','宋诗','song-poetry','','[]','長岡隆雄來北邊，勢到合下方回旋。',64,'全唐诗/poet.song.22000.json','["長岡隆雄來北邊，勢到合下方回旋。", "三世白士猶醉眠，山翁作善天應憐。", "如彼發源今流泉，子孫何數鷹馬然。", "有起家者出其間，願翁壽考無窮年。"]'),
('bc1c5b05-e597-4dab-87e5-cf4974d37d95','遊沖虛觀','蔡襄','宋','宋诗','song-poetry','','[]','真人玉骨輕，御氣升瑶臺。',96,'全唐诗/poet.song.22000.json','["真人玉骨輕，御氣升瑶臺。", "俯首視下方，萬落腥塵埃。", "香火久寂寞，山川空徘徊。", "舊樹絡青蔓，虛壇生紫苔。", "宴坐白晝永，長吟清風來。", "飛花亂棋子，游蜂依酒盃。", "嘉月當醉飲，上客誠珍才。", "神仙那可冀，金鼎何時開。"]'),
('96324619-7c09-47de-844c-804debe245a4','題延平閣','蔡襄','宋','宋诗','song-poetry','','[]','雙溪會一流，新搆橫鮮赭。',144,'全唐诗/poet.song.22000.json','["雙溪會一流，新搆橫鮮赭。", "浮居紫霄端，卧影澄川下。", "峽深風力豪，石峭湍聲瀉。", "古劍成蟄龍，商帆來陣馬。", "晴光轉羣山，翠色著萬瓦。", "汀洲生芳香，草樹自閒冶。", "主郡王士安，高文勇枚賈。", "顧我久疎悴，霜髭漸盈把。", "臨津張廣筵，窮晝傳清斝。", "舞鼉驚浪翻，歌扇嬌雲惹。", "歡餘適晚霽，望外迷空野。", "曾是倦遊人，意慮亦瀟灑。"]'),
('983607cb-0ff9-4d8b-bc68-473f0e831dec','送勤上人歸吳中','蔡襄','宋','宋诗','song-poetry','','["\u897f\u6e56"]','吳江水好吳岫靈，吳人晳白神氣清。',144,'全唐诗/poet.song.22000.json','["吳江水好吳岫靈，吳人晳白神氣清。", "當須比屋皆佳器，奈何儻有名公卿。", "究觀是事見藏伏，例學浮圖超死生。", "遂令才智蓄利澤，若日不下霑四瀛。", "勤師內外久著力，文字骨節初老成。", "十年棲遲輦轂下，淵然澹薄無經營。", "惜哉明了足見解，獨擘迅翮翻青冥。", "殘秋忽別東南去，塵土擺落衣裾輕。", "西湖勝處拂談席，綠波畫舫吾其行。"]'),
('b763b392-95d5-4d18-beba-4877d7eb138a','送石昌言知宿州','蔡襄','宋','宋诗','song-poetry','','[]','符離封城古云望，扼控東南地形壯。',224,'全唐诗/poet.song.22000.json','["符離封城古云望，扼控東南地形壯。", "飛流金粟走舟車，鎮壓奸雄宿兵仗。", "昌言才思才臺閣，聲名遠出風騷將。", "倦直承明得守符，詔書遣臨士民上。", "萬家裁製須得宜，譬若楩楠迎大匠。", "京師從遊日月久，送君酒酣益惆悵。", "人生豈效雞鶩羣，意在糠粱取甘養。", "邊隅多故方急材，往往稠人拔公相。", "吾儕有策空自奇，皎皎丹衷亦誰亮。", "欲隨戎馬僅勝衣，强作文章還覆醤。", "大都用置繫於時，丈夫未死固難量。", "觥巡卷到君勿辭，行看岸下船頭放。", "我今聯束若愁鷹，注目青雲思遠颺。", "一麾當復泛隋渠，願君加數爲公釀。"]'),
('c2c0cc67-9688-4e40-b0c4-a1c5b7886e28','觀宋中道家藏書畫','蔡襄','宋','宋诗','song-poetry','','[]','宣獻業文學，嘗作調羹鹽。',288,'全唐诗/poet.song.22000.json','["宣獻業文學，嘗作調羹鹽。", "藏書百千帙，傳世惟清廉。", "東堂得春和，花卉晨露霑。", "之君延賓從，當晝褰珠簾。", "朱函青錦囊，寶軸紅牙籤。", "大令至歐褚，屈玉聯鉤鈐。", "草行戰騎合，楷正中軍嚴。", "水墨固昏淡，骨氣猶深潛。", "江田亦名手，農野興鉏鐮。", "桑麻婦女喜，饁餉兒童覘。", "列女自幽閒，明眸咽頸纖。", "昔人何遥遥，意會相披瞻。", "南曹古貌醒，博士新詩炎。", "持杯屢屬我，謂我毫錐銛。", "煤嫗浮醉鈿，研流泣秋蟾。", "放灑雲雷起，取餘風良恬。", "鄙藝豈足多，詫語誰能兼。", "因思左宣獻，載檄陪車幨。", "辱公知遇厚，表裏曾無嫌。", "間復請筆法，指病如投砭。", "今朝觀故物，惜已悲慚兼。", "層丘恩德重，素髮年華添。", "不能枉尺尋，況乃事飛箝。", "壯心久已衰，奇尚顧未厭。"]'),
('37bdf1e9-60f8-40fa-8e53-d292687e78b9','西齋秋暑','蔡襄','宋','宋诗','song-poetry','','[]','齋居一室靜，晝永來風微。',48,'全唐诗/poet.song.22000.json','["齋居一室靜，晝永來風微。", "仙棋覆前局，女布便輕衣。", "向人顔色强，與世心事違。", "且效金門隠，詎有田園歸。"]'),
('b82a8e26-1173-44a2-a0fc-e95773a436fe','胡鴈','蔡襄','宋','宋诗','song-poetry','','[]','胡鴈畏空漠，羣飛響洲渚。',96,'全唐诗/poet.song.22000.json','["胡鴈畏空漠，羣飛響洲渚。", "褰雲避射弋，萬里聲悲苦。", "月色滿關河，欲下迷處所。", "春江沙平凈，魚蚌不可數。", "飽暖身肥腴，歸路欲遠舉。", "尋常弓箭兒，仰視隨意取。", "從來遠禍心，狼藉失舊侶。", "小哉銜蘆智，豈識保身語。"]'),
('dbc1d908-3ea7-461b-8088-9313b4c0d97b','即惠山煮茶','蔡襄','宋','宋诗','song-poetry','','[]','此泉何以珍，適與真茶遇。',72,'全唐诗/poet.song.22000.json','["此泉何以珍，適與真茶遇。", "在物兩稱絕，於予獨得趣。", "鮮香筯下雲，甘滑杯中露。", "當能變俗骨，豈特湔塵慮。", "晝靜清風生，飄蕭入庭樹。", "中含古人意，來者庶冥悟。"]'),
('7783bb95-f396-4104-a5f7-77b589ad2592','題周著作萃賢亭','蔡襄','宋','宋诗','song-poetry','','[]','君家作虛亭，獨得江山清。',120,'全唐诗/poet.song.22000.json','["君家作虛亭，獨得江山清。", "四向各有適，萬趣各自呈。", "夜深蟲鳥息，漸聞泉石鳴。", "日高烟靄去，始見峯巒生。", "之人務佳尚，意與賢豪傾。", "中盤淪薇蕨，傍砌顛瓶罌。", "毫端潜造物，局上暗投兵。", "樂遊時景邁，薄宦身事縈。", "種花行老色，馴猿無故情。", "蕭散復後期，外塵殊可輕。"]'),
('2c8de7e0-bf4e-49bd-9e7f-e338bcb6622b','瞻禮開師真像','蔡襄','宋','宋诗','song-poetry','','[]','輕瀾還故潯，墜軫無遺音。',72,'全唐诗/poet.song.22000.json','["輕瀾還故潯，墜軫無遺音。", "好在池邊竹，猶存虛直心。", "往復二十年，每見唯清吟。", "覺性既自如，世味隨浮沈。", "琅琅白雲姿，悵望空山岑。", "豈不悟至理，悲來難可任。"]'),
('746eb32c-e531-4a9e-a3a2-35e21992c525','偶作','蔡襄','宋','宋诗','song-poetry','','[]','作墨本誰氏，研摩有强弱。',24,'全唐诗/poet.song.22000.json','["作墨本誰氏，研摩有强弱。", "摩盡不見墨，此處原非著。"]'),
('aa5f934b-e7a7-41f4-a876-bb091b006e20','至和雜書五首 八月一日','蔡襄','宋','宋诗','song-poetry','','[]','淮天過盡入吳渠，蘭亭晚日光疎疎。',192,'全唐诗/poet.song.22000.json','["淮天過盡入吳渠，蘭亭晚日光疎疎。", "金桃傅粉好顔色，綠醽泛灧深車渠。", "觥巡屢卷明星出，花翹零落隨衣裾。", "幺絃不動凝古意，春容淺破長眉舒。", "庭院簾帷一齊下，紅蠟陰沈霜滿瓦。", "雞頭軟熟七月終，舉手分傳玉盈把。", "席前碧甕覆瑶槳，一秋愁淚風前灑。", "雲中寶暈萬重高，付與輕綃藏冰麝。", "孤城寒柝夜迢遥，誰道劉郎有天馬。", "歸來却問東海桑，海浪漫漫彩虹挂。", "紅絲縈膾曉刀鳴，雙龍笑斷夢中驚。", "莫將團扇掩塵匣，曾障清歌十數聲。"]'),
('1c0ab70e-9c95-4d27-8771-6830af231744','至和雜書五首 八月二日','蔡襄','宋','宋诗','song-poetry','','[]','濃雲瞥過雙鳳飛，清顔照射朝日輝。',192,'全唐诗/poet.song.22000.json','["濃雲瞥過雙鳳飛，清顔照射朝日輝。", "畫船南畔烟成陣，鮮荷掩護仙銖衣。", "凝魂杳眇不知處，酒醺香破驚新知。", "一聲入耳醉人骨，天容牢落星點稀。", "海山萬里風濤外，扶桑未老成春絲。", "春絲不斷縈成結，玉環宛轉無窮時。", "曉簾半上香飄穗，笑指冰壺凝遠淚。", "秦樓後夜鏁孤鸞，秋風不動烏龍睡。", "願將瓊樹隔花看，一一花房暗相值。", "濁水芙蕖天際雲，長時倚望清江濱。", "迎來未語送歸速，暮山紫翠空含嚬。", "勸君美酒千萬壽，情如芳草年年新。"]'),
('3e8deab8-034a-4827-998f-93df7546cb33','至和雜書五首 八月九日','蔡襄','宋','宋诗','song-poetry','','[]','曉虹跨江一千尺，平浪東西入天碧。',112,'全唐诗/poet.song.22000.json','["曉虹跨江一千尺，平浪東西入天碧。", "遊人初覺秋氣涼，衣不禁風薄羅窄。", "漁家小艇方醉眠，艇裏長魚三尺白。", "彩欄北倚數流螢，似與流螢舊相識。", "香脂揩盡暗成雲，銀甲試絃初未直。", "橋前流水聲潺潺，年華一去何時還。", "重來若問桃花路，記取松亭月影間。"]'),
('995a143d-09b4-4d43-a85a-0d6f484a0c82','至和雜書五首 八月十二日','蔡襄','宋','宋诗','song-poetry','','[]','高樓中天月色凈，玉山禾熟秋雲映。',96,'全唐诗/poet.song.22000.json','["高樓中天月色凈，玉山禾熟秋雲映。", "草邊水際見流螢，流螢獨自尋香徑。", "稜層鴈塔挂千燈，密意雖通語還併。", "城上驚烏飛復啼，落泊無依終不定。", "欲下長橋夜漏深，燭臺飄灺青梧陰。", "仙人若也乘鸞去，彩霧千重何處尋。"]'),
('50bf09d4-255b-4b35-bf75-c6055bd237b9','八月十九日','蔡襄','宋','宋诗','song-poetry','','[]','潮頭出海卷秋風，風豪潮起蒼海空。',112,'全唐诗/poet.song.22000.json','["潮頭出海卷秋風，風豪潮起蒼海空。", "弄潮船旗出復沒，騰身潮上爭驍雄。", "沙頭萬目注江水，晴雷乾雹來無窮。", "窗外簾旌飛獵獵，新醅翠斝行坐中。", "欲作吳歌弄清晝，回看滿眼西陽紅。", "六曲屏深映雲母，珠盤縷縷青鴉茸。", "山移海轉有變化，生緣長短須相逢。"]'),
('86baae57-3072-4db0-abfc-90d9fcad4696','讀樂天閒居篇','蔡襄','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','予年四十四，髮白成衰翁。',288,'全唐诗/poet.song.22000.json','["予年四十四，髮白成衰翁。", "非有高蓋車，曷與賢者同。", "嗟予出寒遠，家世嘗力農。", "十九登科第，聖彀參英雄。", "十年出吏選，校書蓬陼中。", "天子投採拔，謂有諫諍風。", "既叨言責地，蹇蹇思匪躬。", "竊不自度量，語剡奸邪胸。", "一毫抗千鈞，擯落無流蹤。", "同時皆驤首，金紫班著崇。", "唯予守長樂，幸就祿養豐。", "八年江海外，再上螭階東。", "四十入西閣，宿仇司化工。", "蒙錦投機穽，唯頼天聽聰。", "代言遊禁密，侍從多從容。", "尋行京兆事，繫斷露銛鋒。", "是職非所好，輒以死竭忠。", "願闢大幽都，爲君囚四凶。", "願拂四省堂，爲君延夔龍。", "願舒泰山雲，甘澤成歲功。", "願回太清日，晴景破陰蒙。", "願躋萬人壽，夭扎終不逢。", "願令編戶富，食衣無困窮。", "羣臣走率職，陛下居法宮。"]'),
('9693ca1a-bf86-48a4-a200-35e64e948d56','元日過浦城西陽嶺','蔡襄','宋','宋诗','song-poetry','','[]','逝者東流水，情知無却迴。',40,'全唐诗/poet.song.22000.json','["逝者東流水，情知無却迴。", "遲留曾到處，嗟古不同來。", "誰道新年好風物，忍將淚眼向春開。"]'),
('74db884b-883f-489e-8f69-9c3f5e0452fc','題將軍巖','蔡襄','宋','宋诗','song-poetry','','[]','赤日正停午，解衣巖石下。',48,'全唐诗/poet.song.22000.json','["赤日正停午，解衣巖石下。", "石泉殊甘涼，野籟亦瀟灑。", "驚猿度嶺雲，遺果墜庭瓦。", "披軒忽永歎，幽抱不可寫。"]'),
('1920ab86-9f96-478a-9095-fe5ec65e3d55','安靜堂書事','蔡襄','宋','宋诗','song-poetry','','[]','勿學異世人，過常不可深。',72,'全唐诗/poet.song.22000.json','["勿學異世人，過常不可深。", "勿學慢世人，側身隨浮沈。", "白日當中天，難破是非心。", "不有拔俗器，安得太古音。", "大暑苦煩濁，清泉流高岑。", "烈士無戀嫪，至理須推尋。"]'),
('edceb046-5721-45eb-bd13-52e2dee0469e','丙申秋八月過漁溪驛驛舊有梅數株嘗題詩記今無有也二首  其一','蔡襄','宋','宋诗','song-poetry','','[]','曾把早梅枝，思君在別離。',72,'全唐诗/poet.song.22000.json','["曾把早梅枝，思君在別離。", "別離雖云遠，萬里有還期。", "樹枯根已撥，人去復何之。", "故館動秋色，雲物藏寒曦。", "清香不可聞，衰草空繁滋。", "一夜平階雨，輾轉良自知。"]'),
('5ee3fca0-c579-49c8-9e27-527191cc1ef7','丙申秋八月過漁溪驛驛舊有梅數株嘗題詩記今無有也二首  其二','蔡襄','宋','宋诗','song-poetry','','[]','梅花不復見，況乃扳花人。',72,'全唐诗/poet.song.22000.json','["梅花不復見，況乃扳花人。", "花飛別故樹，粉黛化爲塵。", "秋風捲落葉，蟲豸鳴悲辛。", "昏鴉投舊巢，匹侶自相親。", "缺月行復滿，歸雲本無垠。", "因題憶花篇，此意難重陳。"]'),
('145be85f-2d91-4d7e-a644-d12c97997991','答葛公綽求猿','蔡襄','宋','宋诗','song-poetry','','[]','子求穉猿書至閩，我說猿意持贈君。',208,'全唐诗/poet.song.22000.json','["子求穉猿書至閩，我說猿意持贈君。", "吾州四面列巖巘，鉅木轇葛凌氛氳。", "結窠栽檻走疾置，十日可置澄江濆。", "嗟憐庶品各有性，拘憂適喜無間分。", "彼猿之類宅丘壑，愛戀深厚編前文。", "戲禽雖傳古仙者，射臂未許今將軍。", "朝棲喬木之蒼莽，夕飲幽澗之潺沄。", "山空月明一長嘯，商船海上迎風聞。", "君家東園豈不美，檜竹翠密蘭茞薰。", "斯猿儻憶故時侶，舉首斷隔千重雲。", "縱之不遣乃得所，推夫此理惠澤雰。", "令吾郡邑決籠柙，蹄者奔逸羽者翂。", "因觀微物通萬化，譬諸獻鵠良有云。"]'),
('354fe693-1d87-48e9-86ae-6c9dc55573a6','秋夜書廨中壁','蔡襄','宋','宋诗','song-poetry','','[]','遥夜不能寢，值茲節物清。',48,'全唐诗/poet.song.22000.json','["遥夜不能寢，值茲節物清。", "大空瑩虛碧，仰觀澄性情。", "素月若可把，浮雲何故生。", "瑶琴且勿弄，誰憐希代聲。"]'),
('4b80bd6a-cedb-4aa7-8a86-834605102596','秋思','蔡襄','宋','宋诗','song-poetry','','[]','幽蘭受新霜，孤雁叫落月。',72,'全唐诗/poet.song.22000.json','["幽蘭受新霜，孤雁叫落月。", "沈憂何由平，永夕不可徹。", "將琴鼓憶憐，聲急弦屢絕。", "芳華日益遠，香澤物已歇。", "秋風吹石門，思君還復訣。", "誰云無生忍，識此悠悠別。"]'),
('ccb30354-b5c1-4d20-843a-6aaa4a5c782c','寒食梨花小飲','蔡襄','宋','宋诗','song-poetry','','[]','江南寒薄春嘗早，花卉入春先自老。',272,'全唐诗/poet.song.22000.json','["江南寒薄春嘗早，花卉入春先自老。", "嗟予衰病不及時，出見池園半青草。", "縱有餘葩在葉間，行看落片隨風掃。", "尋春已過索莫歸，重憶歡娛耿懷抱。", "雖然妖艷難再得，但只逢花須醉倒。", "二月中央寒食朝，牆隈忽見梨花飄。", "開門四顧粲然白，傳催翠帟賓朋招。", "長吟環遶不知數，漸值明月臨清霄。", "誰翦輕雲成碎蕊，天留密雪封枯條。", "重重盡挂珠纓絡，簌簌初呈簂步摇。", "傍花行酒發新唱，滿座例舉黄金瓢。", "西都姚黄高一尺，揚州寶髻分雙翹。", "幽香絕艷信尤物，設欲置之千里遥。", "壁門寫生亦名畫，未免五彩塗鮫綃。", "莫如此君慰人意，相對一笑開無憀。", "古來英豪多感激，坐使綠鬢朱顔雕。", "勸君且作梨花飲，慎勿稱量別流品。"]'),
('3bd5aec4-1d63-4e0b-9536-33c9227019dd','雨晴早出','蔡襄','宋','宋诗','song-poetry','','[]','徂秋久不雨，霑濡纔此旬。',48,'全唐诗/poet.song.22000.json','["徂秋久不雨，霑濡纔此旬。", "新陽凈萬物，太虛無一塵。", "老稚出曠野，鋤犂及清晨。", "愛爾安居樂，力作勿辭貧。"]'),
('310b05e4-786e-4ced-b3d7-df5992d3fa4d','訪天台菴','蔡襄','宋','宋诗','song-poetry','','[]','幽人去未還，門戶和雲閉。',48,'全唐诗/poet.song.22000.json','["幽人去未還，門戶和雲閉。", "亭午樹陰圓，深冬泉響細。", "寒生羣鳥鳴，清徹孤鶴唳。", "寂寞傍山歸，寫向滄溟際。"]'),
('f57c6d3d-03b7-408b-b6d8-99685453bf4a','和吳省副青梅','蔡襄','宋','宋诗','song-poetry','','[]','梅華畏高寒，獨向江南發。',48,'全唐诗/poet.song.22000.json','["梅華畏高寒，獨向江南發。", "那知汴陽墅，青顆摘春月。", "持之務所無，歸思動楚越。", "願君侑清罇，行恐新芳歇。"]'),
('acd77867-c3b4-4c45-ac31-3ffbe6fb0100','留別舊居花檻','蔡襄','宋','宋诗','song-poetry','','[]','別意起中夕，出門風吹衣。',48,'全唐诗/poet.song.22000.json','["別意起中夕，出門風吹衣。", "側月光艷薄，餘花香氣微。", "清尊歲相向，欲去心有違。", "殘葩勿盡放，主人行亦歸。"]'),
('001d4697-1c79-4fd5-be99-b159a5e6e563','甲辰閏月初伏快雨凉風晝眠初覺庭前小欄花木各有意氣效柏梁體','蔡襄','宋','宋诗','song-poetry','','[]','閏夏天地熱焰烘，崇朝快雨隨清風。',176,'全唐诗/poet.song.22000.json','["閏夏天地熱焰烘，崇朝快雨隨清風。", "晝軒夢覺開前櫳，畫欄花草意氣雄。", "側枕遥問數異同，如子微物煩化工。", "盍各言爾之所從，繁葩富艷生朱紅。", "枯條大蕊千萬重，修幹點綴赤日中。", "蠲去憂忿誰與功，採摘烹煮袪煩胸。", "秋霜鉅實垂如甕，橫柯遠引交加叢。", "葉抽綠劍端黄茸，直立開拂泉貸通。", "壘遶翠羽翻虯龍，誤入畦町非余公。", "助滌渴肺思菲躬，物物自名詞不窮。", "願當我意乃汝容，負汝不飲慙衰翁。"]'),
('d5130ec3-ad30-4427-abbb-1dead718773f','過皇甫侍郎','蔡襄','宋','宋诗','song-poetry','','[]','丈人幾八十，歲晚益窮經。',192,'全唐诗/poet.song.22000.json','["丈人幾八十，歲晚益窮經。", "陰陽判九六，天地環丙丁。", "初若發泉穴，漸已澄滄溟。", "所寶非世有，願充天子庭。", "問我久京國，鬢髮何星星。", "無乃矜才能，吐論生風霆。", "不爾負潔修，揚眉自娉婷。", "昏翳本來性，憔悴百歲形。", "子知大方家，真精潛杳冥。", "萬化一相遇，起滅如秋螢。", "而於須臾間，計較罍與瓶。", "膏消見遠照，水燼聞餘馨。", "唯公懇懇誨，敢怠拳拳聽。", "追思響踐歷，媿汗曾未停。", "決然趨所適，金刀貴發硎。", "去矣汴流駛，薰風送揚舲。"]'),
('e658466c-7b7c-46f8-8c3a-ce51c6bd2a88','南都思杜祁公','蔡襄','宋','宋诗','song-poetry','','[]','祁公清德老，在昔相先帝。',156,'全唐诗/poet.song.22000.json','["祁公清德老，在昔相先帝。", "青雲吐論高，白璧持身銳。", "待俗無町畦，取人兼揭厲。", "甘貧安車後，直道洪鈞際。", "每聞天下士，行業若材藝。", "未見比調饑，況乃挹襟袂。", "早嘗登公門，顧睞叨末契。", "謂有金石姿，良工心劘礪。", "仰瞻通德衢，獨立耆英第。", "評書草聖優，煮荈雲腴細。", "遺墨秘巾篋，感激君子惠。", "悲風吹白楊，佳城茲久閉。", "聲名與濉渙，東流無已歲。"]'),
('7662388b-99c4-4082-88ce-e89c958f0326','酇陽行','蔡襄','宋','宋诗','song-poetry','','[]','春秋書大水，災患古所評。',240,'全唐诗/poet.song.22000.json','["春秋書大水，災患古所評。", "去年積行潦，田畝魚蛙生。", "今歲穀翔貴，鼎餁無以烹。", "繼亦掇原野，草萊不得萌。", "剝伐及桑棗，折發連簷甍。", "誰家有倉囷，指此爲兼并。", "頭會復箕斂，勸率以爲名。", "壯强先轉徙，羸瘠何經營。", "天子憂元元，四郊揚使旌。", "朝暮給饘粥，軍廩闕豐盈。", "殍亡與疫死，顛倒投官坑。", "坑滿棄道傍，腐肉犬豕爭。", "往往互食噉，欲語心驚魂。", "荒村但寂寥，晚日多哭聲。", "哭哀聲不續，饑病焉能哭。", "止哭復吞聲，清血暗雙目。", "隴上麥欲黄，寄命在一熟。", "麥熟有幾何，人稀麥應足。", "縱得新麥嘗，悲哉舊親屬。", "我歌酇陽行，詩成寧忍讀。"]'),
('c03623ab-6131-4a7f-94eb-c620fd2adb93','期秦伯鎮不至','蔡襄','宋','宋诗','song-poetry','','[]','高人懷真趣，每欲棄祿仕。',84,'全唐诗/poet.song.22000.json','["高人懷真趣，每欲棄祿仕。", "超然外造化，那復顧妻子。", "有田給饑寒，有路出生死。", "儻得自由身，休隨榮利起。", "或聞亳郊澇，族大無餘米。", "且持州紱去，官廩尚可指。", "何時當歸來，焚香朝玉几。"]'),
('f49bf1b7-ce24-4d46-b26d-5bf705a75e3b','會亭遇資政孫公赴闕公致仕已七年時召歸將有西鄙之任','蔡襄','宋','宋诗','song-poetry','','[]','志節雖落落，不能無謗毀。',216,'全唐诗/poet.song.22000.json','["志節雖落落，不能無謗毀。", "壯年自雄豪，末路遽顛委。", "衆口方叢嘈，即欲置之死。", "公嘗爲大臣，沈寃不辨理。", "恭惟仁宗聖，散地而後已。", "新治甬上居，閒逸安暮齒。", "恭惟今天子，繼照明鑒是。", "問公何處在，勉哉爲予起。", "使者臨其門，將駕不容俟。", "滔滔汴流急，行舟姑少止。", "長堤榆柳深，夜涼襟带褫。", "語終求其要，茲事殊可喜。", "朝廷英俊林，豈無人器使。", "謂公先帝臣，擢任刷前恥。", "惟公體上意，畢力荷恩紀。", "富貴安足論，清心寂如水。", "古人老益壯，忠義在所指。", "況復千載遇，功名邁良史。"]'),
('ad367b1d-fe55-40ab-930a-3a09fcacbd96','泗州登馬子山觀漕亭','蔡襄','宋','宋诗','song-poetry','','[]','廟社奠東都，恃德非恃險。',264,'全唐诗/poet.song.22000.json','["廟社奠東都，恃德非恃險。", "聚兵三十萬，待哺無容歉。", "西有砥柱峻，菽麥不踰陝。", "齊魯糧食囏，灞水不瀲灧。", "唯餘汴渠利，直貫長淮隒。", "歲輸六百萬，江湖極收斂。", "挽送入太倉，因陳失蓋弇。", "將漕苟不登，汝職茲爲忝。", "或謂取太多，六路有豐儉。", "其間一不熟，饑殍誰能掩。", "一旦俾之粟，是人意常慊。", "區處失其宜，斯言反爲玷。", "嘗欲請增減，革孚亦須漸。", "連營今飯稻，香美若菱芡。", "因循未易論，官曹畏書檢。", "虛亭一臨眺，比比危檣颭。", "來從數千里，歲時空苒苒。", "雨餘山氣凈，黛色淺深染。", "夜昏漁火出，倏忽電光閃。", "須臾月色空，水面鋪寒簟。", "相逢喜道舊，城柝屢移點。", "因語發長謠，誰能刊琬琰。"]'),
('61cb5b7b-e53a-43f3-af85-cf529c309905','和答孫推官久病新起見過','蔡襄','宋','宋诗','song-poetry','','[]','去年大暑過京口，唯子見過牛馬走。',368,'全唐诗/poet.song.22000.json','["去年大暑過京口，唯子見過牛馬走。", "氣溫貌古風骨粹，如入魏國逢軻叟。", "前趨王事難少留，兀若洪鐘未遑扣。", "窮秋忽聞感疾恙，鬭蟻入牀揚左肘。", "天生賢者固有待，豈得數奇而不偶。", "勿藥之喜既和平，大肉快噉飲幾斗。", "神明復還方寸靜，萬卷舊書仍次部。", "新年於已無職事，雖欲耕田不盈畝。", "輕舟將覽吳中春，獨信檣烏沿霞藪。", "知子玉趾遠臨訪，倒屣出迎唯恐後。", "山堂永日接言詞，楚萍色味兩俱剖。", "自云君命入巖幽，顧此一身縈組綬。", "病軀未堪事刀筆，野性如何屈杞柳。", "寧甘貧薄且晦處，終歲窮經徒皓首。", "陶家埏埴以爲器，其大如甕小如缶。", "昔人知命斯上通，動靜以時隨所有。", "我聞子論心惻惻，儻或祭天必薪槱。", "大篇短韻時見投，開霽清暘穿戶牖。", "强抽鄙意答長歌，脂澤陋滋容益醜。", "錢塘風物湖山好，與子相從頻載酒。", "一水汪灣暮日浴，千巖轉側朝雲嘔。", "放懷方外聊自適，舉杯相屬起爲壽。", "美哉此樂世難得，勿話歸期論子丑。"]'),
('8242a2f6-3b72-433c-a9af-4d39b13fcb48','丙午二月十二日雜言','蔡襄','宋','宋诗','song-poetry','','[]','仲春一浹，我生之辰。',100,'全唐诗/poet.song.22000.json','["仲春一浹，我生之辰。", "紀歲之行，五十有五。", "慈親是時九十二，稱觴獻壽於膝下。", "曾孫滿前侑以詞，慈顔强飲至酒所。", "我今鬢髮白垂絲，揮拂萊衣輒起舞。", "願親長年無窮已，願兒强健典州府。", "不富不貧正得宜，如我奉親難比數。"]'),
('160fbce0-25d3-41bd-b9ec-da9cfbd6f590','和王學士水車','蔡襄','宋','宋诗','song-poetry','','[]','星鳥正中春事濃，農夫入田布嘉種。',224,'全唐诗/poet.song.22000.json','["星鳥正中春事濃，農夫入田布嘉種。", "田中白水極瀰漫，鷺翅羣騫魚鬣聳。", "扶持水車倚塍畔，翻翻龍脊超雙踵。", "日在天中人在野，脫粟未逢心益恐。", "婦姑晚餉猶德色，童稚伺餘窺饁籠。", "夏苗欲長苦焦枯，又送微波上層隴。", "傷哉作勞無早夜，歲終贏饒凡幾桶。", "豐年遺秉尚或歉，一有不登皆散冗。", "賦田無利從來遠，索息嚴於公上奉。", "富者不耕耕者饑，役民權枋雄豪總。", "錢塘風俗本夸奢，上商射利尤加勇。", "丁男特壯走長街，僕奴意氣金銜駷。", "方春遊女湖上行，舉首惟愁釵插重。", "笑汝田家弄水車，何不乘時作光寵。"]'),
('8021b20f-e8f4-4c3e-a41a-80ffa7334bb9','四月八日西湖觀民放生','蔡襄','宋','宋诗','song-poetry','','["\u897f\u6e56"]','盈舟載魚蝦，投瀉清波際。',72,'全唐诗/poet.song.22000.json','["盈舟載魚蝦，投瀉清波際。", "應無校人欺，獨行流水惠。", "非求升斗活，終免螻蟻制。", "江湖自相忘，洲島亦還逝。", "脫淵思曩戒，嗅餌省非計。", "爲生豈不幸，萍藻庶可翳。"]'),
('ed13dbd2-3159-4709-aac0-e05033a0d687','和王學士芍藥','蔡襄','宋','宋诗','song-poetry','','[]','粲爾芳草葉，孤根當砌植。',48,'全唐诗/poet.song.22000.json','["粲爾芳草葉，孤根當砌植。", "違春已自分，薰風猶借力。", "艷艷朝日光，紛披照顔色。", "持之遺佳人，歲久香不息。"]'),
('bece8953-f60a-4275-a505-597705839223','觀三聖御書應制','蔡襄','宋','宋诗','song-poetry','','[]','聖業存功德，宸毫冠藝文。',48,'全唐诗/poet.song.22000.json','["聖業存功德，宸毫冠藝文。", "勢開千里浪，光動九天雲。", "法駕乘時至，仙都與世分。", "皇心欽寶訓，求治益精勤。"]'),
('d6d24e09-cb1f-4784-909e-1d0381b21350','羣玉殿賜宴','蔡襄','宋','宋诗','song-poetry','','[]','治道承炎曆，皇基亙萬年。',264,'全唐诗/poet.song.22000.json','["治道承炎曆，皇基亙萬年。", "深仁涵海嶽，至德著坤乾。", "文物歸元首，臣鄰必巨賢。", "蓼蕭思及下，奕葉力追先。", "昕色方羣進，臚音忽四傳。", "衣冠紛雜遝，臺殿鬰蟺蜎。", "寶字崇三聖，瑶圖祕九天。", "榮河祥氣徹，昭漢曉光旋。", "磊砢珠璣在，崢嶸歲月遷。", "家聲終卓越，上意益恭虔。", "書觀開舖首，宸毫落彩牋。", "煙雲初不定，鸞鳳互相鮮。", "拜賜兼金重，珍藏尺璧全。", "人人皆自得，事事獨超先。", "睿藻敦風教，冥搜出化權。", "來從玉山府，遠過柏梁篇。", "迴馭臨高館，推恩錫廣筵。", "迷魂遊帝所，休應動星躔。", "申命嚴樽俎，新章被管絃。", "千齡叨際會，曠古絕寅緣。", "大施難論報，精誠第祝延。", "唯應歌盛美，樂石可磨鎸。"]'),
('a2ac9a50-aac9-4883-9920-a5f1673fbe19','上元進詩','蔡襄','宋','宋诗','song-poetry','','[]','疊聳青峰寶炬森，端門初晚翠華臨。',64,'全唐诗/poet.song.22000.json','["疊聳青峰寶炬森，端門初晚翠華臨。", "宸遊不爲三元夜，樂事全歸萬衆心。", "天上清光開夜色，人間和氣閣春陰。", "要知盡作華封祝，四十年來惠愛深。"]'),
('aff0ff8d-5a22-4868-8da6-20faa187dfc0','夢中作','蔡襄','宋','宋诗','song-poetry','','[]','白玉樓臺第一天，琪花風靜彩鸞眠。',32,'全唐诗/poet.song.22000.json','["白玉樓臺第一天，琪花風靜彩鸞眠。", "誰人得似秦臺女，吹徹雲蕭上紫煙。"]'),
('68eb2f5b-0337-440e-9ee2-3f55c9745809','久寓悟空院剎行而書之','蔡襄','宋','宋诗','song-poetry','','[]','寂寂精廬切半空，古原高下稻花中。',64,'全唐诗/poet.song.22000.json','["寂寂精廬切半空，古原高下稻花中。", "蓮趺披素輕雲梵，花萼雕紅細雨宮。", "孤鶴睡迷千樹月，斷蟬吟繞五更風。", "心縻尺組遥相謝，歸馬南蹄疾似蓬。"]'),
('e586061c-02d9-466c-b082-3ea6f01f791c','漳南十詠 龍臺','蔡襄','宋','宋诗','song-poetry','','[]','試看初日照龍臺，白玉堂高錦障開。',64,'全唐诗/poet.song.22000.json','["試看初日照龍臺，白玉堂高錦障開。", "樹色一番連雨凈，溪光幾曲抱山來。", "雲歸深洞天形瘦，風落前村笛弄哀。", "擬結青樓遍題詠，思王何吝斗量才。"]'),
('dfb08c9a-23f1-4a37-9d25-762449f87f0c','漳南十詠 城東水閣','蔡襄','宋','宋诗','song-poetry','','[]','亭上芳樽惜別人，亭前斜日欲歸輪。',64,'全唐诗/poet.song.22000.json','["亭上芳樽惜別人，亭前斜日欲歸輪。", "傷心定是丹楓樹，拂面空來紫陌塵。", "歲月暗驚山色古，愁情長與草芽新。", "何時此地迴飛蓋，寂寞欄干又一春。"]'),
('10bc39bb-9e27-4e13-aa72-5bc41bbd971d','漳南十詠 南溪','蔡襄','宋','宋诗','song-poetry','','[]','近郭溪光綠好裁，雨睛波底敞棲臺。',64,'全唐诗/poet.song.22000.json','["近郭溪光綠好裁，雨睛波底敞棲臺。", "蔭堤佳樹千圍合，掠水輕舟一箭開。", "驚釣寒魚拖糝去，忘機閒鳥信潮迴。", "官餘擬欲袪塵意，書遍平沙我獨來。"]'),
('0ae67dd9-68c3-4d7a-954d-8f669100a347','漳南十詠 滿月池亭','蔡襄','宋','宋诗','song-poetry','','[]','有客高懷脫世塵，碧灣晴檻樂遊頻。',64,'全唐诗/poet.song.22000.json','["有客高懷脫世塵，碧灣晴檻樂遊頻。", "無心自合波中月，照影誰分鑑內人。", "莎砌亂蛙爭噪雨，杏梁雙燕欲留春。", "長年老厭趨豪末，來揖孤雲作上賓。"]'),
('c07b1f06-a917-4995-9053-fc452861c973','漳南十詠 西湖','蔡襄','宋','宋诗','song-poetry','','["\u897f\u6e56"]','湖上山光一笋青，佛宮高下裹巖扃。',64,'全唐诗/poet.song.22000.json','["湖上山光一笋青，佛宮高下裹巖扃。", "烟收水曲開塵匣，春送人家入畫屏。", "竹氣更清初霽雨，梅英猶細欲殘星。", "吳船越棹知何處，柳拂長堤月滿汀。"]'),
('c98356c0-d993-44e3-9f76-99e59a315042','漳南十詠 圓山廟','蔡襄','宋','宋诗','song-poetry','','[]','風雅遺芬嶽有神，此山靈祀越千春。',64,'全唐诗/poet.song.22000.json','["風雅遺芬嶽有神，此山靈祀越千春。", "彩毫佳句言猶在，翠剡新詞意未真。", "絕頂黑林長带雨，曲崖飛磴不留塵。", "瘴雲收盡秋田熟，跋境肴漿再拜人。"]'),
('51fc6f78-7ecf-4f1a-a474-ad9e5ec3c3fe','漳南十詠 陳將軍廟','蔡襄','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','曾憑水柵誓長江，報國全軀事不雙。',64,'全唐诗/poet.song.22000.json','["曾憑水柵誓長江，報國全軀事不雙。", "力屈已嗟關羽死，勢孤猶笑李陵降。", "宿墳古劍龍腥匣，環壁靈旗獸纏扛。", "神理高高人意近，楮錢祈福暗塵窗。"]'),
('868daeb7-f731-4a47-a1e2-6ba1b9d9dd99','漳南十詠 白雲亭','蔡襄','宋','宋诗','song-poetry','','[]','雲擎翬檻翠巖巔，石老松皴不計年。',64,'全唐诗/poet.song.22000.json','["雲擎翬檻翠巖巔，石老松皴不計年。", "舉世覺來空白日，幾人遊去上青天。", "醉看絕壑都無地，嘯倚清風只恐仙。", "花晚春殘無限意，他時迴首定依然。"]'),
('198926b0-d031-4b9b-ac93-51536e5ccf2c','漳南十詠 齊雲閣','蔡襄','宋','宋诗','song-poetry','','[]','紫閣青梯壓翠岑，春情秋思共登臨。',64,'全唐诗/poet.song.22000.json','["紫閣青梯壓翠岑，春情秋思共登臨。", "雨嵐供眼橫千掌，星漢垂簷直半尋。", "忍別朱欄真俗吏，獨棲珍樹祗仙禽。", "當年人事多奇尚，擬托巖扃息寸心。"]'),
('fedc6caa-4cb0-4f93-a786-8f7839264e85','漳南十詠 東郊','蔡襄','宋','宋诗','song-poetry','','[]','苒惹晴雲釀雨時，東城無處不芳菲。',64,'全唐诗/poet.song.22000.json','["苒惹晴雲釀雨時，東城無處不芳菲。", "斜坡草短孤麛卧，平壠麥深雙雉飛。", "照塢亂花驚客眼，罥空輕絮點郎衣。", "年來意氣多覊束，無復長楸带酒歸。"]'),
('a59e8275-bcca-4707-ab5b-2ce9c864acc9','別宋判官','蔡襄','宋','宋诗','song-poetry','','[]','縷縷青陰拂去鞍，雨花狼籍顫春寒。',32,'全唐诗/poet.song.22000.json','["縷縷青陰拂去鞍，雨花狼籍顫春寒。", "年光別緒侵入鬢，莫向離亭子細看。"]'),
('fd3a125d-295d-414f-9194-725b6b20e3f3','城南春會','蔡襄','宋','宋诗','song-poetry','','[]','陰雲薄薄地無塵，清曉城南集畫輪。',96,'全唐诗/poet.song.22000.json','["陰雲薄薄地無塵，清曉城南集畫輪。", "睢苑即時裁雪霰，潁川連夜聚星辰。", "山眉帖漢晴光擬，鶑舌尋風碎語真。", "芳草有情迷謝客，落花無處問秦人。", "樽前莫厭歌醒耳，世上偏饒淚滿巾。", "嘉意未闌繁盛減，東皇底事惜殘春。"]'),
('5da7ff99-e581-4a3f-8c91-c987fc2de80e','序賓亭','蔡襄','宋','宋诗','song-poetry','','[]','師律先憂寄，朝家此得人。',240,'全唐诗/poet.song.22000.json','["師律先憂寄，朝家此得人。", "門庭環劍佩，胸膽貫星辰。", "今已閒戎略，疇能卜宴申。", "樓高休暇日，臺逈厭登春。", "珍館瑶甍舉，璇題寶篆新。", "鴨欄迴鬭頸，龍壁活盤鱗。", "夾幕寒波顫，前峰古黛皴。", "始知仙有路，盡恐世無塵。", "武馭來金虎，儒簪下石麟。", "機分榮辱主，觶序去留賓。", "揖讓盈三魄，雌雄競一神。", "氣橫飛客箭，歌協大夫蘋。", "萬古浮雲片，勞生斷梗身。", "即時懽未已，往事夢非真。", "席久疑枯海，琴幺似隔鄰。", "釭花明雨暮，甕酎壓霜晨。", "鴉動殘絲柳，鱸肥滑線蓴。", "晴霞上丹葉，熟粉護青筠。", "賦景呵吟筆，揮談密醉茵。", "流年祇容易，嘉會可因循。"]'),
('4b81b984-d844-4567-951b-b8e2230168c3','望春詞','蔡襄','宋','宋诗','song-poetry','','[]','霏霏細雨勒梅黄，一望春容十斷腸。',32,'全唐诗/poet.song.22000.json','["霏霏細雨勒梅黄，一望春容十斷腸。", "平蕪古柳青青遍，獨使潘郎兩鬢霜。"]'),
('f4a1a0a7-f468-4a04-b250-f044eabf0cf9','落花','蔡襄','宋','宋诗','song-poetry','','[]','何事蒼苔數點紅，曉來花片落春風。',32,'全唐诗/poet.song.22000.json','["何事蒼苔數點紅，曉來花片落春風。", "可憐春色兼花盡，今古此情無處窮。"]'),
('24015840-6990-4efd-b68f-4462ec06b251','耕園驛佛桑花','蔡襄','宋','宋诗','song-poetry','','[]','溪館初寒似早春，寒花相倚醉於人。',64,'全唐诗/poet.song.22000.json','["溪館初寒似早春，寒花相倚醉於人。", "可憐萬木彫零盡，獨見繁枝爛熳新。", "清艷夜霑雲表露，幽香時過轍中塵。", "名園不肯爭顔色，的的夭紅野水濱。"]'),
('31170962-4d86-42fb-9420-e7bd1554db14','溪行','蔡襄','宋','宋诗','song-poetry','','[]','秋色已寥落，清溪纔此行。',48,'全唐诗/poet.song.22000.json','["秋色已寥落，清溪纔此行。", "船移酒杯側，魚得鱠刀鳴。", "日色浮兼動，風痕滅又生。", "從知隠者趣，不獨傲榮名。"]'),
('60dd5bd8-ce9c-4b23-bbfe-8ff74e44bddf','淨衆院嘗荔支','蔡襄','宋','宋诗','song-poetry','','[]','霞樹珠林暑後新，直疑天意別留春。',32,'全唐诗/poet.song.22000.json','["霞樹珠林暑後新，直疑天意別留春。", "京華百世爭鮮貴，自是芳根著海濱。"]'),
('f447f3c5-4ac9-461b-aa1c-541a1add1c98','奉酬王知縣賞春不與以詩見贈','蔡襄','宋','宋诗','song-poetry','','[]','仙陬翠觀盡繁英，朱白相兼照眼明。',64,'全唐诗/poet.song.22000.json','["仙陬翠觀盡繁英，朱白相兼照眼明。", "池浸嵐光生晚碧，鳥驚人語斷春聲。", "談諧遽喜開懷久，骩骳終慙走筆成。", "佳致可能陶靖節，庭柯斜眄獨忘情。"]'),
('66f6e86b-637b-407d-bb58-e5984edd4803','喜弟及第','蔡襄','宋','宋诗','song-poetry','','[]','里閈高高祖德新，魯庭詩禮孟家鄰。',64,'全唐诗/poet.song.22000.json','["里閈高高祖德新，魯庭詩禮孟家鄰。", "連登桂籍青袍客，共拜萱堂白首親。", "倚國精誠明火玉，照人清節對霜筠。", "童襟開慧盈書館，漸喜芝蘭在處春。"]'),
('f0ea7fb2-bdc7-4a55-8483-f91ce67bc948','西郊','蔡襄','宋','宋诗','song-poetry','','[]','曉蓋西郊道，春光極太虛。',48,'全唐诗/poet.song.22000.json','["曉蓋西郊道，春光極太虛。", "村風香晚稻，溪日曝寒魚。", "雀噪饑鷹下，山空病木踈。", "歸期侵杪歲，友思望吾廬。"]'),
('661a1109-fff1-412a-b7d3-9efd7f140ee3','三月詣陳逋民','蔡襄','宋','宋诗','song-poetry','','[]','振衣凌曉色，霽野縱遊韁。',48,'全唐诗/poet.song.22000.json','["振衣凌曉色，霽野縱遊韁。", "莓潤溪雲重，春深山露香。", "林幽風更細，院靜日偏長。", "曾是天皇外，相從識酒鄉。"]'),
('fa8ee363-5d72-4903-87c5-50a1dbccf76b','次韻翠巖寺','蔡襄','宋','宋诗','song-poetry','','[]','攬蔓巖扃峻，交繩寶界平。',48,'全唐诗/poet.song.22000.json','["攬蔓巖扃峻，交繩寶界平。", "斜峰約雲勢，乾樹起秋聲。", "泉檻妨蛩響，霜樓助月明。", "冥筌兼灑落，警句一何清。"]'),
('134dd47d-3f6e-47ea-aa45-398c09ab5ce2','夏晚南墅','蔡襄','宋','宋诗','song-poetry','','[]','夏竹侍前楹，涼襟析舊酲。',48,'全唐诗/poet.song.22000.json','["夏竹侍前楹，涼襟析舊酲。", "疊雲封日茜，斜雨著虹明。", "魚動池開暈，蟬移樹減清。", "葭洲烟向暝，鳬鶩自相迎。"]'),
('5bb81a81-2c92-4f22-8f3b-b086012f0577','蕪陰樓上','蔡襄','宋','宋诗','song-poetry','','[]','野馬沈寒氣，神禽度細風。',48,'全唐诗/poet.song.22000.json','["野馬沈寒氣，神禽度細風。", "斷霞天共紫，斜日樹齊紅。", "山口橫虛釣，江隈跋遠艐。", "解窮千里目，爭奈思無窮。"]'),
('034cbb1e-9929-497b-9bbf-d1397c31df1c','杪秋湖上','蔡襄','宋','宋诗','song-poetry','','[]','舊暑侵涼已分銷，蕭疎丹樹見斜橋。',64,'全唐诗/poet.song.22000.json','["舊暑侵涼已分銷，蕭疎丹樹見斜橋。", "千千露竹全瀟灑，一一風蟬共寂寥。", "菰米熟汀來客燕，芡絲分水避歸橈。", "月魂未上東城角，誰向東城與下招。"]'),
('d851683d-abc7-4768-863f-1e166eb8df15','和陳殿丞南州新詠','蔡襄','宋','宋诗','song-poetry','','[]','寶坊高閣遍憑欄，曾是芳辰得未閒。',64,'全唐诗/poet.song.22000.json','["寶坊高閣遍憑欄，曾是芳辰得未閒。", "日上天容低接海，風輕湖底倒摇山。", "夜深佛火寒星外，春過人烟暗樹間。", "無意孤吟採幽致，異時行橐斷空還。"]'),
('f8e490ab-3ceb-47eb-a141-6812a31e4e9f','通源驛別顔茂才','蔡襄','宋','宋诗','song-poetry','','[]','躍馬東來不記時，酒醒寒色入征衣。',32,'全唐诗/poet.song.22000.json','["躍馬東來不記時，酒醒寒色入征衣。", "垂楊官道連天去，落日郵亭別我歸。"]'),
('7f7dd768-d243-4f40-828f-bebf8fbf77a0','陪尹子漸申安禮宿香山寺','蔡襄','宋','宋诗','song-poetry','','[]','二月已强半，尋春登石樓。',72,'全唐诗/poet.song.22000.json','["二月已强半，尋春登石樓。", "山光侵雨變，草色到雲休。", "歸鳥沈巖際，行人過樹頭。", "剝苔看石碣，因火認漁舟。", "漸夜灘聲惡，憑虛屋勢浮。", "乘閒卿自適，觴詠屬吾流。"]'),
('1987a65f-b093-4374-b1bc-b6467af354e8','正月四日','蔡襄','宋','宋诗','song-poetry','','[]','今朝纔見雪泥乾，日薄雲低又作寒。',32,'全唐诗/poet.song.22000.json','["今朝纔見雪泥乾，日薄雲低又作寒。", "家山千里何時到，溪上梅花正好看。"]'),
('2d6611ab-3169-452d-89cd-bfbc14592286','春曉','蔡襄','宋','宋诗','song-poetry','','[]','曈曈初日注窗明，窗外雛鶑乳燕聲。',32,'全唐诗/poet.song.22000.json','["曈曈初日注窗明，窗外雛鶑乳燕聲。", "東風氣味濃於酒，曉夢魔人似宿酲。"]'),
('35d0c139-682f-4a02-ba1e-8a64fbf04ce7','晚色','蔡襄','宋','宋诗','song-poetry','','[]','晚色在何處，樓高天宇低。',24,'全唐诗/poet.song.22000.json','["晚色在何處，樓高天宇低。", "閒雲無去住，歸燕自東西。"]'),
('e6325ec6-cf88-4df9-b5d0-c08d40d9b786','過天津橋','蔡襄','宋','宋诗','song-poetry','','[]','日暖溪平冰漸銷，水聲纔下內前橋。',64,'全唐诗/poet.song.22000.json','["日暖溪平冰漸銷，水聲纔下內前橋。", "山川滿眼閒宮殿，草樹迷入舊市朝。", "每向尋春偏有意，却成懷古更無聊。", "洛陽平昔多豪俊，惆悵埋魂不可招。"]'),
('f017075f-ebad-4da3-aa85-b9e4d2e54fd1','讀離騷經','蔡襄','宋','宋诗','song-poetry','','[]','莫怪靈均戀楚濱，可能臣子外君親。',64,'全唐诗/poet.song.22000.json','["莫怪靈均戀楚濱，可能臣子外君親。", "精心獨去珠無纇，飛語潛來箭有神。", "宋玉招魂推意遠，揚雄流涕掩書頻。", "江邊自是修門路，嗟苦先生隕此身。"]'),
('68729642-7316-4b2e-af98-1a7c7acb5678','暮春登南門','蔡襄','宋','宋诗','song-poetry','','[]','麗譙高倚晚天霞，滿目平臯盡物華。',64,'全唐诗/poet.song.22000.json','["麗譙高倚晚天霞，滿目平臯盡物華。", "千曲胡笳催鼓答，三重湘酎倩旗誇。", "連江急雨送歸燕，拂地輕風移落花。", "强倚欄干還自問，此情何處是邊涯。"]'),
('71ea536c-b0fe-47fc-a553-7ca248484af3','和邱提刑寄湖南賈度支','蔡襄','宋','宋诗','song-poetry','','[]','何處多離感，山郵霽野光。',48,'全唐诗/poet.song.22000.json','["何處多離感，山郵霽野光。", "清吟貫騷雅，遠意屬荆湘。", "霜樹呈秋色，風蘭生晚香。", "使軺偏倚望，摛藻寄回腸。"]'),
('004d4c95-6148-4c6e-96bc-dee33756e4d7','和邱提刑聞新鴈寄賈度支','蔡襄','宋','宋诗','song-poetry','','[]','翔鴈來江渚，秋容在遠空。',48,'全唐诗/poet.song.22000.json','["翔鴈來江渚，秋容在遠空。", "幾聲疎樹外，一字斷雲中。", "虛館垂簷月，平臯敗葉風。", "裁詩託幽思，幽思更無窮。"]'),
('3b73a283-0e22-4465-a63a-87e8bca00351','遊龍門香山寺','蔡襄','宋','宋诗','song-poetry','','[]','彩閣縈林轉，蒼崖隔水開。',72,'全唐诗/poet.song.22000.json','["彩閣縈林轉，蒼崖隔水開。", "龕明千像日，波起一灘雷。", "綠淺春前草，香餘臘後梅。", "背人驚鷺去，將雨好風來。", "雲氣隨衣袂，嵐光入酒杯。", "清遊知不屢，欲下更徘徊。"]'),
('6be7a034-9ff7-40fd-baf8-8ab5f5dc4d57','聞福昌院春日一川花卉最盛  其一','蔡襄','宋','宋诗','song-poetry','','[]','聞道春深多物華，遥憐春日思無涯。',64,'全唐诗/poet.song.22000.json','["聞道春深多物華，遥憐春日思無涯。", "烟涵樹色相依好，山擁溪流一带斜。", "休問主人先看竹，只隨漁叟便逢花。", "憑誰畫得當時境，持去江南細與誇。"]'),
('30816fb6-3316-4a3f-bc03-769ab675950e','聞福昌院春日一川花卉最盛  其二','蔡襄','宋','宋诗','song-poetry','','[]','山前溪上最宜春，千樹夭桃一雨新。',32,'全唐诗/poet.song.22000.json','["山前溪上最宜春，千樹夭桃一雨新。", "爭得扁舟隨水去，亂花深處問秦人。"]'),
('4ad9264f-f789-46ba-9604-38e657102797','登府店福昌山閣','蔡襄','宋','宋诗','song-poetry','','[]','危磴通高閣，登臨境迥清。',72,'全唐诗/poet.song.22000.json','["危磴通高閣，登臨境迥清。", "雲開千岫出，雪霽一川明。", "斷雁來孤影，遥泉落細聲。", "野烟依竹見，溪樹與橋平。", "已助騷人思，空摇遠客情。", "扁舟如可泛，歷歷是江程。"]'),
('f1a92fdc-bc81-4f96-b76f-765c37577796','雪中不見女几山','蔡襄','宋','宋诗','song-poetry','','[]','宜陽南路是仙山，雪擁雲埋杳靄間。',32,'全唐诗/poet.song.22000.json','["宜陽南路是仙山，雪擁雲埋杳靄間。", "洗眼來看無處覓，不知可復在塵寰。"]'),
('330a708b-c2a6-4227-a06f-be8ab6862ca8','登三鄉寺閣','蔡襄','宋','宋诗','song-poetry','','[]','歷覽宜陽道，披軒臨朔風。',72,'全唐诗/poet.song.22000.json','["歷覽宜陽道，披軒臨朔風。", "地疑塵世外，人盡畫圖中。", "巖曲疎鐘答，村前小彴通。", "水烟寒更白，山氣曉微紅。", "遊宦真浮梗，流年似轉蓬。", "長懷無所寄，盡日送歸鴻。"]'),
('69819c06-4efd-4773-9bb7-afcc9dae442b','嵩陽道中','蔡襄','宋','宋诗','song-poetry','','[]','千里動秋意，縈迴上古原。',48,'全唐诗/poet.song.22000.json','["千里動秋意，縈迴上古原。", "山樵斵晚日，野火著寒雲。", "鐘磬出鄰寺，牛羊下過村。", "振衣歸去好，塵事莫知聞。"]'),
('561118f1-c678-4957-b63a-7f62384d7946','訪陳處士','蔡襄','宋','宋诗','song-poetry','','[]','橋畔修篁下碧溪，君家元在此橋西。',32,'全唐诗/poet.song.22000.json','["橋畔修篁下碧溪，君家元在此橋西。", "來時不似人間世，日暖花香山鳥啼。"]'),
('55a6f43d-cf45-4961-8377-7b8fb62f5906','題建造寺奉先院','蔡襄','宋','宋诗','song-poetry','','[]','日照溪山生翠光，春深花草雜幽香。',32,'全唐诗/poet.song.22000.json','["日照溪山生翠光，春深花草雜幽香。", "登臨誰會遲留意，門外塵埃去路長。"]'),
('49465686-1f47-4782-b415-6348219c0068','送別陳比部','蔡襄','宋','宋诗','song-poetry','','[]','祖帳西郊道，川原畫閣臨。',48,'全唐诗/poet.song.22000.json','["祖帳西郊道，川原畫閣臨。", "燒痕經雨活，樹色入溪深。", "斜日有春態，孤雲感客心。", "何人知別意，重把酒杯斟。"]'),
('e6f9e706-36f4-47ad-98c5-d6cfb78942f7','城西金明池小飲二首  其一','蔡襄','宋','宋诗','song-poetry','','[]','曉出都門外，名園連翠屏。',48,'全唐诗/poet.song.22000.json','["曉出都門外，名園連翠屏。", "融怡春物動，瀟灑塵慮醒。", "輕風送花信，遠水涵空青。", "舊遊無處問，芳樹隔重扃。"]'),
('0fa91454-5aaa-4b97-b0e9-c32eacc23d59','城西金明池小飲二首  其二','蔡襄','宋','宋诗','song-poetry','','[]','城西禁籞宿烟收，霜薄朝寒上罽裘。',64,'全唐诗/poet.song.22000.json','["城西禁籞宿烟收，霜薄朝寒上罽裘。", "佳樹得春生意動，平池受日翠光浮。", "十年歌笑驚前世，滿眼風花是舊遊。", "從此曲江芳物好，定知重到更疑留。"]'),
('f8f70e71-478c-47bf-be94-c104eab5f0f0','送張太傅還鄉','蔡襄','宋','宋诗','song-poetry','','[]','置器功成佚退身，故園南望整車茵。',96,'全唐诗/poet.song.22000.json','["置器功成佚退身，故園南望整車茵。", "青冥直上無餘事，白首歸來有幾人。", "門外離筵晴日曉，江邊行路雜花春。", "橐金均散心如水，冢樹重攀淚滿巾。", "盃酒相逢耆舊少，山川不改歲華新。", "從公几杖何由去，更祝千年比大椿。"]'),
('37767e4b-a510-4f04-9b2e-9f3b1da4d4fc','寒食樂詞','蔡襄','宋','宋诗','song-poetry','','[]','皇州令節已藏烟，帝渥乘時錫廣筵。',64,'全唐诗/poet.song.22000.json','["皇州令節已藏烟，帝渥乘時錫廣筵。", "和氣去添春色重，恩光來助日華鮮。", "千聲鳳吹朱門裏，一番花香穀雨前。", "更喜簪裳嘉宴日，親逢干羽治平年。"]'),
('06b4d92d-6d7c-423f-bf4e-77e0d2fe9f41','喜歐陽永叔余安道王仲儀除諫官','蔡襄','宋','宋诗','song-poetry','','[]','御筆新除三諫官，士民千口盡相歡。',64,'全唐诗/poet.song.22000.json','["御筆新除三諫官，士民千口盡相歡。", "昔時流落丹心在，自古忠賢得路難。", "好竭謀猷居帝右，直須風采動朝端。", "人生萬事皆塵土，惟是功名永遠看。"]'),
('a7aed28f-56d1-4f05-9e71-c79a80778c61','送楊殿丞通判睦州','蔡襄','宋','宋诗','song-poetry','','[]','蒼崖中斷一溪來，迤邐人家向水開。',64,'全唐诗/poet.song.22000.json','["蒼崖中斷一溪來，迤邐人家向水開。", "盡日烟雲迎旆去，滿瀧鐃吹引船迴。", "虛齋晝夢鳴禽下，別塢春遊畫角催。", "莫怪杜郎題處少，更留佳致待清才。"]'),
('ef51dee9-dfc5-401e-b1e4-42572d02d508','宿揚州','蔡襄','宋','宋诗','song-poetry','','[]','瓜洲堰埭阻行橈，更等江頭後信潮。',32,'全唐诗/poet.song.22000.json','["瓜洲堰埭阻行橈，更等江頭後信潮。", "獨背殘燈數歸路，風傳寒柝夜迢迢。"]'),
('6659e0df-9fa4-4833-baff-3366befcc041','廣陵','蔡襄','宋','宋诗','song-poetry','','[]','廣陵歸客嘆飛蓬，懷古傷離向此中。',64,'全唐诗/poet.song.22000.json','["廣陵歸客嘆飛蓬，懷古傷離向此中。", "前世翻波那復問，十年彈指已成空。", "樓頭畫角催殘日，城上寒鴉噪晚風。", "井徑蕭條人不見，又隨潮信度江東。"]'),
('e591de58-48b5-490b-ad75-0f4604f319a1','馬奴周晬思之因成','蔡襄','宋','宋诗','song-poetry','','[]','馬奴今日方周晬，昨夜迢遥夢到家。',64,'全唐诗/poet.song.22000.json','["馬奴今日方周晬，昨夜迢遥夢到家。", "盤裏應知心所愛，尊前唯祝壽無涯。", "吚嚘弄語羣兒學，踉蹌初行乳母誇。", "獨上揚州津館望，江山摇落去鴻斜。"]'),
('cee48c39-3ed7-462f-8fe1-3f8845d523c0','聞鴈','蔡襄','宋','宋诗','song-poetry','','[]','霜風吹鴈入南雲，千里征人枕上聞。',32,'全唐诗/poet.song.22000.json','["霜風吹鴈入南雲，千里征人枕上聞。", "欲問梁園近消息，月沈星轉五更分。"]'),
('a6f0ed97-f4f0-40ad-bd51-19d2c1135436','江頭別杜殿丞','蔡襄','宋','宋诗','song-poetry','','[]','揚子江頭南北路，木蘭船上往來人。',64,'全唐诗/poet.song.22000.json','["揚子江頭南北路，木蘭船上往來人。", "年華衮衮東流水，世事勞勞薄宦身。", "回首天涯成遠別，忘懷物外自相親。", "津亭共起憂時嘆，重記津亭淚滿巾。"]'),
('87b14c85-0a6e-411b-b85c-ff75f1f82a07','題金山寺','蔡襄','宋','宋诗','song-poetry','','[]','畫梁詩板暗流塵，水石魚龍萬句新。',32,'全唐诗/poet.song.22000.json','["畫梁詩板暗流塵，水石魚龍萬句新。", "誰識高僧最深意，慈航長護過江人。"]'),
('5d182672-fbb2-4846-a268-1d90302b933c','題僧希元禪隠堂','蔡襄','宋','宋诗','song-poetry','','[]','遊錫遍他方，歸休靜默堂。',48,'全唐诗/poet.song.22000.json','["遊錫遍他方，歸休靜默堂。", "孤吟時有得，諸念若爲忘。", "刪竹減庭翠，煮茶生野香。", "雲山莫騰誚，心地本清涼。"]'),
('4864cca5-8bfe-487b-adb7-82e2c3c07e89','經錢塘故宮','蔡襄','宋','宋诗','song-poetry','','[]','廢苑蕪城裹故宮，行人苑外問秋風。',64,'全唐诗/poet.song.22000.json','["廢苑蕪城裹故宮，行人苑外問秋風。", "當時歌舞何年盡，此意古今無處窮。", "往事蕭條隨敗葉，客情迢遞寄孤鴻。", "扁舟欲去更回首，寒樹蒼蒼夕照東。"]'),
('fddb8b15-8064-4bc5-b39d-6026132025db','經林逋舊居二首  其一','蔡襄','宋','宋诗','song-poetry','','["\u897f\u6e56"]','修竹無多宅一區，先生曾此隠西湖。',32,'全唐诗/poet.song.22000.json','["修竹無多宅一區，先生曾此隠西湖。", "詩言不喜書封禪，亦有餘書補世無。"]'),
('fce528c3-b1c5-413b-98dd-e1c1cf1ca220','經林逋舊居二首  其二','蔡襄','宋','宋诗','song-poetry','','[]','山色凝嵐水色清，山雲長與水雲平。',32,'全唐诗/poet.song.22000.json','["山色凝嵐水色清，山雲長與水雲平。", "先生來舉持竿手，釣得人間亢俗名。"]'),
('372a6405-4c41-415e-b2b3-56dc1259d552','離錢塘','蔡襄','宋','宋诗','song-poetry','','[]','迎潮小舸滿旗風，迴首津亭暮靄中。',32,'全唐诗/poet.song.22000.json','["迎潮小舸滿旗風，迴首津亭暮靄中。", "惆悵今宵歸去夢，迢迢直至海門東。"]'),
('239178b2-d0b1-42a2-91f1-cb588d77b105','至睦州','蔡襄','宋','宋诗','song-poetry','','[]','一带滄波兩面山，扁舟中去幾時還。',32,'全唐诗/poet.song.22000.json','["一带滄波兩面山，扁舟中去幾時還。", "浮生多半在離別，此意明知未肯閒。"]'),
('2786ed71-5705-4639-a8a3-b86f2d0ce8ab','題杉溪驛二首  其一','蔡襄','宋','宋诗','song-poetry','','[]','宵行避酷暑，山路乍縈迴。',48,'全唐诗/poet.song.22000.json','["宵行避酷暑，山路乍縈迴。", "明月正相向，涼風時一來。", "幽林潛物怪，祕洞蓄雲雷。", "豈敢憚勞苦，畏途誠可猜。"]'),
('a89bca4e-59bc-4ec2-9c86-59b58babb0bc','題杉溪驛二首  其二','蔡襄','宋','宋诗','song-poetry','','[]','隘道臨深壑，俯闌千仞强。',48,'全唐诗/poet.song.22000.json','["隘道臨深壑，俯闌千仞强。", "驚禽忽獨去，怪石偶成行。", "月下芙蕖色，風前䆉䅉香。", "反慙羣動息，幽意更徬徨。"]'),
('73dc489d-eedf-44d9-858f-aa7b0343a10a','宿延平津','蔡襄','宋','宋诗','song-poetry','','[]','鳴籟蕭森萬木聲，濃嵐環合亂峯青。',64,'全唐诗/poet.song.22000.json','["鳴籟蕭森萬木聲，濃嵐環合亂峯青。", "樓臺矗處雙溪會，雷電交時一劍靈。", "曉市人煙披霽旭，夜潭漁火鬭寒星。", "畫屏曾指孤舟看，今日孤舟在畫屏。"]'),
('9764ae5e-59cd-403a-8210-a85a12354a37','呈沈子山  其一','蔡襄','宋','宋诗','song-poetry','','[]','荷葉新詞天下工，玉人垂手倚秋風。',32,'全唐诗/poet.song.22000.json','["荷葉新詞天下工，玉人垂手倚秋風。", "一聲清唱穿雲去，斜日烘簾曲未終。"]'),
('26945b6d-af3b-4845-9d6e-3c785af68d01','呈沈子山  其二','蔡襄','宋','宋诗','song-poetry','','[]','六月閩溪荔子丹，新秋猶喜薦雕盤。',32,'全唐诗/poet.song.22000.json','["六月閩溪荔子丹，新秋猶喜薦雕盤。", "自嗟千里歸程遠，不得繁枝雨後看。"]'),
('71e62330-c08c-42a6-bf56-865bbd6c5f3b','題福州釋迦院幽幽亭','蔡襄','宋','宋诗','song-poetry','','[]','路盡得佳賞，川原何凈明。',120,'全唐诗/poet.song.22000.json','["路盡得佳賞，川原何凈明。", "周圍地形壯，灑落世塵清。", "背郭千峰起，涵空一水橫。", "風帆人共遠，潮嶼歲重耕。", "曉市炊烟合，孤庵汲道縈。", "俯窺巖鳥過，微認野雲生。", "香氣林端出，秋容物外呈。", "表閒幡弄影，覺靜磬傳聲。", "官舍今稀訟，轓車此駐行。", "唱篇知寡和，君世負詩名。"]'),
('614385a4-102e-40a4-8d81-e7547d98bfa9','題漁溪驛','蔡襄','宋','宋诗','song-poetry','','[]','昔年同向臘中迴，曾遶欄干折早梅。',32,'全唐诗/poet.song.22000.json','["昔年同向臘中迴，曾遶欄干折早梅。", "今日獨來攀舊樹，風翻黄葉下蒼苔。"]'),
('b92e3962-9211-4d16-8e4f-9e3940b311ea','晚上碧峯亭','蔡襄','宋','宋诗','song-poetry','','[]','城頭近晚忽開晴，有色皆鮮是物清。',64,'全唐诗/poet.song.22000.json','["城頭近晚忽開晴，有色皆鮮是物清。", "地勢四來州午向，山圍一罅水東行。", "乘風歌吹無時已，面日樓臺觸處明。", "不比兒曹誇衣錦，自緣恩與養親榮。"]'),
('4e5c9710-eba8-45de-ab9e-4fcf3532e3ff','春潮','蔡襄','宋','宋诗','song-poetry','','[]','納納春潮草際生，商船鳴樐趁潮行。',32,'全唐诗/poet.song.22000.json','["納納春潮草際生，商船鳴樐趁潮行。", "封書欲寄天涯意，海水風濤不計程。"]'),
('044b4455-e984-4341-ac0b-32da84b9bad4','病中偶書二首  其一','蔡襄','宋','宋诗','song-poetry','','[]','已感節候變，物態舒陽春。',48,'全唐诗/poet.song.22000.json','["已感節候變，物態舒陽春。", "那復壯年意，如今多病身。", "凈室焚香久，烘爐煮藥頻。", "神歡百慮解，銷盡眼前塵。"]'),
('e9df1197-feea-4dfd-a1c3-67a7a92c07dd','病中偶書二首  其二','蔡襄','宋','宋诗','song-poetry','','[]','行年三十六，幾是半生人。',48,'全唐诗/poet.song.22000.json','["行年三十六，幾是半生人。", "舉止不入俗，清修難厭貧。", "宴坐爐烟暖，微醺甕酎醇。", "前看簫管輩，未免作埃塵。"]'),
('c212fc6b-a11a-477e-87ff-0ce1a854d6ec','和王介夫遊西禪兼呈黄承制','蔡襄','宋','宋诗','song-poetry','','[]','山城只有四圍青，海國都無一點塵。',64,'全唐诗/poet.song.22000.json','["山城只有四圍青，海國都無一點塵。", "荔子風標全占夏，荷花顔色未饒春。", "水邊清吹傳觴久，路上殘陽立馬頻。", "不是閒來誇景物，欲將謠俗寄王人。"]'),
('e2ea3973-5d8f-4a5b-9cb6-58bb67223080','興化軍曹殿丞寄荔支','蔡襄','宋','宋诗','song-poetry','','[]','厚葉先枝新絳囊，使君分寄驛人忙。',64,'全唐诗/poet.song.22000.json','["厚葉先枝新絳囊，使君分寄驛人忙。", "彩毫封處曾留意，筠籠開時不見香。", "風色甚豪應少損，路程差近得分嘗。", "閩州縱有千千樹，未抵家園氣味長。"]'),
('89f54004-1406-489c-ab50-3d98aa9a43aa','和曹殿丞寄荔支','蔡襄','宋','宋诗','song-poetry','','[]','荔子凝丹摘曉鮮，江南來路與雲連。',64,'全唐诗/poet.song.22000.json','["荔子凝丹摘曉鮮，江南來路與雲連。", "託根曾是三山下，結實應歸萬木先。", "鄉國遠携甘旨重，宴堂分翫色香全。", "清才仍更傳新唱，一一驪珠照眼圖。"]'),
('7afea15b-d854-407b-b5b2-8254a3540bcd','飲薛老亭晚歸','蔡襄','宋','宋诗','song-poetry','','[]','終日行山不出城，城中山勢與雲平。',64,'全唐诗/poet.song.22000.json','["終日行山不出城，城中山勢與雲平。", "萬家市井魚鹽合，千里川原彩畫明。", "坐上潮風醒酒力，晚來巖霧蓋鐘聲。", "歸時休更燃官燭，在處紗燈夾道迎。"]'),
('63246baa-e0b0-4bd5-9941-2e663f8b198d','和許寺丞泊釣龍臺見寄','蔡襄','宋','宋诗','song-poetry','','[]','釣龍臺下艤行橈，獵獵船旗待晚潮。',64,'全唐诗/poet.song.22000.json','["釣龍臺下艤行橈，獵獵船旗待晚潮。", "萬里征人應悵望，一川秋色正蕭條。", "雨雲來去山明滅，風浪高低日動摇。", "有志四方男子事，莫懷鄉國便魂銷。"]'),
('7e53fc77-a6c3-4499-9910-40ecc3f2dc18','十一月後庭梅花盛開  其一','蔡襄','宋','宋诗','song-poetry','','[]','迎臘梅花無數開，旋看飛片點青苔。',32,'全唐诗/poet.song.22000.json','["迎臘梅花無數開，旋看飛片點青苔。", "幽香粉艷誰人見，時有山禽入樹來。"]'),
('f295a671-5a8f-4ab1-a3c5-ac6c9569bd0d','十一月後庭梅花盛開  其二','蔡襄','宋','宋诗','song-poetry','','[]','日暖香繁已盛開，開時曾遶百千迴。',32,'全唐诗/poet.song.22000.json','["日暖香繁已盛開，開時曾遶百千迴。", "春風豈是多情思，相伴花前去又來。"]'),
('513e560f-4ced-4c00-92f7-aaf18dd79a00','發篋得亡友書札','蔡襄','宋','宋诗','song-poetry','','[]','宿昔重交義，零落今誰存。',48,'全唐诗/poet.song.22000.json','["宿昔重交義，零落今誰存。", "舊情留紙札，永恨入丘墳。", "世味薄於水，生涯空似雲。", "撫孤無力及，流淚復何言。"]'),
('9f4d9563-4139-4a45-9b19-1bb134daeefe','寄答汝州王仲儀待制','蔡襄','宋','宋诗','song-poetry','','[]','汝水閩山道路長，行郵時復寄新章。',64,'全唐诗/poet.song.22000.json','["汝水閩山道路長，行郵時復寄新章。", "諫垣笑別三年近，病枕魂飛萬里强。", "烈火未應焚玉石，埋輪曾是問豺狼。", "主恩未報頭生白，羞見龍泉百鍊鋼。"]'),
('75f84469-5651-4701-86cf-b1e3e41e8ef7','正月十八日廿棠院  其一','蔡襄','宋','宋诗','song-poetry','','[]','上元纔過去尋春，紅白山花粲粲新。',32,'全唐诗/poet.song.22000.json','["上元纔過去尋春，紅白山花粲粲新。", "似喜使君初病起，隔欄相向笑迎人。"]'),
('81543c4c-751d-4e3b-bc82-4cb2cbea15af','正月十八日廿棠院  其二','蔡襄','宋','宋诗','song-poetry','','[]','天氣和柔酒更醇，緩歌花底正青春。',32,'全唐诗/poet.song.22000.json','["天氣和柔酒更醇，緩歌花底正青春。", "狂花有意憐醉客，撩亂飛紅滿一身。"]'),
('6299f050-da02-4b1a-914f-d996ae581ec9','正月十八日廿棠院  其三','蔡襄','宋','宋诗','song-poetry','','[]','無奈閒情著物歡，更愁花草便闌珊。',32,'全唐诗/poet.song.22000.json','["無奈閒情著物歡，更愁花草便闌珊。", "夭紅嫩翠宜燈燭，放散笙歌靜裏看。"]'),
('63014c03-7646-4f3b-9f9f-cd7eeff3c631','福州寧越門外石橋看西山晚照','蔡襄','宋','宋诗','song-poetry','','[]','寧越門前路，歸鞍駐石梁。',24,'全唐诗/poet.song.22000.json','["寧越門前路，歸鞍駐石梁。", "西山氣色好，晚日正相當。"]'),
('73a94114-848b-44fc-a070-a3d0b1604081','夢遊洛中十首  其一','蔡襄','宋','宋诗','song-poetry','','[]','天際烏雲含雨重，樓前紅日照山明。',32,'全唐诗/poet.song.22000.json','["天際烏雲含雨重，樓前紅日照山明。", "嵩陽居士今安否，青眼看人萬里情。"]'),
('4be7e0e5-f2ae-4c1a-9c8e-326f784530b6','夢遊洛中十首  其二','蔡襄','宋','宋诗','song-poetry','','[]','修竹蕭蕭曲檻前，清泉㶁㶁小池邊。',32,'全唐诗/poet.song.22000.json','["修竹蕭蕭曲檻前，清泉㶁㶁小池邊。", "琴中一弄履霜操，人靜當庭月正圓。"]'),
('333340b1-ae4c-4fdb-97cf-7980ff5ba451','夢遊洛中十首  其三','蔡襄','宋','宋诗','song-poetry','','[]','過雨池塘涼氣早，落花門戶亂紅多。',32,'全唐诗/poet.song.22000.json','["過雨池塘涼氣早，落花門戶亂紅多。", "松亭石上題名處，誰剝莓苔看在麽。"]'),
('1048f550-a98d-4485-8294-daecbd980cba','夢遊洛中十首  其四','蔡襄','宋','宋诗','song-poetry','','[]','廟下春行香霧合，觀中朝茹藥牙尖。',32,'全唐诗/poet.song.22000.json','["廟下春行香霧合，觀中朝茹藥牙尖。", "故人別後無消息，茺草生墳白露霑。"]'),
('bdb29b09-a299-4660-8e3a-1e25b189bcd6','夢遊洛中十首  其五','蔡襄','宋','宋诗','song-poetry','','[]','霜後丹楓照曲堤，酒闌明月下前溪。',32,'全唐诗/poet.song.22000.json','["霜後丹楓照曲堤，酒闌明月下前溪。", "石樓夜半雲中笑，驚起沙禽過水西。"]'),
('477e887a-6141-4cf1-8845-b7888dc65baa','夢遊洛中十首  其六','蔡襄','宋','宋诗','song-poetry','','[]','韓王宅裏酒千壚，范帥園中花萬株。',32,'全唐诗/poet.song.22000.json','["韓王宅裏酒千壚，范帥園中花萬株。", "行樂主人今已矣，春風還似舊時無。"]'),
('1b7b5523-a603-4f47-938b-630cf37862eb','夢遊洛中十首  其七','蔡襄','宋','宋诗','song-poetry','','[]','名花百種結春芳，天與穠華更與香。',32,'全唐诗/poet.song.22000.json','["名花百種結春芳，天與穠華更與香。", "每憶月陂隄下路，便開圖畫覓姚黄。"]'),
('0c471581-a856-4020-b9d1-7569d68c906a','夢遊洛中十首  其八','蔡襄','宋','宋诗','song-poetry','','[]','草白霜晴鶻睛開，原頭遊騎四邊來。',32,'全唐诗/poet.song.22000.json','["草白霜晴鶻睛開，原頭遊騎四邊來。", "枯叢鴉鵲休驚噪，日暮分持走兔迴。"]'),
('52fc4b04-c741-4e7c-a594-f080ddbb48fe','夢遊洛中十首  其九','蔡襄','宋','宋诗','song-poetry','','[]','履道園池竹萬竿，竹間池際笋斑斕。',32,'全唐诗/poet.song.22000.json','["履道園池竹萬竿，竹間池際笋斑斕。", "當時酒所誇文戰，今日誰登上將壇。"]'),
('e4e10460-0ebc-4cc0-9791-989af809887c','夢遊洛中十首  其一○','蔡襄','宋','宋诗','song-poetry','','[]','白馬寺前冠蓋盛，送行賓友盡英豪。',32,'全唐诗/poet.song.22000.json','["白馬寺前冠蓋盛，送行賓友盡英豪。", "耿丞血染邊場草，留得聲名日月高。"]'),
('ec3e5475-0a50-49e7-b3e2-fe71ef0a4d19','題何山人大隠閣','蔡襄','宋','宋诗','song-poetry','','[]','萬井連交道，中天敞靜軒。',120,'全唐诗/poet.song.22000.json','["萬井連交道，中天敞靜軒。", "由來隠鄽市，全勝賁丘園。", "目極無留賞，心閒不避喧。", "沼光摇屋動，花艷出欄繁。", "雨霽山容靜，潮生海氣昏。", "幽人披彩檻，永日對芳樽。", "素業名家久，通醫與義存。", "丹圖環八卦，仙訣遁三元。", "造化今爲友，懽憂本聚門。", "應須超世累，宴坐此忘言。"]'),
('a1be6f49-e2ff-4b91-8c6c-922f5e26e59e','正月巡歷部郡侍親還家','蔡襄','宋','宋诗','song-poetry','','[]','養親方解郡，奉使又還家。',48,'全唐诗/poet.song.22000.json','["養親方解郡，奉使又還家。", "遠岫鄉關近，前旌父老遮。", "揮金貧自愧，舞綵喜仍誇。", "特地延賓友，相期詠白華。"]'),
('ea69e38b-f603-4816-b9fc-016e17f85b08','方山渡口占','蔡襄','宋','宋诗','song-poetry','','[]','江上行人空自愁，壯年雙鬢已驚秋。',32,'全唐诗/poet.song.22000.json','["江上行人空自愁，壯年雙鬢已驚秋。", "不知風裏千重浪，何事無情也白頭。"]'),
('37920260-501c-498c-9ee3-545966332665','江村','蔡襄','宋','宋诗','song-poetry','','[]','黯澹江村春日斜，汀洲芳草野田花。',32,'全唐诗/poet.song.22000.json','["黯澹江村春日斜，汀洲芳草野田花。", "孤舟橫笛向何處，竹外炊煙一兩家。"]'),
('0f7e890c-bbfe-4295-b007-c4e29b69591b','三月再還家','蔡襄','宋','宋诗','song-poetry','','[]','曉樹鄉關路，春衣使者軺。',48,'全唐诗/poet.song.22000.json','["曉樹鄉關路，春衣使者軺。", "江眠聞落霰，野飯掇新苗。", "入里威稜減，寧親喜氣饒。", "勤勤父師教，民病若爲消。"]'),
('ccfaba81-b845-49d4-960d-2ea4f7852671','宿海邊寺','蔡襄','宋','宋诗','song-poetry','','[]','潮頭欲上風先至，海面初明日近來。',32,'全唐诗/poet.song.22000.json','["潮頭欲上風先至，海面初明日近來。", "怪得寺南多語笑，蜑船爭送早魚迴。"]'),
('eced7281-6f0e-431a-848e-8e6488b4fb66','建溪桃花','蔡襄','宋','宋诗','song-poetry','','[]','何物山桃不自羞，欲乘風力占溪流。',32,'全唐诗/poet.song.22000.json','["何物山桃不自羞，欲乘風力占溪流。", "仙源明有重來路，莫下橫波礙客舟。"]'),
('fad401db-7ad7-4177-9e5a-555cf5fecbd9','吳屯驛曉起','蔡襄','宋','宋诗','song-poetry','','[]','殘月依山明朧{月悤}，長煙浮水白糢胡。',67,'全唐诗/poet.song.22000.json','["殘月依山明朧{月悤}，長煙浮水白糢胡。", "竹林繞舍啼鴉臼，石井當窗下轆轤。", "迎吏遠傳空狀小，僕奴潜報一錢無。", "騶兵不管晨炊絕，呵叫蓯籠意氣麤。"]'),
('17da11cf-fdb0-4489-ad7a-de14afc3f5d0','王臺驛見晚李花有感','蔡襄','宋','宋诗','song-poetry','','[]','玉京仙子愛春芳，弄遍瓊枝嗅盡香。',32,'全唐诗/poet.song.22000.json','["玉京仙子愛春芳，弄遍瓊枝嗅盡香。", "祗有此花知舊意，又隨風色過東牆。"]'),
('b14c2240-db27-46b3-901e-255c04bb1839','晝寢宴坐軒憶與蘇才翁會別','蔡襄','宋','宋诗','song-poetry','','[]','投涼下馬卧僧家，遶簟清風卷絳紗。',64,'全唐诗/poet.song.22000.json','["投涼下馬卧僧家，遶簟清風卷絳紗。", "修竹滿前微雨過，遠山無際薄雲遮。", "武侯奮隠人應到，閩粵孤城日自斜。", "解與塵心消百事，更開新焙煮靈芽。"]'),
('55a5e03e-8038-4761-9271-1ee28c92210f','漳州白蓮僧宗要見遺紙扇每扇各書一首  其一','蔡襄','宋','宋诗','song-poetry','','[]','山僧遺我白紙扇，入手輕快清風多。',32,'全唐诗/poet.song.22000.json','["山僧遺我白紙扇，入手輕快清風多。", "物無大小貴適用，何必吳綾與蜀羅。"]'),
('36c0ac98-7155-42e5-ae47-f82335ca0685','漳州白蓮僧宗要見遺紙扇每扇各書一首  其二','蔡襄','宋','宋诗','song-poetry','','[]','野老尋山翦白雲，欲將清吹助南薰。',32,'全唐诗/poet.song.22000.json','["野老尋山翦白雲，欲將清吹助南薰。", "不堪便面張京兆，恰稱能書王右軍。"]'),
('708ccbb7-4db5-45d2-a2f8-476f6ca56ad9','漳州白蓮僧宗要見遺紙扇每扇各書一首  其三','蔡襄','宋','宋诗','song-poetry','','[]','徑尺規圓比雪霜，昔人何事恨秋涼。',32,'全唐诗/poet.song.22000.json','["徑尺規圓比雪霜，昔人何事恨秋涼。", "珍藏篋笥未爲失，更有明年夏日長。"]'),
('07f0e3c7-d801-4090-bf8a-40425cbd60aa','漳州白蓮僧宗要見遺紙扇每扇各書一首  其四','蔡襄','宋','宋诗','song-poetry','','[]','武侯白羽麾三軍，帳前甲馬生風雲。',32,'全唐诗/poet.song.22000.json','["武侯白羽麾三軍，帳前甲馬生風雲。", "憐君才地亦疎薄，相過書林至夜分。"]'),
('858a1d69-8963-426c-a78b-0e967d060e63','漳州白蓮僧宗要見遺紙扇每扇各書一首  其五','蔡襄','宋','宋诗','song-poetry','','[]','薄似蒲葵質更圓，忽疑明月落尊前。',32,'全唐诗/poet.song.22000.json','["薄似蒲葵質更圓，忽疑明月落尊前。", "南堂暑氣生煩濁，一座清涼直幾錢。"]'),
('7b23f519-5c6e-4382-85d9-bd5d06a39b5b','漳州白蓮僧宗要見遺紙扇每扇各書一首  其六','蔡襄','宋','宋诗','song-poetry','','[]','滉白新牋卷線稜，刮青纖竹纏紅藤。',32,'全唐诗/poet.song.22000.json','["滉白新牋卷線稜，刮青纖竹纏紅藤。", "可憐子夜書帷下，一片圓光得未曾。"]'),
('00a5ca36-f72c-44a8-894d-925afa7dc69f','漳州白蓮僧宗要見遺紙扇每扇各書一首  其七','蔡襄','宋','宋诗','song-poetry','','[]','堂陰壁罅蚊蚋都，指麾西向先驅除。',32,'全唐诗/poet.song.22000.json','["堂陰壁罅蚊蚋都，指麾西向先驅除。", "山翁一夜穩眠睡，若或論功誰勝渠。"]'),
('93005715-9c70-4794-8f67-bb1c82c88cbb','漳州白蓮僧宗要見遺紙扇每扇各書一首  其八','蔡襄','宋','宋诗','song-poetry','','[]','老去將携只要輕，況臨炎暑遶風清。',32,'全唐诗/poet.song.22000.json','["老去將携只要輕，況臨炎暑遶風清。", "兒童愛把承簷溜，未識山家質素情。"]'),
('a2b40abe-f4da-45b0-b8f6-859357ba6950','漳州白蓮僧宗要見遺紙扇每扇各書一首  其九','蔡襄','宋','宋诗','song-poetry','','[]','不掩歌脣向畫堂，不須名筆作花房。',32,'全唐诗/poet.song.22000.json','["不掩歌脣向畫堂，不須名筆作花房。", "直應携去林泉好，轉覺林泉興味長。"]'),
('e81357ba-57c2-46c9-b795-ae55cf322e65','漳州白蓮僧宗要見遺紙扇每扇各書一首  其一○','蔡襄','宋','宋诗','song-poetry','','[]','虛堂永晝來風長，石枕竹簟寒生光。',32,'全唐诗/poet.song.22000.json','["虛堂永晝來風長，石枕竹簟寒生光。", "文園肺渴厭煩熱，更要夫君在側傍。"]'),
('744ca3d2-b5ec-4a65-b654-3a7aa72216d0','懷文雅儼上人','蔡襄','宋','宋诗','song-poetry','','[]','填填車馬走沙塵，中有伊人離俗氛。',64,'全唐诗/poet.song.22000.json','["填填車馬走沙塵，中有伊人離俗氛。", "千里不逢京下信，五年虛斷海邊魂。", "何窮世事秋林葉，自在心靈晚岫雲。", "聞道西堂今粹隠，暮鐘朝磬欲何云。"]'),
('dc25ed4a-83a0-46bf-90f1-3365048e709d','寄題處州朱山人幽居','蔡襄','宋','宋诗','song-poetry','','[]','之子適所遇，愛此山林居。',72,'全唐诗/poet.song.22000.json','["之子適所遇，愛此山林居。", "禪心庭下樹，仙訣枕中書。", "溪明暑醉後，洞暗春遊初。", "逢疴藥籙補，得意琴聲徐。", "人生隨樂住，世事與閒疎。", "勿用挂雲網，孤鴻翔太虛。"]'),
('34374c45-cbb2-4562-a423-3b7adc7ca60c','耕園驛','蔡襄','宋','宋诗','song-poetry','','[]','使軺迢遞到天涯，候館遷延感歲華。',64,'全唐诗/poet.song.22000.json','["使軺迢遞到天涯，候館遷延感歲華。", "白髮却攀臨砌樹，青條猶放過牆花。", "悲來唯見金城柳，醉後曾乘海客槎。", "欲問昔遊無處所，晚烟生水日沈沙。"]'),
('8c70bfde-650c-4146-a7bc-928755dcdf5a','題白蓮院東軒','蔡襄','宋','宋诗','song-poetry','','[]','昔年文酒自爲情，身外鴻毛萬事輕。',64,'全唐诗/poet.song.22000.json','["昔年文酒自爲情，身外鴻毛萬事輕。", "暑醉每憐風引夢，夜歸多見月隨行。", "重尋蘭若餘芳在，却怪桑門老態生。", "點數朋遊今有幾，拂塵看字淚先橫。"]'),
('4cf8076b-a40e-4f66-82b5-a9c1bd3e68d0','後舍緋桃','蔡襄','宋','宋诗','song-poetry','','[]','十年樹底折香葩，䔩䔩浮光弄曉霞。',32,'全唐诗/poet.song.22000.json','["十年樹底折香葩，䔩䔩浮光弄曉霞。", "只恨無情是風雨，直將紅片入西家。"]'),
('5b9d8bc8-c4ff-40f3-b7e5-f6f94975ff77','題龍紀院僧室','蔡襄','宋','宋诗','song-poetry','','[]','山僧九十五，行是百年人。',48,'全唐诗/poet.song.22000.json','["山僧九十五，行是百年人。", "焚香猶夜起，喜酒見天真。", "生平持戒定，老大有精神。", "須知不變者，那減故時新。"]'),
('edd0daf3-8e6f-44c9-8c9a-f683f1424fee','宿黄蘗聽彬長老譚禪','蔡襄','宋','宋诗','song-poetry','','[]','一圓靈寂本清真，誰向蒼浪更問津。',32,'全唐诗/poet.song.22000.json','["一圓靈寂本清真，誰向蒼浪更問津。", "欲說西來無見處，奈何言句亦前塵。"]'),
('c389fd1d-335e-4465-aa8d-c056f398f8ae','南劍州芋陽舖見臘月桃花','蔡襄','宋','宋诗','song-poetry','','[]','可笑夭桃耐雪風，山家牆外見疎紅。',32,'全唐诗/poet.song.22000.json','["可笑夭桃耐雪風，山家牆外見疎紅。", "爲君持酒一相向，生意雖殊寂寞同。"]'),
('46a7578c-aa6d-49a5-b3e8-9f81bd744c47','士安飲我數杯至觀音院纔醒聞灘聲泉響因留短闋','蔡襄','宋','宋诗','song-poetry','','[]','林外灘聲砌下泉，泠泠幽響靜中傳。',32,'全唐诗/poet.song.22000.json','["林外灘聲砌下泉，泠泠幽響靜中傳。", "朝衫却染京塵去，爭得夫君醒醉眠。"]'),
('43c6d5fd-ba4b-4482-a9e5-34a49c0b3f14','別邵武長史朱照鄰','蔡襄','宋','宋诗','song-poetry','','[]','竊比君侯病駃騠，時看雲路忽長嘶。',64,'全唐诗/poet.song.22000.json','["竊比君侯病駃騠，時看雲路忽長嘶。", "十年還此同不酒，三驛剛來踏雨泥。", "士行滿鄉元自好，官名當世不勝低。", "未霑釜粟榮新祿，應上亨衢別有梯。"]'),
('f8b2a1c6-af94-439c-b386-d177138eb97e','自漁梁驛至衢州大雪有懷','蔡襄','宋','宋诗','song-poetry','','[]','大雪迷空野，征人尚遠行。',120,'全唐诗/poet.song.22000.json','["大雪迷空野，征人尚遠行。", "乾坤初一色，晝夜忽通明。", "有物皆遷白，無塵頓覺清。", "只看流水在，却喜亂山平。", "逐絮飄飄起，投花點點輕。", "玉樓天上出，銀闕海中生。", "舞極摇溶態，聞餘淅瀝聲。", "客爐何暇暖，官酤未能醒。", "薄吹消春凍，新暘破曉晴。", "更登分界嶺，南望不勝情。"]'),
('52982157-2896-46c1-a80d-8e5bcc422fe4','華嚴院西軒見芍藥兩枝追想吉祥賞花慨然有感寄呈才翁  其一','蔡襄','宋','宋诗','song-poetry','','[]','吉祥亭下萬千枝，看盡將開欲落時。',32,'全唐诗/poet.song.22000.json','["吉祥亭下萬千枝，看盡將開欲落時。", "却是雙紅有深意，故留春色綴人思。"]'),
('e46741fb-dff7-4def-beb1-51a2ad9a5e12','華嚴院西軒見芍藥兩枝追想吉祥賞花慨然有感寄呈才翁  其二','蔡襄','宋','宋诗','song-poetry','','[]','烘簾微照自生光，吹面輕風與送香。',32,'全唐诗/poet.song.22000.json','["烘簾微照自生光，吹面輕風與送香。", "誰把金刀收絕艷，醉紅深淺上釵梁。"]'),
('dcee24c6-e606-4a54-8e7f-4fa990045aab','華嚴院西軒見芍藥兩枝追想吉祥賞花慨然有感寄呈才翁  其三','蔡襄','宋','宋诗','song-poetry','','[]','的的名花對酒樽，欄邊沈醉月黄昏。',32,'全唐诗/poet.song.22000.json','["的的名花對酒樽，欄邊沈醉月黄昏。", "今朝關外尋蘭若，忽見孤芳欲斷魂。"]'),
('e817cc24-238e-4f88-8b87-3b4ecf52e816','崇德夜泊寄福建提刑章屯田思錢塘春月並遊','蔡襄','宋','宋诗','song-poetry','','[]','夙昔神都別，于今浙水遭。',144,'全唐诗/poet.song.22000.json','["夙昔神都別，于今浙水遭。", "故情彌切到，佳月事追遨。", "太守才賢重，清明土俗豪。", "犀珠來戍削，征鼓去啾嘈。", "湖樹涵天闊，船旗罥日高。", "醉中春渺渺，愁外夕陶陶。", "新曲尋聲倚，名花逐種褒。", "吟亭披越岫，夢枕覺胥濤。", "論議刀矛快，心懷鐵石牢。", "淹留趨海角，分散念霜毛。", "鱸鱠紅隨筯，瀧波淥滿篙。", "試思南北路，燈暗雨蕭騷。"]'),
('6aa2629e-9e5d-48fa-bb19-7900eb25ee31','嘉禾郡偶書','蔡襄','宋','宋诗','song-poetry','','[]','盡道瑶池瓊樹新，仙源尋到不逢人。',32,'全唐诗/poet.song.22000.json','["盡道瑶池瓊樹新，仙源尋到不逢人。", "陳王也作驚鴻賦，未必當時見洛神。"]'),
('b35b8dd1-683b-4a26-9b0b-7004820c66ad','讀宿州天慶觀門扉仙篆有感','蔡襄','宋','宋诗','song-poetry','','[]','玉骨霞衣帝所遊，案前香氣與星浮。',32,'全唐诗/poet.song.22000.json','["玉骨霞衣帝所遊，案前香氣與星浮。", "無端醉語落塵土，一過人間四十秋。"]'),
('47a54df3-ec4e-4823-b71d-a1c0961b3236','送張處士二首  其一','蔡襄','宋','宋诗','song-poetry','','[]','垂垂秋雨沒韉泥，經晝門前無馬嘶。',32,'全唐诗/poet.song.22000.json','["垂垂秋雨沒韉泥，經晝門前無馬嘶。", "乘靜因題送行什，江南歸思已凄迷。"]'),
('89f76fa9-fcc2-4e4b-8077-32240f34cb05','送張處士二首  其二','蔡襄','宋','宋诗','song-poetry','','[]','梁園塵土著人腥，有似淮山照眼明。',32,'全唐诗/poet.song.22000.json','["梁園塵土著人腥，有似淮山照眼明。", "愛君心迹曾無繫，一片孤雲去就輕。"]'),
('820a4ee0-b2dc-4707-af59-50fef2ff7663','溫成皇后挽詞二首  其一','蔡襄','宋','宋诗','song-poetry','','[]','紫極騰軒曜，青春委蕣顔。',48,'全唐诗/poet.song.22000.json','["紫極騰軒曜，青春委蕣顔。", "雲軿何處去，金殿幾時還。", "仗下編簫咽，陵中夜燭閒。", "六宮哀送返，疑是夢魂間。"]'),
('08d2be62-8cc9-4617-932a-3e015ca764f1','溫成皇后挽詞二首  其二','蔡襄','宋','宋诗','song-poetry','','[]','翟綵開新禮，金文易大名。',48,'全唐诗/poet.song.22000.json','["翟綵開新禮，金文易大名。", "真游上仙路，故物感皇情。", "月落辭丹禁，春前引素旌。", "宮闈鳴挽鐸，不是珮環聲。"]'),
('ca548dc7-b68b-4edb-ae18-6122658f2c38','司徒侍中宋宣獻公挽詞五首  其一','蔡襄','宋','宋诗','song-poetry','','[]','重器推隆棟，馳光逐逝川。',48,'全唐诗/poet.song.22000.json','["重器推隆棟，馳光逐逝川。", "人應騎尾宿，歲亦在辰年。", "文思精天下，忠某盡帝前。", "唯無豐室累，清白是家傳。"]'),
('e6355d54-f0f1-40b3-b1d1-bd7894736dcd','司徒侍中宋宣獻公挽詞五首  其二','蔡襄','宋','宋诗','song-poetry','','[]','申命增華衮，遺忠動紫宸。',48,'全唐诗/poet.song.22000.json','["申命增華衮，遺忠動紫宸。", "世風存令子，暮哭有慈親。", "復辟前言在，論兵密疎陳。", "如何年不永，無路問蒼旻。"]'),
('e8f24fab-81bb-43fb-b24e-8d3d2c5bb244','司徒侍中宋宣獻公挽詞五首  其三','蔡襄','宋','宋诗','song-poetry','','[]','懷道初名世，乘時遂致君。',48,'全唐诗/poet.song.22000.json','["懷道初名世，乘時遂致君。", "平分百年算，中據兩台文。", "行翣連寒樹，凝笳上晚雲。", "路人那得識，揮涕指幽墳。"]'),
('009546a1-4bc4-43ec-80fc-d33ef4b86cc7','司徒侍中宋宣獻公挽詞五首  其四','蔡襄','宋','宋诗','song-poetry','','[]','洛宅初開府，非才辱顧隆。',48,'全唐诗/poet.song.22000.json','["洛宅初開府，非才辱顧隆。", "遺思謠俗在，餘論宴堂空。", "已矣蒼生望，嗟乎吾道窮。", "豈惟懷舊德，一慟向春風。"]'),
('5bed077e-1c1a-4699-8b7e-a9527db56791','司徒侍中宋宣獻公挽詞五首  其五','蔡襄','宋','宋诗','song-poetry','','[]','去歲洛城東，公歸秉樞務。',72,'全唐诗/poet.song.22000.json','["去歲洛城東，公歸秉樞務。", "今日國門西，輤車行哭度。", "同此晚春節，依舊西山路。", "千古訣幽明，一年纔旦暮。", "遠恨寄山川，餘哀慘雲霧。", "平昔送公詩，何言歌薤露。"]'),
('f4d1eb76-18ba-4a40-8fb3-8ff29fc0f241','哭賈少卿','蔡襄','宋','宋诗','song-poetry','','[]','畫旟南度謫長沙，粵海新恩路更賒。',64,'全唐诗/poet.song.22000.json','["畫旟南度謫長沙，粵海新恩路更賒。", "子日鵬來知主去，辰年龍會爲賢嗟。", "猶多婚嫁先捐館，無復田園可寄家。", "曾是德公推奬厚，一觴何處酹魂車。"]'),
('8d31ed07-4688-4dcd-95b6-4e3811a0084e','別顔慥下第','蔡襄','宋','宋诗','song-poetry','','[]','四上不登第，漂流二十年。',24,'全唐诗/poet.song.22000.json','["四上不登第，漂流二十年。", "依依去國恨，杯酒春風前。"]'),
('e0f823c6-a140-4d32-a5ab-6ede0cd9f3b7','和杜相公謝寄茶','蔡襄','宋','宋诗','song-poetry','','[]','破春龍焙走新茶，盡是西溪近社芽。',64,'全唐诗/poet.song.22000.json','["破春龍焙走新茶，盡是西溪近社芽。", "纔拆緘封思退傅，爲留甘旨減藏家。", "鮮明香色凝雲液，清徹神情敵露華。", "却笑虛名陸鴻漸，曾無賢相作詩誇。"]'),
('abe9d2a9-2147-4b88-93e2-f53fd844aa49','謝杜相公','蔡襄','宋','宋诗','song-poetry','','[]','謝政閑宮傅，當年老相君。',48,'全唐诗/poet.song.22000.json','["謝政閑宮傅，當年老相君。", "詩情通造化，筆力作風雲。", "是則經綸手，施於淡泊文。", "捧窺心感悸，無路候公門。"]'),
('28e90e92-3b78-4297-b365-982180eff48e','銓舍後軒','蔡襄','宋','宋诗','song-poetry','','[]','秋欄疎索水葒花，坐見花邊日向斜。',32,'全唐诗/poet.song.22000.json','["秋欄疎索水葒花，坐見花邊日向斜。", "莫問幽人超世訣，即心無累是仙家。"]'),
('4f34ee47-b330-4e54-bde6-62f06389d5d1','閣下晝眠','蔡襄','宋','宋诗','song-poetry','','[]','急雨初收宮殿明，紅薇花落暑風清。',32,'全唐诗/poet.song.22000.json','["急雨初收宮殿明，紅薇花落暑風清。", "忽傳午正驚殘夢，寂寂西軒喜鵲聲。"]'),
('187d1b0b-82cf-4d6c-a928-5d59cc66bd42','戲答王仲儀','蔡襄','宋','宋诗','song-poetry','','[]','零落黄花動節辰，送行杯酒感風塵。',32,'全唐诗/poet.song.22000.json','["零落黄花動節辰，送行杯酒感風塵。", "誰知最恨張京兆，畫徧修眉不示人。"]'),
('f96bdcbe-ce8e-458b-a815-708a46df299e','哭石曼卿','蔡襄','宋','宋诗','song-poetry','','[]','仕宦晚益困，忽驚朝露晞。',72,'全唐诗/poet.song.22000.json','["仕宦晚益困，忽驚朝露晞。", "嗟嗟命不偶，事事志多違。", "直節未嘗屈，英魂何所依。", "有材真國器，無悶即天機。", "前日猶言笑，今亡果是非。", "城南春滿路，空見素旌歸。"]'),
('f25329d0-37a0-4659-a905-767ba1cc1a67','銅雀妓','蔡襄','宋','宋诗','song-poetry','','[]','十五燒香繐帳前，幾多幽怨入危絃。',32,'全唐诗/poet.song.22000.json','["十五燒香繐帳前，幾多幽怨入危絃。", "誰知千載臺傾後，何處西陵有墓田。"]'),
('ad4fbaac-86a0-4835-b8de-cc93da85da24','城西射弓挺之以病不至簡示新詩有唯應欠我渭城歌之句謹吟一篇以答佳意','蔡襄','宋','宋诗','song-poetry','','[]','雪後西郊物外清，官閒乘興此閒行。',64,'全唐诗/poet.song.22000.json','["雪後西郊物外清，官閒乘興此閒行。", "出門疎樹無塵色，入內流渠带野聲。", "近臘酒醪香更釅，得風弓箭力還生。", "知君病起心猶壯，獨背船窗唱渭城。"]'),
('21f6f97b-2a85-41fc-9e42-10b0df018f91','汾陽夫人挽詞二首  其一','蔡襄','宋','宋诗','song-poetry','','[]','福偶天家出，賢名戚里推。',48,'全唐诗/poet.song.22000.json','["福偶天家出，賢名戚里推。", "朱顔不待老，萬事却成悲。", "宿露霑新隴，秋風過舊帷。", "誰歌均一德，傳繼召南詩。"]'),
('4b48aad4-2feb-4999-9572-d5e57222bb7b','汾陽夫人挽詞二首  其二','蔡襄','宋','宋诗','song-poetry','','[]','借有百年在，都如一夢迴。',48,'全唐诗/poet.song.22000.json','["借有百年在，都如一夢迴。", "幻生還復滅，仙去不重來。", "樂色閒宵院，衣香祕夜臺。", "行人知令淑，哭送侍兒哀。"]'),
('03720a22-5f73-494c-bd8a-4946840b523d','秦靈園書事  其一','蔡襄','宋','宋诗','song-poetry','','[]','檻外珍叢叨下泉，祥符天子泰靈仙。',32,'全唐诗/poet.song.22000.json','["檻外珍叢叨下泉，祥符天子泰靈仙。", "忽逢野老臨池水，自剪殘花趁歲錢。"]'),
('a8c1e32e-3501-4b63-911b-2b0e8548cfea','秦靈園書事  其二','蔡襄','宋','宋诗','song-poetry','','[]','上元天仗款琳房，靈圃遥傳玉殿香。',32,'全唐诗/poet.song.22000.json','["上元天仗款琳房，靈圃遥傳玉殿香。", "要識年年桃李色，不關春力是恩光。"]'),
('b237d07c-87ed-410c-a927-24750a8555c3','讀太平告身','蔡襄','宋','宋诗','song-poetry','','[]','綾紋金彩射星霞，潤墨新騰玉署麻。',32,'全唐诗/poet.song.22000.json','["綾紋金彩射星霞，潤墨新騰玉署麻。", "不用著心驚寵辱，去來元是坦空華。"]'),
('72e7ee38-a678-4b6e-a51a-c307ef6222c8','因書答河東轉運楊樂道','蔡襄','宋','宋诗','song-poetry','','[]','前歲君提嶺外兵，國門南路送君行。',64,'全唐诗/poet.song.22000.json','["前歲君提嶺外兵，國門南路送君行。", "由來成事多天幸，直向危時見世情。", "勉力朝廷論大計，甘心江海就私榮。", "牢愁應解侵人骨，未老先教白髮生。"]'),
('db65163f-c7d9-49f9-9871-ecae314eba0f','楚州聞晚角有懷','蔡襄','宋','宋诗','song-poetry','','[]','欽天門外警場開，畫角千枝疊鼓催。',32,'全唐诗/poet.song.22000.json','["欽天門外警場開，畫角千枝疊鼓催。", "今日淮邊孤壘畔，晚風時送數聲來。"]'),
('8563fd3e-acff-43dc-b276-5fd78f644fe9','過真慧素上人院見紅薇盛開因思西閣後軒數株遂成短章寄翰林原叔八丈禹 玉閣長兼書真慧壁間以記所遇','蔡襄','宋','宋诗','song-poetry','','[]','八月吳天覺早涼，翠叢初拆碎朱房。',64,'全唐诗/poet.song.22000.json','["八月吳天覺早涼，翠叢初拆碎朱房。", "繁枝欲卧不勝力，落片將飛猶是香。", "西閣二年臨晝夢，金刀一夕掩春芳。", "欄邊想像頻回首，漸覺星垣迥漢傍。"]'),
('f709a9d8-fcb1-4f48-8918-a21ee91787e6','杭州訪吉祥璘上人追感蘇才翁同嘗牡丹','蔡襄','宋','宋诗','song-poetry','','[]','曾乘春飲遶花畦，花底餘香入燕泥。',64,'全唐诗/poet.song.22000.json','["曾乘春飲遶花畦，花底餘香入燕泥。", "剪處佳人傳燭下，歸時明月到雲西。", "重來草樹驚秋色，零落交朋感舊題。", "若使他年逢勝賞，一觴知復共誰携。"]'),
('e81474e4-6924-46df-bd38-a309d28a35a4','寶月法喜堂','蔡襄','宋','宋诗','song-poetry','','[]','少悟浮圖法，因傳法喜名。',48,'全唐诗/poet.song.22000.json','["少悟浮圖法，因傳法喜名。", "於人無厚薄，知己盡豪英。", "藥舍朝爐暖，棋窗夜燭明。", "性懷元自得，未用厭逢迎。"]'),
('6d8769c6-8fd9-41d4-84f0-f5da24e2409e','過泗州嶺','蔡襄','宋','宋诗','song-poetry','','[]','二十五年間，三迴共往還。',48,'全唐诗/poet.song.22000.json','["二十五年間，三迴共往還。", "那知臨白首，相失向青山。", "想像音容在，侵尋鬢髮斑。", "平生多善行，應不下塵寰。"]'),
('3f4604db-4df9-46ea-82e0-a0b95308fbff','丙申元日過浦城西陽嶺','蔡襄','宋','宋诗','song-poetry','','[]','曾侍天王玉几傍，捲簾袍色殿中央。',64,'全唐诗/poet.song.22000.json','["曾侍天王玉几傍，捲簾袍色殿中央。", "重霄未徹宮縣樂，上宰初持萬壽觴。", "曉日半臨幡影轉，春風徧送佩聲長。", "今朝千里穿雲嶺，喜奉親輿返故鄉。"]'),
('98a33163-82ec-48ee-a9dc-2809e0a0ae33','宿漁梁驛','蔡襄','宋','宋诗','song-poetry','','[]','庭樹疎疎河漢低，瓦溝霜白月平西。',32,'全唐诗/poet.song.22000.json','["庭樹疎疎河漢低，瓦溝霜白月平西。", "寒鴉不奈單棲若，落泊驚飛到曉啼。"]'),
('b8768a80-b210-432c-b4b2-451f055fa9c5','過南劍州芋陽舖見桃花','蔡襄','宋','宋诗','song-poetry','','[]','七年相別復相逢，牆外千枝依舊紅。',32,'全唐诗/poet.song.22000.json','["七年相別復相逢，牆外千枝依舊紅。", "只有蒼顔日憔悴，奈緣多感泣春風。"]'),
('c87e2e7a-f86e-4283-9781-48626a13bf15','見勻親抄書泣悼卷末','蔡襄','宋','宋诗','song-poetry','','[]','得汝抄書心自喜，古來清白紹家難。',32,'全唐诗/poet.song.22000.json','["得汝抄書心自喜，古來清白紹家難。", "誰知向老秋燈下，一見親蹤不忍看。"]'),
('242130f7-9846-43bd-b21f-d766870f0094','寓居興化轉運廨舍','蔡襄','宋','宋诗','song-poetry','','[]','病惱連春夏，居閒意味長。',48,'全唐诗/poet.song.22000.json','["病惱連春夏，居閒意味長。", "海風生永晝，山雨送微涼。", "書帙梅蒸潤，衣巾荔實香。", "塵緣消遣盡，物我兩相忘。"]'),
('6955ec8d-5c03-4813-a622-ebe329446f26','丙申五月遊興化西門上溪','蔡襄','宋','宋诗','song-poetry','','[]','尋溪因過上溪遊，雨後溪渾水亂流。',64,'全唐诗/poet.song.22000.json','["尋溪因過上溪遊，雨後溪渾水亂流。", "因傍堤松却飛蓋，爲聞山鳥輟鳴騶。", "平田䆉䅉青雲合，滿谷芭蕉碧玉抽。", "開濟無功須早去，故時瓜隴有通侯。"]'),
('ccb5e899-32fa-4237-989d-efb2c3c6f066','謝宋評事','蔡襄','宋','宋诗','song-poetry','','[]','齋館從容接燕申，每臨佳樹走觥巡。',64,'全唐诗/poet.song.22000.json','["齋館從容接燕申，每臨佳樹走觥巡。", "兵鋒却後知神物，年壽高來况主人。", "並賞昔聞思故友，分甘今喜奉慈親。", "豈唯持祝公難老，兼欲靈株比大椿。"]'),
('5128b072-a9fd-491e-9c87-f6236cda51b5','謝阮評事','蔡襄','宋','宋诗','song-poetry','','[]','手授新書荷至情，何時仙訣得真精。',64,'全唐诗/poet.song.22000.json','["手授新書荷至情，何時仙訣得真精。", "高年轉覺面顔少，細字全由眼力明。", "藥籙謾勞分上下，丹爐終費侯虧盈。", "爭如一語醒然悟，獨葆天光不外營。"]'),
('2981534c-573b-48b3-a5c9-fc6c72ce50bc','和詩送茶寄孫之翰','蔡襄','宋','宋诗','song-poetry','','[]','北苑靈芽天下精，要須寒過入春生。',64,'全唐诗/poet.song.22000.json','["北苑靈芽天下精，要須寒過入春生。", "故人偏愛雲腴白，佳句遥傳玉律清。", "衰病萬緣皆絕慮，甘香一味未忘情。", "封題原是山家寶，盡日虛堂試品程。"]'),
('04abcd53-72f0-407d-abef-84b30ebcb2a6','泉州安靜堂','蔡襄','宋','宋诗','song-poetry','','[]','庭松永晝轉春禽，天氣初晴又半陰。',32,'全唐诗/poet.song.22000.json','["庭松永晝轉春禽，天氣初晴又半陰。", "惆悵此生多病惱，正看行樂獨傷心。"]'),
('eaa8cb24-6de2-4d45-a0ee-c1171db6a7e6','泉州北藏院見初荷華','蔡襄','宋','宋诗','song-poetry','','[]','初華纔過小荷身，曉露霑紅點點勻。',32,'全唐诗/poet.song.22000.json','["初華纔過小荷身，曉露霑紅點點勻。", "莫爲愁心偏倚望，清江元有未歸人。"]'),
('1f8f4403-3561-4f7e-a60f-df26f2dd70cb','詔貢士','蔡襄','宋','宋诗','song-poetry','','[]','星騎翩翩鶴詔來，旋聞歡語沸春雷。',64,'全唐诗/poet.song.22000.json','["星騎翩翩鶴詔來，旋聞歡語沸春雷。", "天閑未減真龍種，滄海還空老蚌胎。", "拂紙半毫含意勁，摩雲雙翅待風開。", "寄言商潁辟榮客，好致吾君放首迴。"]'),
('e78ff95f-4595-41bc-969e-3113432da24a','福州堂下小欄花卉多是手栽今已繁盛因賞花有所感悼','蔡襄','宋','宋诗','song-poetry','','[]','愛花盡日傍花臺，點檢當年手自栽。',64,'全唐诗/poet.song.22000.json','["愛花盡日傍花臺，點檢當年手自栽。", "前事已隨朝暮變，舊華空見淺深開。", "山禽忽下還飛去，溪雨纔收又復來。", "只有春醪能遣恨，無人欄畔共持杯。"]'),
('94dfc77e-068e-41bf-97e3-24bd76df019e','登四徹亭','蔡襄','宋','宋诗','song-poetry','','[]','偶爾尋幽上翠微，遊人啼鳥似前期。',64,'全唐诗/poet.song.22000.json','["偶爾尋幽上翠微，遊人啼鳥似前期。", "花間行印露霑紙，山下放衙雲滿旗。", "艷艷舞衣朝日處，飄飄商櫓落潮時。", "傳杯且與乘春醉，身世悠然兩自遺。"]'),
('4229557b-e6c1-4022-888b-01c4f9f3e735','登清風樓','蔡襄','宋','宋诗','song-poetry','','[]','郭外清溪溪外山，溪雲飛上破山顔。',32,'全唐诗/poet.song.22000.json','["郭外清溪溪外山，溪雲飛上破山顔。", "晴明天氣琉璃色，何處峰頭带雨還。"]'),
('77debb91-45b0-4b7f-a07a-31c4ba41c691','榴花洞','蔡襄','宋','宋诗','song-poetry','','[]','洞裏花開無定期，落紅曾見逐泉飛。',32,'全唐诗/poet.song.22000.json','["洞裏花開無定期，落紅曾見逐泉飛。", "仙人應向青山口，管却春花不與歸。"]'),
('adc69a56-b71d-4fd9-a16f-10ef023e27c7','寄南海李龍圖求素馨含笑花','蔡襄','宋','宋诗','song-poetry','','[]','二草曾觀嶺外圖，開時嘗與暑風俱。',32,'全唐诗/poet.song.22000.json','["二草曾觀嶺外圖，開時嘗與暑風俱。", "使君已自憐清分，分得新條過海無。"]'),
('3a9a687e-b950-4b4c-9722-affb0eccaba1','寄題張景山大卿園池','蔡襄','宋','宋诗','song-poetry','','[]','人仰公才世吏師，更甘歸老舊林池。',64,'全唐诗/poet.song.22000.json','["人仰公才世吏師，更甘歸老舊林池。", "門闌清似當官處，心力强於少壯時。", "物理自冥非寄酒，兵謀猶在却因棋。", "濠邊風月如招隠，願拂塵裾從所之。"]'),
('a26fa0cd-934a-451e-a54d-22044adee29a','仁宗皇帝挽詞七首  其一','蔡襄','宋','宋诗','song-poetry','','[]','道德由來太古同，生靈休養至仁中。',64,'全唐诗/poet.song.22000.json','["道德由來太古同，生靈休養至仁中。", "五兵不試歸神武，萬物無私是化工。", "玉座忽逢春月盡，金旌遥指洛川窮。", "年年翠輦長陪扈，那向西城別梓宮。"]'),
('a50aeddf-d006-4f55-83c8-88ea32d7a84d','仁宗皇帝挽詞七首  其二','蔡襄','宋','宋诗','song-poetry','','[]','向近千秋節，何言七月期。',48,'全唐诗/poet.song.22000.json','["向近千秋節，何言七月期。", "遺恩羣玉宴，往事荷宮祠。", "仙路雲龍會，秋風鼓角悲。", "萬人瞻彩仗，猶認吉行時。"]'),
('3975c6be-7e96-4b8f-8f66-f28dd65aedc3','仁宗皇帝挽詞七首  其三','蔡襄','宋','宋诗','song-poetry','','[]','聲教中原泰，恩仁萬國臨。',48,'全唐诗/poet.song.22000.json','["聲教中原泰，恩仁萬國臨。", "憂勤符帝夢，付與得天心。", "簫吹凝寒氣，雲山斂夕陰。", "還期千載後，歌頌莫知深。"]'),
('6e7c953b-e53f-47b1-ab4d-69ea4d749ed8','仁宗皇帝挽詞七首  其四','蔡襄','宋','宋诗','song-poetry','','[]','儉薄留遺詔，遵行在繼承。',48,'全唐诗/poet.song.22000.json','["儉薄留遺詔，遵行在繼承。", "桐棺會稽冢，瓦器孝文陵。", "闕外秋螢度，林端曉月澄。", "須知無可欲，終古不騫崩。"]'),
('57402b0e-9c74-421d-8473-4517bacc11e0','仁宗皇帝挽詞七首  其五','蔡襄','宋','宋诗','song-poetry','','[]','萬世威神在，多方惠澤隆。',48,'全唐诗/poet.song.22000.json','["萬世威神在，多方惠澤隆。", "密音通虜壤，行哭亦兒童。", "畫翣離丹闕，幽堂對紫嵩。", "孤城空雨泣，白首抱遺弓。"]'),
('f9c3e18b-e6e0-474a-985c-a184add1a906','仁宗皇帝挽詞七首  其六','蔡襄','宋','宋诗','song-poetry','','[]','儉勤追禹績，恭讓體堯仁。',48,'全唐诗/poet.song.22000.json','["儉勤追禹績，恭讓體堯仁。", "措枉朝多直，除苛吏盡循。", "遵儒恩禮異，左戚賞刑均。", "立子知天意，超然即上賓。"]'),
('422af4ba-5e7b-464c-8ef7-7cc1dc4e4cb2','仁宗皇帝挽詞七首  其七','蔡襄','宋','宋诗','song-poetry','','[]','攢宮開七月，隧路閉千秋。',48,'全唐诗/poet.song.22000.json','["攢宮開七月，隧路閉千秋。", "地带三川拆，天含萬國愁。", "鳥雲知聖沒，龍駕想神遊。", "厚祿將無報，慙恩更白頭。"]'),
('57659847-0eb2-4405-bbe4-c6079caaaa4b','昭陵行','蔡襄','宋','宋诗','song-poetry','','[]','宮人上臨候昏鐘，簾外香煙燭影紅。',32,'全唐诗/poet.song.22000.json','["宮人上臨候昏鐘，簾外香煙燭影紅。", "庭柏飛霜陵漏永，可憐今夜月明中。"]'),
('67f0a8f3-a683-4e22-8e32-53c94a08a471','和子發','蔡襄','宋','宋诗','song-poetry','','[]','空梁詩板歲年多，唯有秋蟲占作窠。',32,'全唐诗/poet.song.22000.json','["空梁詩板歲年多，唯有秋蟲占作窠。", "聞道故人時拂拭，此生無奈舊情何。"]'),
('b46c8bc9-2fbf-4def-b6a8-cbe0f55e649b','有遺梅花枕前者因成','蔡襄','宋','宋诗','song-poetry','','[]','誰寄梅花置枕傍，前時復得枕清香。',32,'全唐诗/poet.song.22000.json','["誰寄梅花置枕傍，前時復得枕清香。", "因香夢徹江南路，江水浮天月似霜。"]'),
('6fa536bb-1243-43ad-ad41-e8e45d5316fa','甲辰寒日遊公謹園池','蔡襄','宋','宋诗','song-poetry','','[]','二月名園蓊鬰青，爲憐佳節此閒行。',64,'全唐诗/poet.song.22000.json','["二月名園蓊鬰青，爲憐佳節此閒行。", "偶因觴詠心還適，蹔離塵埃眼倍明。", "風靜落花深一寸，日遲啼鳥度千聲。", "主公高意何須道，芳物於人自有情。"]'),
('a69d4725-2574-4f48-b7b2-859397adf355','四月十七日奉安仁宗皇帝御容於景靈孝嚴殿是日舟次陳留感懷述事十六韻','蔡襄','宋','宋诗','song-poetry','','[]','先帝傳基固，真人嗣統平。',192,'全唐诗/poet.song.22000.json','["先帝傳基固，真人嗣統平。", "餘恩華夏在，高誼古今傾。", "漢法原爲廟，仙居別有京。", "海中金闕見，天上玉樓成。", "睿意懷丕烈，宸豪薦大名。", "薦唯將舜擬，嚴亦與周并。", "龍向朝雲起，奎和晝日呈。", "流光俄洊歲，發號慶重明。", "令節千秋過，端儀萬衆迎。", "讙呼山嶽動，驅拂鬼神驚。", "縹緲來佳氣，雍容下太清。", "旛旌多異制，歌吹自新聲。", "琳館初停御，鑾輿始此行。", "盥孚通至感，福澤被羣生。", "往事時兼遠，孤臣淚獨橫。", "晨興西響久，悽斷老年情。"]'),
('efb1f972-3e64-46c0-9efd-59cc7929e5c3','至鎖外','蔡襄','宋','宋诗','song-poetry','','[]','旗聲不斷鼓聲催，堤柳陰濃野色開。',32,'全唐诗/poet.song.22000.json','["旗聲不斷鼓聲催，堤柳陰濃野色開。", "今日客衣何事凈，京塵不肯出城來。"]'),
('f3f8ffce-c60d-48ad-82cb-478b0e87f3a1','洪澤阻風','蔡襄','宋','宋诗','song-poetry','','[]','今日風期惡，遲迴一水濱。',48,'全唐诗/poet.song.22000.json','["今日風期惡，遲迴一水濱。", "村旗呈酒聖，廟鼓賽河神。", "躍鯉曾驚網，饑烏不避人。", "商工時借問，何處即通津。"]'),
('d307ba08-ee7a-48ca-bbe2-5ed5b521e705','遊金山寺','蔡襄','宋','宋诗','song-poetry','','[]','平日壓塵土，今遊興味長。',48,'全唐诗/poet.song.22000.json','["平日壓塵土，今遊興味長。", "波濤圍四際，臺殿起中央。", "魚聽晨餐鼓，雪和夕炷香。", "薰風休遞吹，襟袂不勝涼。"]'),
('152a115a-da7d-4100-9abc-d02d16eb61a6','五月宿江陰軍葛公綽草堂','蔡襄','宋','宋诗','song-poetry','','[]','曾解征衣寄草堂，枕邊泉石自生涼。',32,'全唐诗/poet.song.22000.json','["曾解征衣寄草堂，枕邊泉石自生涼。", "休論仙訣能延壽，蹔得身閒夢亦長。"]'),
('1e46d357-14b0-4544-8ac4-79a247bec8c4','七月過孤山勤上人院','蔡襄','宋','宋诗','song-poetry','','[]','青林藹藹日暉暉，薄晚涼生暑氣微。',32,'全唐诗/poet.song.22000.json','["青林藹藹日暉暉，薄晚涼生暑氣微。", "湖上清風如可載，畫船十隻不空歸。"]'),
('06c6e981-3018-463d-a9aa-655814c9ef79','重陽日有美堂南望','蔡襄','宋','宋诗','song-poetry','','[]','越邑吳封繡錯分，華堂繁吹半空聞。',64,'全唐诗/poet.song.22000.json','["越邑吳封繡錯分，華堂繁吹半空聞。", "山峯高下抽青笋，江水東西卧白雲。", "菊蕊芬芳初應節，松林照耀欲迎曛。", "州人不見歸時醉，未擬風流待使君。"]'),
('b688063e-336f-42a5-b6f7-66da0b735ec8','韓玉汝山堂會別梅花已盛至蘇州示諭水鄉天寒未開','蔡襄','宋','宋诗','song-poetry','','[]','遥知畫舫艤江隈，寒勒梅花未得開。',32,'全唐诗/poet.song.22000.json','["遥知畫舫艤江隈，寒勒梅花未得開。", "唯有山堂紅燭下，至今繁艷傍尊罍。"]'),
('d614b856-2fa8-47bf-9c86-dfe11a7edec2','梨園小部','蔡襄','宋','宋诗','song-poetry','','[]','傾宮晨起傳輕粧，山殿生風夏日長。',32,'全唐诗/poet.song.22000.json','["傾宮晨起傳輕粧，山殿生風夏日長。", "小部新聲落天上，無人知是荔枝香。"]'),
('0c7c19a3-f3ea-4d35-a6cc-420223b200f5','答葛公綽','蔡襄','宋','宋诗','song-poetry','','[]','山堂爭似草堂清，俗事隨人百種名。',32,'全唐诗/poet.song.22000.json','["山堂爭似草堂清，俗事隨人百種名。", "頼有四窗春茗在，甌中時看白雲生。"]'),
('c303e518-21ea-42f7-adbd-fe000d96b7b4','公綽示及生日以九龍泉爲壽依韻奉答','蔡襄','宋','宋诗','song-poetry','','[]','多謝山人遠祝延，壽杯仍是九龍泉。',32,'全唐诗/poet.song.22000.json','["多謝山人遠祝延，壽杯仍是九龍泉。", "餘生事事無心緒，直向清涼度歲年。"]'),
('e7c68b97-dcfa-4136-aafe-6f609f5ef72c','和答孫推官久病新起見過錢塘之什二首  其一','蔡襄','宋','宋诗','song-poetry','','[]','於世無機是海翁，客情醒醉任鄰鍾。',64,'全唐诗/poet.song.22000.json','["於世無機是海翁，客情醒醉任鄰鍾。", "廉纖雨意還侵夜，料峭春期未減冬。", "寶氣上浮難掩玉，歲寒中立不凋松。", "君王自結英雄網，千載風雲定有從。"]'),
('17fe8674-14c2-46b0-9a21-38d23b8aac80','和答孫推官久病新起見過錢塘之什二首  其二','蔡襄','宋','宋诗','song-poetry','','[]','病來安健賦詩誇，甲子新移一歲加。',64,'全唐诗/poet.song.22000.json','["病來安健賦詩誇，甲子新移一歲加。", "吾道所存唯浩氣，世緣何著但空花。", "煙雲已過同歸鴈，楊柳初藏並宿鴉。", "便擬尋山逐幽趣，春泥隨馬上須遮。"]'),
('b2dfb5aa-ef0a-442d-af61-0a238c9d771e','和夜登有美堂','蔡襄','宋','宋诗','song-poetry','','[]','忽聞乘月上層臺，正值江湖夜色開。',64,'全唐诗/poet.song.22000.json','["忽聞乘月上層臺，正值江湖夜色開。", "雲屋萬重燈火合，雪山千仞海潮來。", "靜遊雖有詩情得，獨笑應無俗語陪。", "縱使羈懷多感慨，若逢清致少徘徊。"]'),
('7a5c3c0f-8eb4-491f-b8f0-c56cf5dc060d','和偶登安濟亭','蔡襄','宋','宋诗','song-poetry','','[]','津亭遥望草萋萋，空曠清懷與物齊。',64,'全唐诗/poet.song.22000.json','["津亭遥望草萋萋，空曠清懷與物齊。", "春水倒行潮欲上，晚雲平壓日先低。", "高城覽古人何在，遠渡傷離客自迷。", "好共山翁同出處，不隨朝騎五門西。"]'),
('056ef0a4-a5ab-4c2d-9a27-3a35e005c2ec','和江上觀潮','蔡襄','宋','宋诗','song-poetry','','["\u94b1\u5858\u6c5f"]','地卷天回出海東，人間何事可爭雄。',64,'全唐诗/poet.song.22000.json','["地卷天回出海東，人間何事可爭雄。", "千年浪說鴟夷怒，一信全疑渤澥空。", "寂靜最宜聞夜枕，崢嶸須待駕秋風。", "尋思物理真難測，隨月虧圓亦未通。"]'),
('4bfe74b1-4685-46e2-8fcc-99df08f227bb','和答孫推官','蔡襄','宋','宋诗','song-poetry','','[]','擬將身計入扁舟，縱得三公不黑頭。',64,'全唐诗/poet.song.22000.json','["擬將身計入扁舟，縱得三公不黑頭。", "病體已輕休賦鵩，機心如動輒驚鷗。", "强看吳野江山醉，肯爲春風花草愁。", "所向乾坤皆客寓，可能與我更遲留。"]'),
('a479195d-0872-4c4b-bbbf-44589c426463','和古寺偃松','蔡襄','宋','宋诗','song-poetry','','[]','古寺無人野蘚滋，空庭永日雪風吹。',64,'全唐诗/poet.song.22000.json','["古寺無人野蘚滋，空庭永日雪風吹。", "橫柯圓若張青蓋，老幹孤如植紫芝。", "萬乘未輕蟠木器，千年終與大椿期。", "須知才短爲天幸，江上婆娑得所宜。"]'),
('90f0f6ee-2d97-48c8-88e6-a79da99f9c80','和新燕','蔡襄','宋','宋诗','song-poetry','','[]','燕燕何來處處喧，新從海上振輕翰。',64,'全唐诗/poet.song.22000.json','["燕燕何來處處喧，新從海上振輕翰。", "卑飛不避春泥重，竝語應愁夜雨寒。", "客舍暗窺吟筆健，宴堂時見酒盃乾。", "雕梁信美多移主，願爾將雛擇便安。"]'),
('bc9d83c0-3135-4245-b014-9ec12d1e86fd','開州園縱民游樂二首  其一','蔡襄','宋','宋诗','song-poetry','','[]','風日朝來好，園林雨後清。',48,'全唐诗/poet.song.22000.json','["風日朝來好，園林雨後清。", "遊鱼知水樂，戲蝶見春晴。", "草軟迷行迹，花深隠笑聲。", "觀民聊自適，不用管絃迎。"]'),
('a0068ce2-14e0-4dac-9198-912e7a669bb6','開州園縱民游樂二首  其二','蔡襄','宋','宋诗','song-poetry','','[]','節候近清明，遊人已踏青。',48,'全唐诗/poet.song.22000.json','["節候近清明，遊人已踏青。", "插花穿戟戶，酤酒向旗亭。", "日迥林光潤，風迴海氣腥。", "未知何處樂，歸路已嚴扃。"]'),
('b1a8cb24-ad02-4102-a860-dbe9a7540807','遣興','蔡襄','宋','宋诗','song-poetry','','[]','苦竹生笋四五寸，櫻桃開花千萬枝。',64,'全唐诗/poet.song.22000.json','["苦竹生笋四五寸，櫻桃開花千萬枝。", "空濛野色當樓處，寂寞春寒带雨時。", "已放清歌逐瑶管，旋篘新釀行金巵。", "衰翁酩酊自爲樂，舉鞭不問并州兒。"]'),
('7ad3d4fe-f11f-4274-96e2-8b09b40f64f5','夜雨病中','蔡襄','宋','宋诗','song-poetry','','[]','久雨曾無度，陽和漸向闌。',48,'全唐诗/poet.song.22000.json','["久雨曾無度，陽和漸向闌。", "雜香生衆木，濃翠入孤巒。", "漏緩宵仍靜，燈微曉更寒。", "芳時猶卧病，何日出城看。"]'),
('46e586e0-3b7f-4645-9eea-0dbe8b43f03f','寒食西湖','蔡襄','宋','宋诗','song-poetry','','["\u897f\u6e56"]','山前雨氣曉纔收，水際風光翠欲流。',64,'全唐诗/poet.song.22000.json','["山前雨氣曉纔收，水際風光翠欲流。", "盡日旌旗停曲岸，滿潭鉦鼓競飛舟。", "浮來煙島疑相就，引去山禽好自由。", "歸騎不令歌吹歇，萬枝燈燭度花樓。"]'),
('87ef1e8d-8fe2-4f63-88ba-5257ff8c9f44','上巳日州園東樓','蔡襄','宋','宋诗','song-poetry','','[]','地上多於枝上花，東樓凝望惜年華。',64,'全唐诗/poet.song.22000.json','["地上多於枝上花，東樓凝望惜年華。", "潮頭正對伍員廟，燕子爭歸百姓家。", "粉籜漸高山徑笋，綠旗初展石岩茶。", "流芳自與人兼老，樽酒相逢莫重嗟。"]'),
('e594f2f0-108c-45d7-8b70-8b0d7250eb29','四月清明西湖','蔡襄','宋','宋诗','song-poetry','','["\u897f\u6e56"]','千頃平湖綠一遭，空城遊樂自奢豪。',64,'全唐诗/poet.song.22000.json','["千頃平湖綠一遭，空城遊樂自奢豪。", "畫船爭勝飛江鶻，翠讞都浮載海鼇。", "芳草堤邊裙带短，柔桑陌上髻鬟高。", "樓前盡日聞歌笑，不啻秋風卷怒濤。"]'),
('5c89d869-7c0c-4df5-bbba-9d28f6833a7d','效陶秋巖韻','釋文珦','宋','宋诗','song-poetry','','[]','眼前幾富貴，變滅同浮煙。',48,'全唐诗/poet.song.220000.json','["眼前幾富貴，變滅同浮煙。", "舉非吾所欽，眷然思古先。", "窮達無二道，彭殤可齊年。", "中心既昭徹，萬象皆澄鮮。"]'),
('e4fba432-5b7f-42a6-993e-12463431edf8','擬古  其一','釋文珦','宋','宋诗','song-poetry','','[]','容易三年別，纏綿萬里情。',24,'全唐诗/poet.song.220000.json','["容易三年別，纏綿萬里情。", "夢中頻見面，終是不分明。"]'),
('56231d25-4d5e-4786-8228-ba2610bce9f9','擬古  其二','釋文珦','宋','宋诗','song-poetry','','[]','事往不可追，愁來不可掃。',96,'全唐诗/poet.song.220000.json','["事往不可追，愁來不可掃。", "悠悠百年間，一身孰能保。", "昔爲席上珍，今作路傍草。", "倚伏理則然，寧復有當道。", "古者賢聖人，身否亦枯槁。", "嘉名如日月，萬世猶杲杲。", "浮雲非我心，歸根以爲寶。", "茫昧曷能明，吾將問蒼昊。"]'),
('7969bb8a-230a-4fa2-af89-f91efdd5c197','偶成','釋文珦','宋','宋诗','song-poetry','','[]','名利雙蝸角，堪輿一旅亭。',48,'全唐诗/poet.song.220000.json','["名利雙蝸角，堪輿一旅亭。", "生平嫌著物，老去更忘形。", "慢火煎茶熟，寒燈照夢醒。", "室空無道伴，自展八還經。"]'),
('a3ca2b72-2498-405c-832b-ff7c40c075a2','偶作  其一','釋文珦','宋','宋诗','song-poetry','','[]','風露洗空寒，秋清四體安。',48,'全唐诗/poet.song.220000.json','["風露洗空寒，秋清四體安。", "偶扶筇杖出，因采菊花餐。", "老覺心情嬾，閒知世界寬。", "寒山詩一卷，隨意作經看。"]'),
('92beb791-bebb-4432-ba75-b3e3de9d6cee','偶作  其二','釋文珦','宋','宋诗','song-poetry','','[]','陵谷今遷變，衣冠半不存。',24,'全唐诗/poet.song.220000.json','["陵谷今遷變，衣冠半不存。", "閭閻小兒女，盡解北人言。"]'),
('e5adab3d-bfe0-4966-bc31-bbbecc6fb3eb','驂服騰飛行','釋文珦','宋','宋诗','song-poetry','','[]','有客乘車建其，四牡驂服騰飛。',140,'全唐诗/poet.song.220000.json','["有客乘車建其，四牡驂服騰飛。", "華綬雜佩陸離，指顧綽有餘輝。", "賁然到我柴扉，我生靡識輕肥。", "旋穿敝屣粗衣，延之欲語襟期。", "客言子其病而，胡不與世推移。", "余曰子言誠非，窮達有命有時。", "與其如脂如韋，孰若飯糗羹藜。", "顔子陋巷寒饑，尼父嘗稱庶幾。", "恬淡道德之基，不義富貴奚爲。", "將子勿復致辭，吾志非君所知。"]'),
('e78c065c-1b34-4e17-a877-6bebfee6a7f5','運有榮枯行','釋文珦','宋','宋诗','song-poetry','','[]','運有榮枯，道有隆汙。',190,'全唐诗/poet.song.220000.json','["運有榮枯，道有隆汙。", "吉凶福禍，相爲乘除。", "歷覽舊載，變滅紛如。", "或以貪殘，或以逼誅。", "莫知其端，爲之長吁。", "予少愚蠢，不能奔趨。", "翛然物表，與古爲徒。", "彼是兩忘，乃道之樞。", "庶幾中庸，匪疾匪徐。", "不事王侯，不遊國都。", "高尚其事，猗那其居。", "煙霞沖澹，松竹扶疎。", "來往忘機，山澤之癯。", "荷裳芰製，可曳可婁。", "竺墳魯誥，可卷可舒。", "逍遥林壑，寧畏簡書。", "臨清坐茂，洽比禽魚。", "自守玄默，死生弗渝。", "安時處順，其樂只且。"]'),
('ea2564b2-0c1a-418e-ba55-f17fdb2c6fb7','青陽代謝行','釋文珦','宋','宋诗','song-poetry','','[]','青陽已代謝，赤帝方司衡。',120,'全唐诗/poet.song.220000.json','["青陽已代謝，赤帝方司衡。", "草木日繁廡，黄鳥鳴嚶嚶。", "維彼造化者，密運何神靈。", "不知爲所遷，但見白髮生。", "囿身天地間，所衛唯生經。", "宜令心氣平，毋使疾癘嬰。", "順此陰陽序，四體當安寧。", "凱風吹棘薪，夭夭長枝莖。", "懷念父母恩，有淚如雨傾。", "仰觀仍俯察，因之捈中情。"]'),
('edee36f5-6faf-4c01-9878-249ea536b73d','閒中吟','釋文珦','宋','宋诗','song-poetry','','[]','雲山青青，風泉泠泠。',100,'全唐诗/poet.song.220000.json','["雲山青青，風泉泠泠。", "山色可愛，泉聲可聽。", "乃賦歸來，盟諸山靈。", "身去世遠，心與真冥。", "蔬食果腹，麻衣蔽形。", "塵車絕跡，蓬戶常扃。", "不行他緣，唯誦自經。", "眇觀人世，滄波一萍。", "朽鈍寂漠，待終餘齡。", "喚主人公，教常惺惺。"]'),
('f4f64e3e-5eec-4261-85c1-55adce2f27b1','送人之蜀','釋文珦','宋','宋诗','song-poetry','','[]','佳友相辭去，西遊卒未還。',48,'全唐诗/poet.song.220000.json','["佳友相辭去，西遊卒未還。", "單車行數月，萬水與千山。", "雨雪年華晚，煙塵道路艱。", "莫教音信絕，添我鬢毛斑。"]'),
('147a6434-f99d-4d54-8952-7a6b0bafc6d3','送人歸金華','釋文珦','宋','宋诗','song-poetry','','[]','此去金華水作程，扁舟定是過嚴陵。',64,'全唐诗/poet.song.220000.json','["此去金華水作程，扁舟定是過嚴陵。", "高山蔽日寒多霧，淺瀨通潮夜不冰。", "漢代絲風應自詠，故鄉三洞與誰登。", "擬從別後題書寄，又怕征鴻未可馮。"]'),
('973fd7c8-372b-4b58-b631-51df26bf61c7','送人歸山','釋文珦','宋','宋诗','song-poetry','','[]','君歸西山去，爲愛山中雲。',48,'全唐诗/poet.song.220000.json','["君歸西山去，爲愛山中雲。", "雲亦喜君歸，日夕常氤氳。", "雲蹤渺難期，別恨徒殷勤。", "他時望山色，眼中如見君。"]'),
('7153b74d-6754-424c-ac94-440f8a890461','送鄉友歸','釋文珦','宋','宋诗','song-poetry','','[]','青春欲盡時，鳥啼花亂飛。',36,'全唐诗/poet.song.220000.json','["青春欲盡時，鳥啼花亂飛。", "共起思鄉恨，君歸吾未歸。", "臨分重執手，老淚溼荷衣。"]'),
('02dbc4b8-72e9-40cf-822c-7d5cdc6e0a4a','句','李應春','宋','宋诗','song-poetry','','[]','象繪耆英希五老，鶴歸華表認千年。',16,'全唐诗/poet.song.220000.json','["象繪耆英希五老，鶴歸華表認千年。"]');
